{
  "name": "Snap2Sheet - Image to Excel Converter",
  "description": "A professional tool to convert printed or digital tables from images into interactive Excel worksheets using AI-powered OCR and data structuring.",
  "requestFramePermissions": [
    "camera"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type TableData = string[][];

export interface ConversionState {
  isProcessing: boolean;
  error: string | null;
  data: TableData | null;
  fileName: string | null;
}

import { GoogleGenAI, Type } from "@google/genai";
import { TableData } from "../types";

export const convertImageToData = async (base64Image: string): Promise<TableData> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `
    Extract all tabular data from this image. 
    Look for tables, grids, or structured lists.
    Format the output as a 2D array (array of arrays), where each inner array represents a row of data.
    Clean up any OCR errors and ensure numbers and headers are accurately represented.
    If multiple tables exist, combine them into one structured grid if they share context, otherwise focus on the primary table.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: {
        parts: [
          { inlineData: { data: base64Image, mimeType: "image/png" } },
          { text: prompt }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            rows: {
              type: Type.ARRAY,
              items: {
                type: Type.ARRAY,
                items: { type: Type.STRING }
              }
            }
          },
          required: ["rows"]
        }
      }
    });

    const result = JSON.parse(response.text || "{}");
    if (!result.rows || !Array.isArray(result.rows)) {
      throw new Error("Failed to extract structured data from the image.");
    }
    return result.rows;
  } catch (error) {
    console.error("Gemini Conversion Error:", error);
    throw new Error("The AI was unable to process this image. Please ensure the table is clear and well-lit.");
  }
};

import * as XLSX from 'xlsx';
import { TableData } from '../types';

export const downloadAsExcel = (data: TableData, fileName: string = 'Snap2Sheet_Export') => {
  const ws = XLSX.utils.aoa_to_sheet(data);
  const wb = XLSX.utils.book_new();
  XLSX.utils.book_append_sheet(wb, ws, "Sheet1");
  XLSX.writeFile(wb, `${fileName}.xlsx`);
};

export const copyToClipboard = async (data: TableData) => {
  const csvContent = data.map(row => row.join('\t')).join('\n');
  try {
    await navigator.clipboard.writeText(csvContent);
    return true;
  } catch (err) {
    console.error('Failed to copy: ', err);
    return false;
  }
};

export const shareData = async (data: TableData) => {
  const csvContent = data.map(row => row.join(',')).join('\n');
  const blob = new Blob([csvContent], { type: 'text/csv' });
  const file = new File([blob], 'Snap2Sheet_Export.csv', { type: 'text/csv' });

  if (navigator.canShare && navigator.canShare({ files: [file] })) {
    try {
      await navigator.share({
        files: [file],
        title: 'Snap2Sheet Data Export',
        text: 'Here is the data converted from my image.',
      });
    } catch (err) {
      console.error('Share failed', err);
    }
  } else {
    alert('Sharing not supported on this browser.');
  }
};

import React, { useRef, useState } from 'react';

interface UploaderProps {
  onImageSelected: (base64: string, fileName: string) => void;
  disabled?: boolean;
}

export const Uploader: React.FC<UploaderProps> = ({ onImageSelected, disabled }) => {
  const [isDragging, setIsDragging] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFile = (file: File) => {
    if (!file.type.startsWith('image/')) {
      alert('Please upload an image file (PNG, JPG, etc.)');
      return;
    }

    const reader = new FileReader();
    reader.onload = (e) => {
      const result = e.target?.result as string;
      const base64 = result.split(',')[1];
      onImageSelected(base64, file.name);
    };
    reader.readAsDataURL(file);
  };

  const onDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
    if (disabled) return;
    const file = e.dataTransfer.files?.[0];
    if (file) handleFile(file);
  };

  return (
    <div 
      className={`relative group max-w-2xl mx-auto p-12 border-2 border-dashed rounded-2xl transition-all duration-300 ${
        isDragging ? 'border-green-500 bg-green-50' : 'border-gray-300 bg-white hover:border-green-400'
      } ${disabled ? 'opacity-50 cursor-not-allowed' : 'cursor-pointer'}`}
      onDragOver={(e) => { e.preventDefault(); setIsDragging(true); }}
      onDragLeave={() => setIsDragging(false)}
      onDrop={onDrop}
      onClick={() => !disabled && fileInputRef.current?.click()}
    >
      <input 
        type="file" 
        className="hidden" 
        accept="image/*" 
        ref={fileInputRef}
        onChange={(e) => {
          const file = e.target.files?.[0];
          if (file) handleFile(file);
        }}
      />

      <div className="text-center">
        <div className="mb-4 inline-flex items-center justify-center w-16 h-16 rounded-full bg-green-100 text-green-600 group-hover:scale-110 transition-transform duration-300">
          <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" />
          </svg>
        </div>
        <h3 className="text-lg font-semibold text-gray-900 mb-1">Upload table image</h3>
        <p className="text-sm text-gray-500 mb-6">Drag and drop or click to browse files</p>

        <div className="flex flex-wrap justify-center gap-2">
          <span className="px-3 py-1 bg-gray-100 text-gray-600 text-xs rounded-full">PNG</span>
          <span className="px-3 py-1 bg-gray-100 text-gray-600 text-xs rounded-full">JPG</span>
          <span className="px-3 py-1 bg-gray-100 text-gray-600 text-xs rounded-full">WEBP</span>
        </div>
      </div>
    </div>
  );
};

import React from 'react';
import { TableData } from '../types';

interface WorksheetProps {
  data: TableData;
}

export const Worksheet: React.FC<WorksheetProps> = ({ data }) => {
  if (!data || data.length === 0) return null;

  const rowCount = data.length;
  const colCount = Math.max(...data.map(row => row.length));

  // Generate column labels (A, B, C...)
  const getColLabel = (index: number) => {
    let label = '';
    while (index >= 0) {
      label = String.fromCharCode((index % 26) + 65) + label;
      index = Math.floor(index / 26) - 1;
    }
    return label;
  };

  return (
    <div className="w-full overflow-auto border border-gray-200 rounded-lg shadow-sm bg-white max-h-[600px]">
      <table className="w-full text-sm text-left border-collapse table-fixed">
        <thead className="sticky top-0 z-10 bg-gray-50 border-b border-gray-200">
          <tr>
            <th className="w-12 border-r border-gray-200 bg-gray-100 px-2 py-2 text-center text-xs font-semibold text-gray-400">#</th>
            {Array.from({ length: colCount }).map((_, i) => (
              <th key={i} className="min-w-[150px] border-r border-gray-200 px-3 py-2 text-center text-xs font-semibold text-gray-500 uppercase tracking-wider">
                {getColLabel(i)}
              </th>
            ))}
          </tr>
        </thead>
        <tbody className="divide-y divide-gray-200">
          {data.map((row, rowIndex) => (
            <tr key={rowIndex} className="hover:bg-green-50/30 transition-colors">
              <td className="w-12 border-r border-gray-200 bg-gray-50 px-2 py-2 text-center text-xs font-medium text-gray-400">
                {rowIndex + 1}
              </td>
              {Array.from({ length: colCount }).map((_, colIndex) => (
                <td key={colIndex} className="border-r border-gray-200 px-3 py-2 text-gray-700 whitespace-nowrap overflow-hidden text-ellipsis">
                  {row[colIndex] || ''}
                </td>
              ))}
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

