export type TableData = string[][];

export interface CellStyle {
  bold?: boolean;
  italic?: boolean;
  align?: 'left' | 'center' | 'right';
}

export type TableStyles = Record<string, CellStyle>; // key is "rowIndex-colIndex"

export interface ConversionState {
  isProcessing: boolean;
  error: string | null;
  data: TableData | null;
  fileName: string | null;
}

import React, { useMemo, useState, useRef, useEffect } from 'react';
import { TableData, CellStyle, TableStyles } from '../types';

interface WorksheetProps {
  data: TableData;
  onChange: (newData: TableData) => void;
}

export const Worksheet: React.FC<WorksheetProps> = ({ data, onChange }) => {
  const [styles, setStyles] = useState<TableStyles>({});
  const [focusedCell, setFocusedCell] = useState<{ r: number; c: number } | null>(null);
  const toolbarRef = useRef<HTMLDivElement>(null);

  if (!data || data.length === 0) return null;

  const colCount = useMemo(() => Math.max(...data.map(row => row.length)), [data]);

  const columnTypes = useMemo(() => {
    const types: boolean[] = [];
    for (let c = 0; c < colCount; c++) {
      let numericCount = 0;
      let totalCount = 0;
      for (let r = 1; r < data.length; r++) {
        const val = data[r][c]?.trim();
        if (val) {
          totalCount++;
          const cleanVal = val.replace(/[$,€,£,%]/g, '');
          if (!isNaN(Number(cleanVal)) && cleanVal !== '') {
            numericCount++;
          }
        }
      }
      types[c] = totalCount > 0 && (numericCount / totalCount) > 0.6;
    }
    return types;
  }, [data, colCount]);

  const handleCellEdit = (rowIndex: number, colIndex: number, value: string) => {
    const newData = data.map((row, r) => {
      if (r === rowIndex) {
        const newRow = [...row];
        while (newRow.length < colCount) newRow.push('');
        newRow[colIndex] = value;
        return newRow;
      }
      return row;
    });
    onChange(newData);
  };

  const updateStyle = (stylePatch: Partial<CellStyle>) => {
    if (!focusedCell) return;
    const key = `${focusedCell.r}-${focusedCell.c}`;
    setStyles(prev => ({
      ...prev,
      [key]: { ...prev[key], ...stylePatch }
    }));
  };

  const isInvalid = (rowIndex: number, colIndex: number, value: string) => {
    if (rowIndex === 0) return false;
    if (!columnTypes[colIndex]) return false;
    if (!value.trim()) return false;
    const cleanVal = value.replace(/[$,€,£,%]/g, '').trim();
    return isNaN(Number(cleanVal));
  };

  const getColLabel = (index: number) => {
    let label = '';
    let i = index;
    while (i >= 0) {
      label = String.fromCharCode((i % 26) + 65) + label;
      i = Math.floor(i / 26) - 1;
    }
    return label;
  };

  const currentCellStyle = focusedCell ? styles[`${focusedCell.r}-${focusedCell.c}`] || {} : {};

  return (
    <div className="w-full space-y-4 relative">
      {/* Floating Toolbar */}
      <div 
        className={`flex items-center space-x-1 p-1 bg-white border border-gray-200 rounded-lg shadow-lg z-30 transition-all duration-200 ${focusedCell ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-2 pointer-events-none'}`}
        style={{ width: 'fit-content' }}
      >
        <button 
          onClick={() => updateStyle({ bold: !currentCellStyle.bold })}
          className={`p-1.5 rounded hover:bg-gray-100 transition-colors ${currentCellStyle.bold ? 'bg-green-100 text-green-700' : 'text-gray-600'}`}
          title="Bold"
        >
          <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 4h8a4 4 0 014 4 4 4 0 01-4 4H6z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 12h9a4 4 0 014 4 4 4 0 01-4 4H6z" /></svg>
        </button>
        <button 
          onClick={() => updateStyle({ italic: !currentCellStyle.italic })}
          className={`p-1.5 rounded hover:bg-gray-100 transition-colors ${currentCellStyle.italic ? 'bg-green-100 text-green-700' : 'text-gray-600'}`}
          title="Italic"
        >
          <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M10 20l4-16m-4 0h4m-4 16h4" /></svg>
        </button>
        <div className="w-px h-4 bg-gray-200 mx-1"></div>
        <button 
          onClick={() => updateStyle({ align: 'left' })}
          className={`p-1.5 rounded hover:bg-gray-100 transition-colors ${currentCellStyle.align === 'left' ? 'bg-green-100 text-green-700' : 'text-gray-600'}`}
          title="Align Left"
        >
          <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 12h10M4 18h16" /></svg>
        </button>
        <button 
          onClick={() => updateStyle({ align: 'center' })}
          className={`p-1.5 rounded hover:bg-gray-100 transition-colors ${currentCellStyle.align === 'center' ? 'bg-green-100 text-green-700' : 'text-gray-600'}`}
          title="Align Center"
        >
          <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M7 12h10M4 18h16" /></svg>
        </button>
        <button 
          onClick={() => updateStyle({ align: 'right' })}
          className={`p-1.5 rounded hover:bg-gray-100 transition-colors ${currentCellStyle.align === 'right' ? 'bg-green-100 text-green-700' : 'text-gray-600'}`}
          title="Align Right"
        >
          <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M10 12h10M4 18h16" /></svg>
        </button>
      </div>

      <div className="flex items-center justify-between text-xs font-medium text-gray-500 px-1">
        <div className="flex items-center space-x-4">
          <div className="flex items-center">
            <div className="w-3 h-3 bg-red-100 border border-red-300 rounded mr-1.5"></div>
            <span>Invalid Format</span>
          </div>
          <div className="flex items-center">
            <div className="w-3 h-3 bg-blue-50 border border-blue-200 rounded mr-1.5"></div>
            <span>Selected Cell</span>
          </div>
        </div>
      </div>

      <div className="w-full overflow-auto border border-gray-200 rounded-xl shadow-sm bg-white max-h-[600px] scrollbar-thin scrollbar-thumb-gray-200">
        <table className="w-full text-sm text-left border-collapse table-fixed">
          <thead className="sticky top-0 z-20 bg-gray-50 border-b border-gray-200">
            <tr>
              <th className="w-12 border-r border-gray-200 bg-gray-100 px-2 py-2.5 text-center text-[10px] font-bold text-gray-400 uppercase tracking-tighter">#</th>
              {Array.from({ length: colCount }).map((_, i) => (
                <th key={i} className="min-w-[150px] border-r border-gray-200 px-3 py-2.5 text-center text-xs font-bold text-gray-500 uppercase tracking-wider relative group">
                  {getColLabel(i)}
                  {columnTypes[i] && (
                    <span className="absolute bottom-0 left-0 w-full h-0.5 bg-blue-400 opacity-50" title="Numeric column"></span>
                  )}
                </th>
              ))}
            </tr>
          </thead>
          <tbody className="divide-y divide-gray-200">
            {data.map((row, rowIndex) => (
              <tr key={rowIndex} className="group hover:bg-gray-50/50 transition-colors">
                <td className="w-12 border-r border-gray-200 bg-gray-50/50 px-2 py-2 text-center text-xs font-medium text-gray-400">
                  {rowIndex + 1}
                </td>
                {Array.from({ length: colCount }).map((_, colIndex) => {
                  const val = row[colIndex] || '';
                  const invalid = isInvalid(rowIndex, colIndex, val);
                  const isFocused = focusedCell?.r === rowIndex && focusedCell?.c === colIndex;
                  const cellStyle = styles[`${rowIndex}-${colIndex}`] || {};

                  return (
                    <td 
                      key={colIndex} 
                      className={`relative border-r border-gray-100 p-0 transition-all duration-200 ${
                        invalid ? 'bg-red-50' : isFocused ? 'bg-blue-50/30' : 'bg-transparent'
                      }`}
                    >
                      <input
                        type="text"
                        value={val}
                        onFocus={() => setFocusedCell({ r: rowIndex, c: colIndex })}
                        onBlur={() => {
                           // Delay blur to allow toolbar interaction
                           setTimeout(() => {
                             setFocusedCell(prev => (prev?.r === rowIndex && prev?.c === colIndex ? null : prev));
                           }, 200);
                        }}
                        onChange={(e) => handleCellEdit(rowIndex, colIndex, e.target.value)}
                        style={{
                          fontWeight: cellStyle.bold ? 'bold' : 'normal',
                          fontStyle: cellStyle.italic ? 'italic' : 'normal',
                          textAlign: cellStyle.align || 'left'
                        }}
                        className={`w-full px-3 py-2 bg-transparent outline-none transition-all ${
                          invalid 
                            ? 'text-red-700 font-medium' 
                            : 'text-gray-700'
                        } ${isFocused ? 'ring-2 ring-blue-400/50 z-10' : ''}`}
                      />
                      {invalid && (
                        <div className="absolute right-1 top-1 w-1.5 h-1.5 rounded-full bg-red-400 animate-pulse" title="Numeric expected"></div>
                      )}
                    </td>
                  );
                })}
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

import { GoogleGenAI, Type } from "@google/genai";
import { TableData } from "../types";

/**
 * High-precision extraction of tabular data from an image.
 * Uses Gemini 3 Pro with reasoning capabilities to ensure no cells are missed
 * and the spatial structure is perfectly preserved.
 */
export const convertImageToData = async (base64Image: string): Promise<TableData> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `
    Act as a high-precision OCR and document analysis engine. 
    Your mission is to extract EVERY SINGLE CELL from the tabular data in this image without exception.

    INSTRUCTIONS:
    1. EXHAUSTIVE SCAN: Meticulously scan the image for any grid, table, or structured list.
    2. SPATIAL INTEGRITY: Preserve the exact row and column structure. If a cell is blank in the image, you MUST include it as an empty string ("") in the output array to maintain column alignment.
    3. ACCURACY: Transcribe all numbers, currencies, dates, and text exactly as they appear. Correct minor OCR artifacts but do not change the underlying data.
    4. NO OMISSIONS: Do not skip headers, footers, or any small rows at the bottom.

    Format the output as a 2D array of strings.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: {
        parts: [
          { inlineData: { data: base64Image, mimeType: "image/png" } },
          { text: prompt }
        ]
      },
      config: {
        // Use thinking to reason about complex table boundaries and alignments
        thinkingConfig: { thinkingBudget: 4096 },
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            rows: {
              type: Type.ARRAY,
              description: "A 2D array representing the table rows and columns.",
              items: {
                type: Type.ARRAY,
                items: { type: Type.STRING }
              }
            }
          },
          required: ["rows"]
        }
      }
    });

    const result = JSON.parse(response.text || "{}");

    if (!result.rows || !Array.isArray(result.rows)) {
      throw new Error("The AI could not identify a valid table structure in this image.");
    }

    // Secondary cleanup to ensure all rows have consistent lengths
    const maxCols = Math.max(...result.rows.map((r: any) => r.length), 0);
    const normalizedRows = result.rows.map((row: any[]) => {
      const newRow = [...row];
      while (newRow.length < maxCols) newRow.push("");
      return newRow;
    });

    return normalizedRows;
  } catch (error) {
    console.error("Gemini High-Precision Extraction Error:", error);
    throw new Error("We encountered an issue with high-precision extraction. Please ensure the image is high resolution and the table is not obscured.");
  }
};

import React, { useState } from 'react';
