  const [state, setState] = useState<ConversionState>({
    isProcessing: false,
    error: null,
    data: null,
    fileName: null
  });
  const [isSaved, setIsSaved] = useState(false);

  // Load from localStorage on mount
  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const { data, fileName } = JSON.parse(saved);
        if (data && fileName) {
          setState(prev => ({ ...prev, data, fileName }));
        }
      } catch (e) {
        console.error("Failed to load autosave data", e);
      }
    }
  }, []);

  // Save to localStorage whenever data or fileName changes
  useEffect(() => {
    if (state.data && state.fileName) {
      localStorage.setItem(STORAGE_KEY, JSON.stringify({
        data: state.data,
        fileName: state.fileName
      }));
      setIsSaved(true);
      const timer = setTimeout(() => setIsSaved(false), 2000);
      return () => clearTimeout(timer);
    }
  }, [state.data, state.fileName]);

  const handleImageSelected = async (base64: string, fileName: string) => {
    setState({ ...state, isProcessing: true, error: null, data: null });

    try {
      const extractedData = await convertImageToData(base64);
      setState({
        isProcessing: false,
        error: null,
        data: extractedData,
        fileName: fileName.split('.')[0]
      });
    } catch (err: any) {
      setState({
        ...state,
        isProcessing: false,
        error: err.message || 'An unexpected error occurred.'
      });
    }
  };

  const handleDataChange = (newData: TableData) => {
    setState(prev => ({ ...prev, data: newData }));
  };

