import React, { useMemo, useState, useRef, useEffect } from 'react';
import { TableData, CellStyle, TableStyles } from '../types';

interface WorksheetProps {
  data: TableData;
  onChange: (newData: TableData) => void;
}

export const Worksheet: React.FC<WorksheetProps> = ({ data, onChange }) => {
  const [styles, setStyles] = useState<TableStyles>({});
  const [focusedCell, setFocusedCell] = useState<{ r: number; c: number } | null>(null);
  const [showFindReplace, setShowFindReplace] = useState(false);
  const [findText, setFindText] = useState('');
  const [replaceText, setReplaceText] = useState('');
  const [matchCase, setMatchCase] = useState(false);
  const [wholeWord, setWholeWord] = useState(false);
  const [searchResult, setSearchResult] = useState<{ r: number, c: number }[]>([]);
  const [currentSearchIndex, setCurrentSearchIndex] = useState(-1);

  if (!data || data.length === 0) return null;

  const colCount = useMemo(() => Math.max(...data.map(row => row.length)), [data]);

  const columnTypes = useMemo(() => {
    const types: boolean[] = [];
    for (let c = 0; c < colCount; c++) {
      let numericCount = 0;
      let totalCount = 0;
      for (let r = 1; r < data.length; r++) {
        const val = data[r][c]?.trim();
        if (val) {
          totalCount++;
          const cleanVal = val.replace(/[$,€,£,%]/g, '');
          if (!isNaN(Number(cleanVal)) && cleanVal !== '') {
            numericCount++;
          }
        }
      }
      types[c] = totalCount > 0 && (numericCount / totalCount) > 0.6;
    }
    return types;
  }, [data, colCount]);

  const handleCellEdit = (rowIndex: number, colIndex: number, value: string) => {
    const newData = data.map((row, r) => {
      if (r === rowIndex) {
        const newRow = [...row];
        while (newRow.length < colCount) newRow.push('');
        newRow[colIndex] = value;
        return newRow;
      }
      return row;
    });
    onChange(newData);
  };

  const updateStyle = (stylePatch: Partial<CellStyle>) => {
    if (!focusedCell) return;
    const key = `${focusedCell.r}-${focusedCell.c}`;
    setStyles(prev => ({
      ...prev,
      [key]: { ...prev[key], ...stylePatch }
    }));
  };

  const isInvalid = (rowIndex: number, colIndex: number, value: string) => {
    if (rowIndex === 0) return false;
    if (!columnTypes[colIndex]) return false;
    if (!value.trim()) return false;
    const cleanVal = value.replace(/[$,€,£,%]/g, '').trim();
    return isNaN(Number(cleanVal));
  };

  const getColLabel = (index: number) => {
    let label = '';
    let i = index;
    while (i >= 0) {
      label = String.fromCharCode((i % 26) + 65) + label;
      i = Math.floor(i / 26) - 1;
    }
    return label;
  };

  const handleFind = () => {
    if (!findText) {
      setSearchResult([]);
      setCurrentSearchIndex(-1);
      return;
    }

    const results: { r: number, c: number }[] = [];
    data.forEach((row, r) => {
      row.forEach((cell, c) => {
        let content = cell || '';
        let search = findText;

        if (!matchCase) {
          content = content.toLowerCase();
          search = search.toLowerCase();
        }

        if (wholeWord) {
          if (content === search) results.push({ r, c });
        } else if (content.includes(search)) {
          results.push({ r, c });
        }
      });
    });

    setSearchResult(results);
    if (results.length > 0) {
      const nextIndex = (currentSearchIndex + 1) % results.length;
      setCurrentSearchIndex(nextIndex);
      setFocusedCell(results[nextIndex]);
    } else {
      setCurrentSearchIndex(-1);
      alert('No matches found.');
    }
  };

  const handleReplace = () => {
    if (currentSearchIndex === -1 || searchResult.length === 0) {
      handleFind();
      return;
    }

    const current = searchResult[currentSearchIndex];
    const newData = data.map((row, r) => {
      if (r === current.r) {
        const newRow = [...row];
        const oldVal = newRow[current.c];

        // Simple replace for the focused match
        // Note: this is a basic string replace, regex would be more precise for "whole word"
        let flags = matchCase ? '' : 'i';
        let escapedFind = findText.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
        let pattern = wholeWord ? `^${escapedFind}$` : escapedFind;
        let regex = new RegExp(pattern, flags);

        newRow[current.c] = oldVal.replace(regex, replaceText);
        return newRow;
      }
      return row;
    });

    onChange(newData);
    // Move to next
    handleFind();
  };

  const handleReplaceAll = () => {
    if (!findText) return;

    let count = 0;
    let flags = matchCase ? 'g' : 'gi';
    let escapedFind = findText.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
    let pattern = wholeWord ? `\\b${escapedFind}\\b` : escapedFind;
    let regex = new RegExp(pattern, flags);

    const newData = data.map(row => 
      row.map(cell => {
        const newVal = cell.replace(regex, replaceText);
        if (newVal !== cell) count++;
        return newVal;
      })
    );

    onChange(newData);
    alert(`Replaced ${count} occurrences.`);
    setSearchResult([]);
    setCurrentSearchIndex(-1);
  };

  const currentCellStyle = focusedCell ? styles[`${focusedCell.r}-${focusedCell.c}`] || {} : {};

  return (
    <div className="w-full space-y-4 relative">
      <div className="flex flex-wrap items-center justify-between gap-4">
        {/* Floating Toolbar */}
        <div 
          className={`flex items-center space-x-1 p-1 bg-white border border-gray-200 rounded-lg shadow-sm z-30 transition-all duration-200 ${focusedCell ? 'opacity-100' : 'opacity-50 grayscale'}`}
          style={{ width: 'fit-content' }}
        >
          <button 
            onClick={() => updateStyle({ bold: !currentCellStyle.bold })}
            className={`p-1.5 rounded hover:bg-gray-100 transition-colors ${currentCellStyle.bold ? 'bg-green-100 text-green-700' : 'text-gray-600'}`}
            title="Bold"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 4h8a4 4 0 014 4 4 4 0 01-4 4H6z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 12h9a4 4 0 014 4 4 4 0 01-4 4H6z" /></svg>
          </button>
          <button 
            onClick={() => updateStyle({ italic: !currentCellStyle.italic })}
            className={`p-1.5 rounded hover:bg-gray-100 transition-colors ${currentCellStyle.italic ? 'bg-green-100 text-green-700' : 'text-gray-600'}`}
            title="Italic"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M10 20l4-16m-4 0h4m-4 16h4" /></svg>
          </button>
          <div className="w-px h-4 bg-gray-200 mx-1"></div>
          <button 
            onClick={() => updateStyle({ align: 'left' })}
            className={`p-1.5 rounded hover:bg-gray-100 transition-colors ${currentCellStyle.align === 'left' ? 'bg-green-100 text-green-700' : 'text-gray-600'}`}
            title="Align Left"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 12h10M4 18h16" /></svg>
          </button>
          <button 
            onClick={() => updateStyle({ align: 'center' })}
            className={`p-1.5 rounded hover:bg-gray-100 transition-colors ${currentCellStyle.align === 'center' ? 'bg-green-100 text-green-700' : 'text-gray-600'}`}
            title="Align Center"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M7 12h10M4 18h16" /></svg>
          </button>
          <button 
            onClick={() => updateStyle({ align: 'right' })}
            className={`p-1.5 rounded hover:bg-gray-100 transition-colors ${currentCellStyle.align === 'right' ? 'bg-green-100 text-green-700' : 'text-gray-600'}`}
            title="Align Right"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M10 12h10M4 18h16" /></svg>
          </button>
        </div>

        <button 
          onClick={() => setShowFindReplace(!showFindReplace)}
          className={`inline-flex items-center px-3 py-1.5 border rounded-lg text-sm font-medium transition-colors ${showFindReplace ? 'bg-blue-600 text-white border-blue-600' : 'bg-white text-gray-700 border-gray-300 hover:bg-gray-50'}`}
        >
          <svg className="w-4 h-4 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
          Find & Replace
        </button>
      </div>

      {/* Find & Replace Panel */}
      {showFindReplace && (
        <div className="p-4 bg-gray-50 border border-gray-200 rounded-xl animate-in slide-in-from-top-2">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-4">
            <div className="space-y-1">
              <label className="text-xs font-bold text-gray-500 uppercase">Find</label>
              <input 
                type="text" 
                value={findText}
                onChange={(e) => setFindText(e.target.value)}
                placeholder="Search for text..."
                className="w-full px-3 py-2 bg-white border border-gray-300 rounded-lg text-sm outline-none focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500"
              />
