                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" />
                  </svg>
                </div>
              </div>
              <h3 className="text-xl font-bold text-gray-900 mb-2">Performing High-Precision Analysis...</h3>
              <p className="text-gray-500 italic">Our AI is meticulously scanning every cell and mapping the layout. This ensures maximum accuracy for complex tables.</p>
            </div>
          )}

          {/* Error State */}
          {state.error && (
            <div className="max-w-2xl mx-auto bg-red-50 border border-red-200 rounded-xl p-6 text-center">
              <div className="inline-flex items-center justify-center w-12 h-12 rounded-full bg-red-100 text-red-600 mb-4">
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
                </svg>
              </div>
              <h3 className="text-lg font-bold text-red-800 mb-2">Conversion failed</h3>
              <p className="text-red-600 mb-6">{state.error}</p>
              <button 
                onClick={reset}
                className="inline-flex items-center px-6 py-3 border border-transparent text-base font-medium rounded-md shadow-sm text-white bg-red-600 hover:bg-red-700 transition-colors"
              >
                Try Another Image
              </button>
            </div>
          )}

          {/* Results State */}
          {state.data && (
            <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-700">
              <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
                <div className="flex flex-col">
                  <div className="flex items-center space-x-2">
                    <h3 className="text-2xl font-bold text-gray-900">Extracted Worksheet</h3>
                    {isSaved && (
                      <span className="flex items-center text-[10px] font-bold text-green-600 bg-green-50 px-2 py-0.5 rounded-full uppercase tracking-wider animate-in fade-in slide-in-from-left-2">
                        <svg className="w-3 h-3 mr-1" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" /></svg>
                        Autosaved
                      </span>
                    )}
                  </div>
                  <p className="text-sm text-gray-500 mt-1">Found {state.data.length} rows of data. Progress is automatically saved.</p>
                </div>

                <div className="flex items-center gap-2">
                  <button 
                    onClick={handleCopy}
                    className="inline-flex items-center px-4 py-2 bg-white border border-gray-300 rounded-lg text-sm font-medium text-gray-700 hover:bg-gray-50 hover:shadow-sm transition-all"
                  >
                    <svg className="w-4 h-4 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 5H6a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2v-1M8 5a2 2 0 002 2h2a2 2 0 002-2M8 5a2 2 0 012-2h2a2 2 0 012 2m0 0h2a2 2 0 012 2v3m2 4H10m0 0l3-3m-3 3l3 3" />
                    </svg>
                    Copy
                  </button>
                  <button 
                    onClick={() => shareData(state.data!)}
                    className="inline-flex items-center px-4 py-2 bg-white border border-gray-300 rounded-lg text-sm font-medium text-gray-700 hover:bg-gray-50 hover:shadow-sm transition-all"
                  >
                    <svg className="w-4 h-4 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8.684 13.342C8.886 12.938 9 12.482 9 12c0-.482-.114-.938-.316-1.342m0 2.684a3 3 0 110-2.684m0 2.684l6.632 3.316m-6.632-6l6.632-3.316m0 0a3 3 0 105.367-2.684 3 3 0 00-5.367 2.684zm0 9.316a3 3 0 105.368 2.684 3 3 0 00-5.368-2.684z" />
                    </svg>
                    Share
                  </button>
                  <button 
                    onClick={() => downloadAsCSV(state.data!, state.fileName || 'Snap2Sheet_Export')}
                    className="inline-flex items-center px-4 py-2 bg-white border border-gray-300 rounded-lg text-sm font-medium text-gray-700 hover:bg-gray-50 hover:shadow-sm transition-all"
                  >
                    <svg className="w-4 h-4 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" />
                    </svg>
                    Export CSV
                  </button>
                  <button 
                    onClick={() => downloadAsExcel(state.data!, state.fileName || 'Snap2Sheet_Export')}
                    className="inline-flex items-center px-4 py-2 bg-green-600 border border-transparent rounded-lg text-sm font-semibold text-white hover:bg-green-700 shadow-sm transition-all"
                  >
                    <svg className="w-4 h-4 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" />
                    </svg>
                    Download .xlsx
                  </button>
                </div>
              </div>

              <Worksheet 
                data={state.data} 
                onChange={handleDataChange}
              />

              <div className="flex justify-center pt-8">
                <button 
                  onClick={reset}
                  className="inline-flex items-center px-6 py-3 border border-gray-300 shadow-sm text-base font-medium rounded-xl text-gray-700 bg-white hover:bg-gray-50 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-green-500 transition-all"
                >
                  <svg className="w-5 h-5 mr-2 text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 15l-3-3m0 0l3-3m-3 3h8M3 12a9 9 0 1118 0 9 9 0 01-18 0z" />
                  </svg>
                  Convert another image
                </button>
              </div>
            </div>
          )}
        </div>

        {/* Features Section */}
        {!state.data && !state.isProcessing && (
          <div className="mt-32 grid grid-cols-1 gap-12 sm:grid-cols-3">
            <div className="text-center">
              <div className="flex items-center justify-center h-12 w-12 rounded-md bg-green-500 text-white mx-auto mb-4">
                <svg className="h-6 w-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" />
                </svg>
              </div>
              <h4 className="text-lg font-bold text-gray-900">Exhaustive Extraction</h4>
              <p className="mt-2 text-gray-500">Powered by Gemini 3 Pro with Thinking reasoning to ensure zero missed cells.</p>
            </div>
            <div className="text-center">
              <div className="flex items-center justify-center h-12 w-12 rounded-md bg-blue-500 text-white mx-auto mb-4">
                <svg className="h-6 w-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
                </svg>
              </div>
              <h4 className="text-lg font-bold text-gray-900">Spatial Awareness</h4>
              <p className="mt-2 text-gray-500">Maintains complex multi-column layouts even with merged or blank cells.</p>
            </div>
            <div className="text-center">
              <div className="flex items-center justify-center h-12 w-12 rounded-md bg-purple-500 text-white mx-auto mb-4">
                <svg className="h-6 w-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z" />
                </svg>
              </div>
              <h4 className="text-lg font-bold text-gray-900">Secure Processing</h4>
              <p className="mt-2 text-gray-500">Your data is ephemeral and used only for the immediate conversion process.</p>
            </div>
          </div>
        )}
      </div>
    </Layout>
  );
};

export default App;

export type TableData = string[][];

export interface CellStyle {
  bold?: boolean;
  italic?: boolean;
  align?: 'left' | 'center' | 'right';
  rowSpan?: number;
  colSpan?: number;
}

export type TableStyles = Record<string, CellStyle>; // key is "rowIndex-colIndex"

export interface ConversionState {
  isProcessing: boolean;
  error: string | null;
  data: TableData | null;
  fileName: string | null;
}

import React, { useMemo, useState, useRef, useEffect, useCallback } from 'react';
import { TableData, CellStyle, TableStyles } from '../types';

interface WorksheetProps {
  data: TableData;
  onChange: (newData: TableData) => void;
}

interface Selection {
  start: { r: number; c: number };
  end: { r: number; c: number };
}

export const Worksheet: React.FC<WorksheetProps> = ({ data, onChange }) => {
  const [styles, setStyles] = useState<TableStyles>({});
  const [focusedCell, setFocusedCell] = useState<{ r: number; c: number } | null>(null);
  const [selection, setSelection] = useState<Selection | null>(null);
  const [isSelecting, setIsSelecting] = useState(false);

  const [showFindReplace, setShowFindReplace] = useState(false);
  const [findText, setFindText] = useState('');
  const [replaceText, setReplaceText] = useState('');
  const [matchCase, setMatchCase] = useState(false);
  const [wholeWord, setWholeWord] = useState(false);
  const [searchResult, setSearchResult] = useState<{ r: number, c: number }[]>([]);
  const [currentSearchIndex, setCurrentSearchIndex] = useState(-1);

  if (!data || data.length === 0) return null;

  const colCount = useMemo(() => Math.max(...data.map(row => row.length)), [data]);

  const columnTypes = useMemo(() => {
    const types: boolean[] = [];
    for (let c = 0; c < colCount; c++) {
      let numericCount = 0;
      let totalCount = 0;
      for (let r = 1; r < data.length; r++) {
        const val = data[r][c]?.trim();
        if (val) {
          totalCount++;
          const cleanVal = val.replace(/[$,€,£,%]/g, '');
          if (!isNaN(Number(cleanVal)) && cleanVal !== '') {
            numericCount++;
          }
        }
      }
      types[c] = totalCount > 0 && (numericCount / totalCount) > 0.6;
    }
    return types;
  }, [data, colCount]);

  // Pre-calculate hidden cells for performance
  const hiddenCells = useMemo(() => {
    const hidden = new Set<string>();
    Object.entries(styles).forEach(([key, style]) => {
      if ((style.rowSpan && style.rowSpan > 1) || (style.colSpan && style.colSpan > 1)) {
        const [r, c] = key.split('-').map(Number);
        const rowSpan = style.rowSpan || 1;
        const colSpan = style.colSpan || 1;
        for (let dr = 0; dr < rowSpan; dr++) {
          for (let dc = 0; dc < colSpan; dc++) {
            if (dr === 0 && dc === 0) continue;
            hidden.add(`${r + dr}-${c + dc}`);
          }
        }
      }
    });
    return hidden;
  }, [styles]);

  const handleCellEdit = (rowIndex: number, colIndex: number, value: string) => {
    const newData = data.map((row, r) => {
      if (r === rowIndex) {
        const newRow = [...row];
        while (newRow.length < colCount) newRow.push('');
        newRow[colIndex] = value;
        return newRow;
      }
      return row;
    });
    onChange(newData);
  };

  const updateStyle = (stylePatch: Partial<CellStyle>) => {
    if (!focusedCell && !selection) return;

    setStyles(prev => {
      const next = { ...prev };

      // If we have a range selection, apply to all visible cells in range
      if (selection) {
        const rStart = Math.min(selection.start.r, selection.end.r);
        const rEnd = Math.max(selection.start.r, selection.end.r);
        const cStart = Math.min(selection.start.c, selection.end.c);
        const cEnd = Math.max(selection.start.c, selection.end.c);

        for (let r = rStart; r <= rEnd; r++) {
          for (let c = cStart; c <= cEnd; c++) {
            const key = `${r}-${c}`;
            if (!hiddenCells.has(key)) {
              next[key] = { ...next[key], ...stylePatch };
            }
          }
        }
      } else if (focusedCell) {
        const key = `${focusedCell.r}-${focusedCell.c}`;
        next[key] = { ...next[key], ...stylePatch };
      }

      return next;
    });
  };

  const handleMerge = () => {
    if (!selection) return;
    const rStart = Math.min(selection.start.r, selection.end.r);
    const rEnd = Math.max(selection.start.r, selection.end.r);
    const cStart = Math.min(selection.start.c, selection.end.c);
    const cEnd = Math.max(selection.start.c, selection.end.c);

    if (rStart === rEnd && cStart === cEnd) return;

    const rowSpan = rEnd - rStart + 1;
    const colSpan = cEnd - cStart + 1;

    setStyles(prev => {
      const next = { ...prev };
      // Remove styles of cells that will be hidden
      for (let r = rStart; r <= rEnd; r++) {
        for (let c = cStart; c <= cEnd; c++) {
          if (r === rStart && c === cStart) continue;
          delete next[`${r}-${c}`];
        }
      }
      // Apply merge to top-left cell
      next[`${rStart}-${cStart}`] = { 
        ...next[`${rStart}-${cStart}`], 
        rowSpan, 
        colSpan 
      };
      return next;
    });
    setSelection(null);
    setFocusedCell({ r: rStart, c: cStart });
  };

  const handleUnmerge = () => {
    if (!focusedCell) return;
    const key = `${focusedCell.r}-${focusedCell.c}`;
    if (styles[key]?.rowSpan || styles[key]?.colSpan) {
      setStyles(prev => {
        const next = { ...prev };
        const { rowSpan, colSpan, ...rest } = next[key];
        next[key] = rest;
        return next;
      });
    }
  };

  const isInvalid = (rowIndex: number, colIndex: number, value: string) => {
    if (rowIndex === 0) return false;
    if (!columnTypes[colIndex]) return false;
    if (!value.trim()) return false;
    const cleanVal = value.replace(/[$,€,£,%]/g, '').trim();
    return isNaN(Number(cleanVal));
  };

  const getColLabel = (index: number) => {
    let label = '';
    let i = index;
    while (i >= 0) {
      label = String.fromCharCode((i % 26) + 65) + label;
      i = Math.floor(i / 26) - 1;
    }
    return label;
  };

  const handleFind = () => {
    if (!findText) {
      setSearchResult([]);
      setCurrentSearchIndex(-1);
      return;
    }

    const results: { r: number, c: number }[] = [];
    data.forEach((row, r) => {
      row.forEach((cell, c) => {
        let content = cell || '';
        let search = findText;

        if (!matchCase) {
          content = content.toLowerCase();
          search = search.toLowerCase();
        }

        if (wholeWord) {
          if (content === search) results.push({ r, c });
        } else if (content.includes(search)) {
          results.push({ r, c });
        }
      });
    });

    setSearchResult(results);
    if (results.length > 0) {
      const nextIndex = (currentSearchIndex + 1) % results.length;
      setCurrentSearchIndex(nextIndex);
      setFocusedCell(results[nextIndex]);
      setSelection(null);
    } else {
      setCurrentSearchIndex(-1);
      alert('No matches found.');
    }
  };

  const handleReplace = () => {
    if (currentSearchIndex === -1 || searchResult.length === 0) {
      handleFind();
      return;
    }

    const current = searchResult[currentSearchIndex];
    const newData = data.map((row, r) => {
      if (r === current.r) {
        const newRow = [...row];
        const oldVal = newRow[current.c];
        let flags = matchCase ? '' : 'i';
        let escapedFind = findText.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
        let pattern = wholeWord ? `^${escapedFind}$` : escapedFind;
        let regex = new RegExp(pattern, flags);
        newRow[current.c] = oldVal.replace(regex, replaceText);
        return newRow;
      }
      return row;
    });

    onChange(newData);
    handleFind();
  };

  const handleReplaceAll = () => {
    if (!findText) return;
    let count = 0;
    let flags = matchCase ? 'g' : 'gi';
    let escapedFind = findText.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
    let pattern = wholeWord ? `\\b${escapedFind}\\b` : escapedFind;
    let regex = new RegExp(pattern, flags);
    const newData = data.map(row => 
      row.map(cell => {
        const newVal = cell.replace(regex, replaceText);
        if (newVal !== cell) count++;
        return newVal;
      })
    );
    onChange(newData);
    alert(`Replaced ${count} occurrences.`);
    setSearchResult([]);
    setCurrentSearchIndex(-1);
  };

  const handleMouseDown = (r: number, c: number) => {
    setIsSelecting(true);
    setSelection({ start: { r, c }, end: { r, c } });
    setFocusedCell({ r, c });
  };

  const handleMouseEnter = (r: number, c: number) => {
    if (isSelecting && selection) {
      setSelection({ ...selection, end: { r, c } });
    }
  };

  const handleMouseUp = () => {
    setIsSelecting(false);
    // If start and end are same, treat as single cell focus
    if (selection && selection.start.r === selection.end.r && selection.start.c === selection.end.c) {
      setSelection(null);
    }
  };

  const isSelected = (r: number, c: number) => {
    if (!selection) return false;
    const rStart = Math.min(selection.start.r, selection.end.r);
    const rEnd = Math.max(selection.start.r, selection.end.r);
    const cStart = Math.min(selection.start.c, selection.end.c);
    const cEnd = Math.max(selection.start.c, selection.end.c);
    return r >= rStart && r <= rEnd && c >= cStart && c <= cEnd;
  };

  const currentCellStyle = focusedCell ? styles[`${focusedCell.r}-${focusedCell.c}`] || {} : {};
  const isSelectedRange = selection && (selection.start.r !== selection.end.r || selection.start.c !== selection.end.c);

  return (
    <div className="w-full space-y-4 relative" onMouseUp={handleMouseUp}>
      <div className="flex flex-wrap items-center justify-between gap-4">
        {/* Floating Toolbar */}
        <div 
          className={`flex items-center space-x-1 p-1 bg-white border border-gray-200 rounded-lg shadow-sm z-30 transition-all duration-200 ${focusedCell || selection ? 'opacity-100' : 'opacity-50 grayscale'}`}
          style={{ width: 'fit-content' }}
        >
          <button 
            onClick={() => updateStyle({ bold: !currentCellStyle.bold })}
            className={`p-1.5 rounded hover:bg-gray-100 transition-colors ${currentCellStyle.bold ? 'bg-green-100 text-green-700' : 'text-gray-600'}`}
            title="Bold"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 4h8a4 4 0 014 4 4 4 0 01-4 4H6z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 12h9a4 4 0 014 4 4 4 0 01-4 4H6z" /></svg>
          </button>
          <button 
            onClick={() => updateStyle({ italic: !currentCellStyle.italic })}
            className={`p-1.5 rounded hover:bg-gray-100 transition-colors ${currentCellStyle.italic ? 'bg-green-100 text-green-700' : 'text-gray-600'}`}
            title="Italic"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M10 20l4-16m-4 0h4m-4 16h4" /></svg>
          </button>
          <div className="w-px h-4 bg-gray-200 mx-1"></div>
          <button 
            onClick={() => updateStyle({ align: 'left' })}
            className={`p-1.5 rounded hover:bg-gray-100 transition-colors ${currentCellStyle.align === 'left' ? 'bg-green-100 text-green-700' : 'text-gray-600'}`}
            title="Align Left"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 12h10M4 18h16" /></svg>
          </button>
          <button 
            onClick={() => updateStyle({ align: 'center' })}
            className={`p-1.5 rounded hover:bg-gray-100 transition-colors ${currentCellStyle.align === 'center' ? 'bg-green-100 text-green-700' : 'text-gray-600'}`}
            title="Align Center"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M7 12h10M4 18h16" /></svg>
          </button>
          <button 
            onClick={() => updateStyle({ align: 'right' })}
            className={`p-1.5 rounded hover:bg-gray-100 transition-colors ${currentCellStyle.align === 'right' ? 'bg-green-100 text-green-700' : 'text-gray-600'}`}
            title="Align Right"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M10 12h10M4 18h16" /></svg>
          </button>
          <div className="w-px h-4 bg-gray-200 mx-1"></div>
          <button 
            onClick={handleMerge}
            disabled={!isSelectedRange}
            className={`p-1.5 rounded hover:bg-gray-100 transition-colors ${!isSelectedRange ? 'opacity-30 cursor-not-allowed' : 'text-gray-600'}`}
            title="Merge Cells"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 8V6a2 2 0 012-2h4M4 16v2a2 2 0 002 2h4M20 8V6a2 2 0 00-2-2h-4M20 16v2a2 2 0 01-2 2h-4M8 12h8" />
            </svg>
          </button>
          <button 
            onClick={handleUnmerge}
            disabled={!focusedCell || !(styles[`${focusedCell.r}-${focusedCell.c}`]?.rowSpan || styles[`${focusedCell.r}-${focusedCell.c}`]?.colSpan)}
            className={`p-1.5 rounded hover:bg-gray-100 transition-colors ${(!focusedCell || !(styles[`${focusedCell.r}-${focusedCell.c}`]?.rowSpan || styles[`${focusedCell.r}-${focusedCell.c}`]?.colSpan)) ? 'opacity-30 cursor-not-allowed' : 'text-gray-600'}`}
            title="Unmerge Cells"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 6v6m0 0v6m0-6h6m-6 0H6M4 4h16v16H4V4z" />
            </svg>
          </button>
        </div>

        <button 
          onClick={() => setShowFindReplace(!showFindReplace)}
          className={`inline-flex items-center px-3 py-1.5 border rounded-lg text-sm font-medium transition-colors ${showFindReplace ? 'bg-blue-600 text-white border-blue-600' : 'bg-white text-gray-700 border-gray-300 hover:bg-gray-50'}`}
        >
          <svg className="w-4 h-4 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
          Find & Replace
        </button>
      </div>

      {/* Find & Replace Panel */}
      {showFindReplace && (
        <div className="p-4 bg-gray-50 border border-gray-200 rounded-xl animate-in slide-in-from-top-2">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-4">
            <div className="space-y-1">
              <label className="text-xs font-bold text-gray-500 uppercase">Find</label>
              <input 
                type="text" 
                value={findText}
                onChange={(e) => setFindText(e.target.value)}
                placeholder="Search for text..."
                className="w-full px-3 py-2 bg-white border border-gray-300 rounded-lg text-sm outline-none focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500"
              />
            </div>
            <div className="space-y-1">
              <label className="text-xs font-bold text-gray-500 uppercase">Replace with</label>
              <input 
                type="text" 
                value={replaceText}
                onChange={(e) => setReplaceText(e.target.value)}
                placeholder="New text..."
                className="w-full px-3 py-2 bg-white border border-gray-300 rounded-lg text-sm outline-none focus:ring-2 focus:ring-green-500/20 focus:border-green-500"
              />
            </div>
          </div>
          <div className="flex flex-wrap items-center justify-between gap-4">
            <div className="flex items-center space-x-4">
              <label className="flex items-center space-x-2 text-sm text-gray-600 cursor-pointer">
                <input type="checkbox" checked={matchCase} onChange={(e) => setMatchCase(e.target.checked)} className="w-4 h-4 rounded border-gray-300 text-blue-600 focus:ring-blue-500" />
                <span>Match case</span>
              </label>
              <label className="flex items-center space-x-2 text-sm text-gray-600 cursor-pointer">
                <input type="checkbox" checked={wholeWord} onChange={(e) => setWholeWord(e.target.checked)} className="w-4 h-4 rounded border-gray-300 text-blue-600 focus:ring-blue-500" />
                <span>Whole word</span>
              </label>
            </div>
            <div className="flex items-center space-x-2">
              {searchResult.length > 0 && (
                <span className="text-xs text-gray-500 mr-2">
                  {currentSearchIndex + 1} of {searchResult.length}
                </span>
              )}
              <button 
                onClick={handleFind}
                className="px-4 py-2 bg-blue-600 text-white text-sm font-semibold rounded-lg hover:bg-blue-700 transition-colors shadow-sm"
              >
                Next Match
              </button>
              <button 
                onClick={handleReplace}
                className="px-4 py-2 bg-white border border-gray-300 text-gray-700 text-sm font-semibold rounded-lg hover:bg-gray-50 transition-colors shadow-sm"
              >
                Replace
              </button>
              <button 
                onClick={handleReplaceAll}
                className="px-4 py-2 bg-white border border-gray-300 text-gray-700 text-sm font-semibold rounded-lg hover:bg-gray-50 transition-colors shadow-sm"
              >
                Replace All
              </button>
            </div>
          </div>
        </div>
      )}

      <div className="flex items-center justify-between text-xs font-medium text-gray-500 px-1">
        <div className="flex items-center space-x-4">
          <div className="flex items-center">
            <div className="w-3 h-3 bg-red-100 border border-red-300 rounded mr-1.5"></div>
            <span>Invalid Format</span>
          </div>
          <div className="flex items-center">
            <div className="w-3 h-3 bg-blue-50 border border-blue-200 rounded mr-1.5"></div>
            <span>Selection</span>
          </div>
          <div className="flex items-center">
            <div className="w-3 h-3 bg-green-50 border border-green-200 rounded mr-1.5"></div>
            <span>Active Cell</span>
          </div>
        </div>
      </div>

      <div className="w-full overflow-auto border border-gray-200 rounded-xl shadow-sm bg-white max-h-[600px] scrollbar-thin scrollbar-thumb-gray-200">
        <table className="w-full text-sm text-left border-collapse table-fixed select-none">
          <thead className="sticky top-0 z-20 bg-gray-50 border-b border-gray-200">
            <tr>
              <th className="w-12 border-r border-gray-200 bg-gray-100 px-2 py-2.5 text-center text-[10px] font-bold text-gray-400 uppercase tracking-tighter">#</th>
              {Array.from({ length: colCount }).map((_, i) => (
                <th key={i} className="min-w-[150px] border-r border-gray-200 px-3 py-2.5 text-center text-xs font-bold text-gray-500 uppercase tracking-wider relative group">
                  {getColLabel(i)}
                  {columnTypes[i] && (
                    <span className="absolute bottom-0 left-0 w-full h-0.5 bg-blue-400 opacity-50" title="Numeric column"></span>
                  )}
                </th>
              ))}
            </tr>
          </thead>
          <tbody className="divide-y divide-gray-200">
            {data.map((row, rowIndex) => (
              <tr key={rowIndex} className="group hover:bg-gray-50/50 transition-colors">
                <td className="w-12 border-r border-gray-200 bg-gray-50/50 px-2 py-2 text-center text-xs font-medium text-gray-400">
                  {rowIndex + 1}
                </td>
                {Array.from({ length: colCount }).map((_, colIndex) => {
                  const key = `${rowIndex}-${colIndex}`;
                  if (hiddenCells.has(key)) return null;

                  const val = row[colIndex] || '';
                  const invalid = isInvalid(rowIndex, colIndex, val);
                  const isFocused = focusedCell?.r === rowIndex && focusedCell?.c === colIndex;
                  const selected = isSelected(rowIndex, colIndex);
                  const cellStyle = styles[key] || {};

                  return (
                    <td 
                      key={colIndex} 
                      rowSpan={cellStyle.rowSpan || 1}
                      colSpan={cellStyle.colSpan || 1}
                      onMouseDown={() => handleMouseDown(rowIndex, colIndex)}
                      onMouseEnter={() => handleMouseEnter(rowIndex, colIndex)}
                      className={`relative border-r border-gray-100 p-0 transition-all duration-200 ${
                        invalid ? 'bg-red-50' : isFocused ? 'bg-green-50/40' : selected ? 'bg-blue-50/50' : 'bg-transparent'
                      } ${selected ? 'ring-1 ring-inset ring-blue-300 z-10' : ''}`}
                    >
                      <input
                        type="text"
                        value={val}
                        onFocus={() => {
                          setFocusedCell({ r: rowIndex, c: colIndex });
                          if (!isSelecting) setSelection(null);
                        }}
                        onChange={(e) => handleCellEdit(rowIndex, colIndex, e.target.value)}
                        style={{
                          fontWeight: cellStyle.bold ? 'bold' : 'normal',
                          fontStyle: cellStyle.italic ? 'italic' : 'normal',
                          textAlign: cellStyle.align || 'left'
                        }}
                        className={`w-full px-3 py-2 bg-transparent outline-none transition-all ${
                          invalid 
                            ? 'text-red-700 font-medium' 
                            : 'text-gray-700'
                        } ${isFocused ? 'ring-2 ring-green-400/50 z-20' : ''}`}
                      />
                      {invalid && (
                        <div className="absolute right-1 top-1 w-1.5 h-1.5 rounded-full bg-red-400 animate-pulse" title="Numeric expected"></div>
                      )}
                    </td>
                  );
                })}
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

import React, { useMemo, useState, useRef, useEffect, useCallback } from 'react';
import { TableData, CellStyle, TableStyles } from '../types';

interface WorksheetProps {
  data: TableData;
  onChange: (newData: TableData) => void;
}

interface Selection {
  start: { r: number; c: number };
  end: { r: number; c: number };
}

export const Worksheet: React.FC<WorksheetProps> = ({ data, onChange }) => {
  const [styles, setStyles] = useState<TableStyles>({});
  const [focusedCell, setFocusedCell] = useState<{ r: number; c: number } | null>(null);
  const [selection, setSelection] = useState<Selection | null>(null);
  const [isSelecting, setIsSelecting] = useState(false);

  const [showFindReplace, setShowFindReplace] = useState(false);
  const [findText, setFindText] = useState('');
  const [replaceText, setReplaceText] = useState('');
  const [matchCase, setMatchCase] = useState(false);
  const [wholeWord, setWholeWord] = useState(false);
  const [searchResult, setSearchResult] = useState<{ r: number, c: number }[]>([]);
  const [currentSearchIndex, setCurrentSearchIndex] = useState(-1);

  if (!data || data.length === 0) return null;

  const colCount = useMemo(() => Math.max(...data.map(row => row.length)), [data]);

  const columnTypes = useMemo(() => {
    const types: boolean[] = [];
    for (let c = 0; c < colCount; c++) {
      let numericCount = 0;
      let totalCount = 0;
      for (let r = 1; r < data.length; r++) {
        const val = data[r][c]?.trim();
        if (val) {
          totalCount++;
          const cleanVal = val.replace(/[$,€,£,%]/g, '');
          if (!isNaN(Number(cleanVal)) && cleanVal !== '') {
            numericCount++;
          }
        }
      }
      types[c] = totalCount > 0 && (numericCount / totalCount) > 0.6;
    }
    return types;
  }, [data, colCount]);

  // Pre-calculate hidden cells for performance
  const hiddenCells = useMemo(() => {
    const hidden = new Set<string>();
    // Fix: Explicitly cast Object.entries to ensure 'style' is recognized as 'CellStyle' instead of 'unknown'
    (Object.entries(styles) as [string, CellStyle][]).forEach(([key, style]) => {
      if ((style.rowSpan && style.rowSpan > 1) || (style.colSpan && style.colSpan > 1)) {
        const [r, c] = key.split('-').map(Number);
        const rowSpan = style.rowSpan || 1;
        const colSpan = style.colSpan || 1;
        for (let dr = 0; dr < rowSpan; dr++) {
          for (let dc = 0; dc < colSpan; dc++) {
            if (dr === 0 && dc === 0) continue;
            hidden.add(`${r + dr}-${c + dc}`);
          }
        }
      }
    });
    return hidden;
  }, [styles]);

  const handleCellEdit = (rowIndex: number, colIndex: number, value: string) => {
    const newData = data.map((row, r) => {
      if (r === rowIndex) {
        const newRow = [...row];
        while (newRow.length < colCount) newRow.push('');
        newRow[colIndex] = value;
        return newRow;
      }
      return row;
    });
    onChange(newData);
  };

  const updateStyle = (stylePatch: Partial<CellStyle>) => {
    if (!focusedCell && !selection) return;

    setStyles(prev => {
      const next = { ...prev };

      // If we have a range selection, apply to all visible cells in range
      if (selection) {
        const rStart = Math.min(selection.start.r, selection.end.r);
        const rEnd = Math.max(selection.start.r, selection.end.r);
        const cStart = Math.min(selection.start.c, selection.end.c);
        const cEnd = Math.max(selection.start.c, selection.end.c);

        for (let r = rStart; r <= rEnd; r++) {
          for (let c = cStart; c <= cEnd; c++) {
            const key = `${r}-${c}`;
            if (!hiddenCells.has(key)) {
              next[key] = { ...next[key], ...stylePatch };
            }
          }
        }
      } else if (focusedCell) {
        const key = `${focusedCell.r}-${focusedCell.c}`;
        next[key] = { ...next[key], ...stylePatch };
      }

      return next;
    });
  };

  const handleMerge = () => {
    if (!selection) return;
    const rStart = Math.min(selection.start.r, selection.end.r);
    const rEnd = Math.max(selection.start.r, selection.end.r);
    const cStart = Math.min(selection.start.c, selection.end.c);
    const cEnd = Math.max(selection.start.c, selection.end.c);

    if (rStart === rEnd && cStart === cEnd) return;

    const rowSpan = rEnd - rStart + 1;
    const colSpan = cEnd - cStart + 1;

    setStyles(prev => {
      const next = { ...prev };
      // Remove styles of cells that will be hidden
      for (let r = rStart; r <= rEnd; r++) {
        for (let c = cStart; c <= cEnd; c++) {
          if (r === rStart && c === cStart) continue;
          delete next[`${r}-${c}`];
        }
      }
      // Apply merge to top-left cell
      next[`${rStart}-${cStart}`] = { 
        ...next[`${rStart}-${cStart}`], 
        rowSpan, 
        colSpan 
      };
      return next;
    });
    setSelection(null);
    setFocusedCell({ r: rStart, c: cStart });
  };

  const handleUnmerge = () => {
    if (!focusedCell) return;
    const key = `${focusedCell.r}-${focusedCell.c}`;
    if (styles[key]?.rowSpan || styles[key]?.colSpan) {
      setStyles(prev => {
        const next = { ...prev };
        const { rowSpan, colSpan, ...rest } = next[key];
        next[key] = rest;
        return next;
      });
    }
  };

  const isInvalid = (rowIndex: number, colIndex: number, value: string) => {
    if (rowIndex === 0) return false;
    if (!columnTypes[colIndex]) return false;
    if (!value.trim()) return false;
    const cleanVal = value.replace(/[$,€,£,%]/g, '').trim();
    return isNaN(Number(cleanVal));
  };

  const getColLabel = (index: number) => {
    let label = '';
    let i = index;
    while (i >= 0) {
      label = String.fromCharCode((i % 26) + 65) + label;
      i = Math.floor(i / 26) - 1;
    }
    return label;
  };

  const handleFind = () => {
    if (!findText) {
      setSearchResult([]);
      setCurrentSearchIndex(-1);
      return;
    }

    const results: { r: number, c: number }[] = [];
    data.forEach((row, r) => {
      row.forEach((cell, c) => {
        let content = cell || '';
        let search = findText;

        if (!matchCase) {
          content = content.toLowerCase();
          search = search.toLowerCase();
        }

        if (wholeWord) {
          if (content === search) results.push({ r, c });
        } else if (content.includes(search)) {
          results.push({ r, c });
        }
      });
    });

    setSearchResult(results);
    if (results.length > 0) {
      const nextIndex = (currentSearchIndex + 1) % results.length;
      setCurrentSearchIndex(nextIndex);
      setFocusedCell(results[nextIndex]);
      setSelection(null);
    } else {
      setCurrentSearchIndex(-1);
      alert('No matches found.');
    }
  };

  const handleReplace = () => {
    if (currentSearchIndex === -1 || searchResult.length === 0) {
      handleFind();
      return;
    }

    const current = searchResult[currentSearchIndex];
    const newData = data.map((row, r) => {
      if (r === current.r) {
        const newRow = [...row];
        const oldVal = newRow[current.c];
        let flags = matchCase ? '' : 'i';
        let escapedFind = findText.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
        let pattern = wholeWord ? `^${escapedFind}$` : escapedFind;
        let regex = new RegExp(pattern, flags);
        newRow[current.c] = oldVal.replace(regex, replaceText);
        return newRow;
      }
      return row;
    });

    onChange(newData);
    handleFind();
  };

  const handleReplaceAll = () => {
    if (!findText) return;
    let count = 0;
    let flags = matchCase ? 'g' : 'gi';
    let escapedFind = findText.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
    let pattern = wholeWord ? `\\b${escapedFind}\\b` : escapedFind;
    let regex = new RegExp(pattern, flags);
    const newData = data.map(row => 
      row.map(cell => {
        const newVal = cell.replace(regex, replaceText);
        if (newVal !== cell) count++;
        return newVal;
      })
    );
    onChange(newData);
    alert(`Replaced ${count} occurrences.`);
    setSearchResult([]);
    setCurrentSearchIndex(-1);
  };

  const handleMouseDown = (r: number, c: number) => {
    setIsSelecting(true);
    setSelection({ start: { r, c }, end: { r, c } });
    setFocusedCell({ r, c });
  };

  const handleMouseEnter = (r: number, c: number) => {
    if (isSelecting && selection) {
      setSelection({ ...selection, end: { r, c } });
    }
  };

  const handleMouseUp = () => {
    setIsSelecting(false);
    // If start and end are same, treat as single cell focus
    if (selection && selection.start.r === selection.end.r && selection.start.c === selection.end.c) {
      setSelection(null);
    }
  };

  const isSelected = (r: number, c: number) => {
    if (!selection) return false;
    const rStart = Math.min(selection.start.r, selection.end.r);
    const rEnd = Math.max(selection.start.r, selection.end.r);
    const cStart = Math.min(selection.start.c, selection.end.c);
    const cEnd = Math.max(selection.start.c, selection.end.c);
    return r >= rStart && r <= rEnd && c >= cStart && c <= cEnd;
  };

  const currentCellStyle = focusedCell ? styles[`${focusedCell.r}-${focusedCell.c}`] || {} : {};
  const isSelectedRange = selection && (selection.start.r !== selection.end.r || selection.start.c !== selection.end.c);

  return (
    <div className="w-full space-y-4 relative" onMouseUp={handleMouseUp}>
      <div className="flex flex-wrap items-center justify-between gap-4">
        {/* Floating Toolbar */}
        <div 
          className={`flex items-center space-x-1 p-1 bg-white border border-gray-200 rounded-lg shadow-sm z-30 transition-all duration-200 ${focusedCell || selection ? 'opacity-100' : 'opacity-50 grayscale'}`}
          style={{ width: 'fit-content' }}
        >
          <button 
            onClick={() => updateStyle({ bold: !currentCellStyle.bold })}
            className={`p-1.5 rounded hover:bg-gray-100 transition-colors ${currentCellStyle.bold ? 'bg-green-100 text-green-700' : 'text-gray-600'}`}
            title="Bold"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 4h8a4 4 0 014 4 4 4 0 01-4 4H6z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 12h9a4 4 0 014 4 4 4 0 01-4 4H6z" /></svg>
          </button>
          <button 
            onClick={() => updateStyle({ italic: !currentCellStyle.italic })}
            className={`p-1.5 rounded hover:bg-gray-100 transition-colors ${currentCellStyle.italic ? 'bg-green-100 text-green-700' : 'text-gray-600'}`}
            title="Italic"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M10 20l4-16m-4 0h4m-4 16h4" /></svg>
          </button>
          <div className="w-px h-4 bg-gray-200 mx-1"></div>
          <button 
            onClick={() => updateStyle({ align: 'left' })}
            className={`p-1.5 rounded hover:bg-gray-100 transition-colors ${currentCellStyle.align === 'left' ? 'bg-green-100 text-green-700' : 'text-gray-600'}`}
            title="Align Left"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 12h10M4 18h16" /></svg>
          </button>
          <button 
            onClick={() => updateStyle({ align: 'center' })}
            className={`p-1.5 rounded hover:bg-gray-100 transition-colors ${currentCellStyle.align === 'center' ? 'bg-green-100 text-green-700' : 'text-gray-600'}`}
            title="Align Center"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M7 12h10M4 18h16" /></svg>
          </button>
          <button 
            onClick={() => updateStyle({ align: 'right' })}
            className={`p-1.5 rounded hover:bg-gray-100 transition-colors ${currentCellStyle.align === 'right' ? 'bg-green-100 text-green-700' : 'text-gray-600'}`}
            title="Align Right"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M10 12h10M4 18h16" /></svg>
          </button>
          <div className="w-px h-4 bg-gray-200 mx-1"></div>
          <button 
            onClick={handleMerge}
            disabled={!isSelectedRange}
            className={`p-1.5 rounded hover:bg-gray-100 transition-colors ${!isSelectedRange ? 'opacity-30 cursor-not-allowed' : 'text-gray-600'}`}
            title="Merge Cells"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 8V6a2 2 0 012-2h4M4 16v2a2 2 0 002 2h4M20 8V6a2 2 0 00-2-2h-4M20 16v2a2 2 0 01-2 2h-4M8 12h8" />
            </svg>
          </button>
          <button 
            onClick={handleUnmerge}
            disabled={!focusedCell || !(styles[`${focusedCell.r}-${focusedCell.c}`]?.rowSpan || styles[`${focusedCell.r}-${focusedCell.c}`]?.colSpan)}
            className={`p-1.5 rounded hover:bg-gray-100 transition-colors ${(!focusedCell || !(styles[`${focusedCell.r}-${focusedCell.c}`]?.rowSpan || styles[`${focusedCell.r}-${focusedCell.c}`]?.colSpan)) ? 'opacity-30 cursor-not-allowed' : 'text-gray-600'}`}
            title="Unmerge Cells"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 6v6m0 0v6m0-6h6m-6 0H6M4 4h16v16H4V4z" />
            </svg>
          </button>
        </div>

        <button 
          onClick={() => setShowFindReplace(!showFindReplace)}
          className={`inline-flex items-center px-3 py-1.5 border rounded-lg text-sm font-medium transition-colors ${showFindReplace ? 'bg-blue-600 text-white border-blue-600' : 'bg-white text-gray-700 border-gray-300 hover:bg-gray-50'}`}
        >
          <svg className="w-4 h-4 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
          Find & Replace
        </button>
      </div>

      {/* Find & Replace Panel */}
      {showFindReplace && (
        <div className="p-4 bg-gray-50 border border-gray-200 rounded-xl animate-in slide-in-from-top-2">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-4">
            <div className="space-y-1">
              <label className="text-xs font-bold text-gray-500 uppercase">Find</label>
              <input 
                type="text" 
                value={findText}
                onChange={(e) => setFindText(e.target.value)}
                placeholder="Search for text..."
                className="w-full px-3 py-2 bg-white border border-gray-300 rounded-lg text-sm outline-none focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500"
              />
            </div>
            <div className="space-y-1">
              <label className="text-xs font-bold text-gray-500 uppercase">Replace with</label>
              <input 
                type="text" 
                value={replaceText}
                onChange={(e) => setReplaceText(e.target.value)}
                placeholder="New text..."
                className="w-full px-3 py-2 bg-white border border-gray-300 rounded-lg text-sm outline-none focus:ring-2 focus:ring-green-500/20 focus:border-green-500"
              />
            </div>
          </div>
          <div className="flex flex-wrap items-center justify-between gap-4">
            <div className="flex items-center space-x-4">
              <label className="flex items-center space-x-2 text-sm text-gray-600 cursor-pointer">
                <input type="checkbox" checked={matchCase} onChange={(e) => setMatchCase(e.target.checked)} className="w-4 h-4 rounded border-gray-300 text-blue-600 focus:ring-blue-500" />
                <span>Match case</span>
              </label>
              <label className="flex items-center space-x-2 text-sm text-gray-600 cursor-pointer">
                <input type="checkbox" checked={wholeWord} onChange={(e) => setWholeWord(e.target.checked)} className="w-4 h-4 rounded border-gray-300 text-blue-600 focus:ring-blue-500" />
                <span>Whole word</span>
              </label>
            </div>
            <div className="flex items-center space-x-2">
              {searchResult.length > 0 && (
                <span className="text-xs text-gray-500 mr-2">
                  {currentSearchIndex + 1} of {searchResult.length}
                </span>
              )}
              <button 
                onClick={handleFind}
                className="px-4 py-2 bg-blue-600 text-white text-sm font-semibold rounded-lg hover:bg-blue-700 transition-colors shadow-sm"
              >
                Next Match
              </button>
              <button 
                onClick={handleReplace}
                className="px-4 py-2 bg-white border border-gray-300 text-gray-700 text-sm font-semibold rounded-lg hover:bg-gray-50 transition-colors shadow-sm"
              >
                Replace
              </button>
              <button 
                onClick={handleReplaceAll}
                className="px-4 py-2 bg-white border border-gray-300 text-gray-700 text-sm font-semibold rounded-lg hover:bg-gray-50 transition-colors shadow-sm"
              >
                Replace All
              </button>
            </div>
          </div>
        </div>
      )}

      <div className="flex items-center justify-between text-xs font-medium text-gray-500 px-1">
        <div className="flex items-center space-x-4">
          <div className="flex items-center">
            <div className="w-3 h-3 bg-red-100 border border-red-300 rounded mr-1.5"></div>
            <span>Invalid Format</span>
          </div>
          <div className="flex items-center">
            <div className="w-3 h-3 bg-blue-50 border border-blue-200 rounded mr-1.5"></div>
            <span>Selection</span>
          </div>
          <div className="flex items-center">
            <div className="w-3 h-3 bg-green-50 border border-green-200 rounded mr-1.5"></div>
            <span>Active Cell</span>
          </div>
        </div>
      </div>

      <div className="w-full overflow-auto border border-gray-200 rounded-xl shadow-sm bg-white max-h-[600px] scrollbar-thin scrollbar-thumb-gray-200">
        <table className="w-full text-sm text-left border-collapse table-fixed select-none">
          <thead className="sticky top-0 z-20 bg-gray-50 border-b border-gray-200">
            <tr>
              <th className="w-12 border-r border-gray-200 bg-gray-100 px-2 py-2.5 text-center text-[10px] font-bold text-gray-400 uppercase tracking-tighter">#</th>
              {Array.from({ length: colCount }).map((_, i) => (
                <th key={i} className="min-w-[150px] border-r border-gray-200 px-3 py-2.5 text-center text-xs font-bold text-gray-500 uppercase tracking-wider relative group">
                  {getColLabel(i)}
                  {columnTypes[i] && (
                    <span className="absolute bottom-0 left-0 w-full h-0.5 bg-blue-400 opacity-50" title="Numeric column"></span>
                  )}
                </th>
              ))}
            </tr>
          </thead>
          <tbody className="divide-y divide-gray-200">
            {data.map((row, rowIndex) => (
              <tr key={rowIndex} className="group hover:bg-gray-50/50 transition-colors">
                <td className="w-12 border-r border-gray-200 bg-gray-50/50 px-2 py-2 text-center text-xs font-medium text-gray-400">
                  {rowIndex + 1}
                </td>
                {Array.from({ length: colCount }).map((_, colIndex) => {
                  const key = `${rowIndex}-${colIndex}`;
                  if (hiddenCells.has(key)) return null;

                  const val = row[colIndex] || '';
                  const invalid = isInvalid(rowIndex, colIndex, val);
                  const isFocused = focusedCell?.r === rowIndex && focusedCell?.c === colIndex;
                  const selected = isSelected(rowIndex, colIndex);
                  const cellStyle = styles[key] || {};

                  return (
                    <td 
                      key={colIndex} 
                      rowSpan={cellStyle.rowSpan || 1}
                      colSpan={cellStyle.colSpan || 1}
                      onMouseDown={() => handleMouseDown(rowIndex, colIndex)}
                      onMouseEnter={() => handleMouseEnter(rowIndex, colIndex)}
                      className={`relative border-r border-gray-100 p-0 transition-all duration-200 ${
                        invalid ? 'bg-red-50' : isFocused ? 'bg-green-50/40' : selected ? 'bg-blue-50/50' : 'bg-transparent'
                      } ${selected ? 'ring-1 ring-inset ring-blue-300 z-10' : ''}`}
                    >
                      <input
                        type="text"
                        value={val}
                        onFocus={() => {
                          setFocusedCell({ r: rowIndex, c: colIndex });
                          if (!isSelecting) setSelection(null);
                        }}
                        onChange={(e) => handleCellEdit(rowIndex, colIndex, e.target.value)}
                        style={{
                          fontWeight: cellStyle.bold ? 'bold' : 'normal',
                          fontStyle: cellStyle.italic ? 'italic' : 'normal',
                          textAlign: cellStyle.align || 'left'
                        }}
                        className={`w-full px-3 py-2 bg-transparent outline-none transition-all ${
                          invalid 
                            ? 'text-red-700 font-medium' 
                            : 'text-gray-700'
                        } ${isFocused ? 'ring-2 ring-green-400/50 z-20' : ''}`}
                      />
                      {invalid && (
                        <div className="absolute right-1 top-1 w-1.5 h-1.5 rounded-full bg-red-400 animate-pulse" title="Numeric expected"></div>
                      )}
                    </td>
                  );
                })}
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export type TableData = string[][];

export interface CellStyle {
  bold?: boolean;
  italic?: boolean;
  align?: 'left' | 'center' | 'right';
  rowSpan?: number;
  colSpan?: number;
  backgroundColor?: string;
}

export type TableStyles = Record<string, CellStyle>; // key is "rowIndex-colIndex"

export interface ConversionState {
  isProcessing: boolean;
  error: string | null;
  data: TableData | null;
  fileName: string | null;
}

import React, { useMemo, useState, useRef, useEffect, useCallback } from 'react';
import { TableData, CellStyle, TableStyles } from '../types';

interface WorksheetProps {
  data: TableData;
  onChange: (newData: TableData) => void;
}

interface Selection {
  start: { r: number; c: number };
  end: { r: number; c: number };
}

export const Worksheet: React.FC<WorksheetProps> = ({ data, onChange }) => {
  const [styles, setStyles] = useState<TableStyles>({});
  const [focusedCell, setFocusedCell] = useState<{ r: number; c: number } | null>(null);
  const [selection, setSelection] = useState<Selection | null>(null);
  const [isSelecting, setIsSelecting] = useState(false);

  const [showFindReplace, setShowFindReplace] = useState(false);
  const [findText, setFindText] = useState('');
  const [replaceText, setReplaceText] = useState('');
  const [matchCase, setMatchCase] = useState(false);
  const [wholeWord, setWholeWord] = useState(false);
  const [searchResult, setSearchResult] = useState<{ r: number, c: number }[]>([]);
  const [currentSearchIndex, setCurrentSearchIndex] = useState(-1);

  const colorInputRef = useRef<HTMLInputElement>(null);

  if (!data || data.length === 0) return null;

  const colCount = useMemo(() => Math.max(...data.map(row => row.length)), [data]);

  const columnTypes = useMemo(() => {
    const types: boolean[] = [];
    for (let c = 0; c < colCount; c++) {
      let numericCount = 0;
      let totalCount = 0;
      for (let r = 1; r < data.length; r++) {
        const val = data[r][c]?.trim();
        if (val) {
          totalCount++;
          const cleanVal = val.replace(/[$,€,£,%]/g, '');
          if (!isNaN(Number(cleanVal)) && cleanVal !== '') {
            numericCount++;
          }
        }
      }
      types[c] = totalCount > 0 && (numericCount / totalCount) > 0.6;
    }
    return types;
  }, [data, colCount]);

  // Pre-calculate hidden cells for performance
  const hiddenCells = useMemo(() => {
    const hidden = new Set<string>();
    (Object.entries(styles) as [string, CellStyle][]).forEach(([key, style]) => {
      if ((style.rowSpan && style.rowSpan > 1) || (style.colSpan && style.colSpan > 1)) {
        const [r, c] = key.split('-').map(Number);
        const rowSpan = style.rowSpan || 1;
        const colSpan = style.colSpan || 1;
        for (let dr = 0; dr < rowSpan; dr++) {
          for (let dc = 0; dc < colSpan; dc++) {
            if (dr === 0 && dc === 0) continue;
            hidden.add(`${r + dr}-${c + dc}`);
          }
        }
      }
    });
    return hidden;
  }, [styles]);

  const handleCellEdit = (rowIndex: number, colIndex: number, value: string) => {
    const newData = data.map((row, r) => {
      if (r === rowIndex) {
        const newRow = [...row];
        while (newRow.length < colCount) newRow.push('');
        newRow[colIndex] = value;
        return newRow;
      }
      return row;
    });
    onChange(newData);
  };

  const updateStyle = (stylePatch: Partial<CellStyle>) => {
    if (!focusedCell && !selection) return;

    setStyles(prev => {
      const next = { ...prev };

      // If we have a range selection, apply to all visible cells in range
      if (selection) {
        const rStart = Math.min(selection.start.r, selection.end.r);
        const rEnd = Math.max(selection.start.r, selection.end.r);
        const cStart = Math.min(selection.start.c, selection.end.c);
        const cEnd = Math.max(selection.start.c, selection.end.c);

        for (let r = rStart; r <= rEnd; r++) {
          for (let c = cStart; c <= cEnd; c++) {
            const key = `${r}-${c}`;
            if (!hiddenCells.has(key)) {
              next[key] = { ...next[key], ...stylePatch };
            }
          }
        }
      } else if (focusedCell) {
        const key = `${focusedCell.r}-${focusedCell.c}`;
        next[key] = { ...next[key], ...stylePatch };
      }

      return next;
    });
  };

  const handleMerge = () => {
    if (!selection) return;
    const rStart = Math.min(selection.start.r, selection.end.r);
    const rEnd = Math.max(selection.start.r, selection.end.r);
    const cStart = Math.min(selection.start.c, selection.end.c);
    const cEnd = Math.max(selection.start.c, selection.end.c);

    if (rStart === rEnd && cStart === cEnd) return;

    const rowSpan = rEnd - rStart + 1;
    const colSpan = cEnd - cStart + 1;

    setStyles(prev => {
      const next = { ...prev };
      // Remove styles of cells that will be hidden
      for (let r = rStart; r <= rEnd; r++) {
        for (let c = cStart; c <= cEnd; c++) {
          if (r === rStart && c === cStart) continue;
          delete next[`${r}-${c}`];
        }
      }
      // Apply merge to top-left cell
      next[`${rStart}-${cStart}`] = { 
        ...next[`${rStart}-${cStart}`], 
        rowSpan, 
        colSpan 
      };
      return next;
    });
    setSelection(null);
    setFocusedCell({ r: rStart, c: cStart });
  };

  const handleUnmerge = () => {
    if (!focusedCell) return;
    const key = `${focusedCell.r}-${focusedCell.c}`;
    if (styles[key]?.rowSpan || styles[key]?.colSpan) {
      setStyles(prev => {
        const next = { ...prev };
        const { rowSpan, colSpan, ...rest } = next[key];
        next[key] = rest;
        return next;
      });
    }
  };

  const isInvalid = (rowIndex: number, colIndex: number, value: string) => {
    if (rowIndex === 0) return false;
    if (!columnTypes[colIndex]) return false;
    if (!value.trim()) return false;
    const cleanVal = value.replace(/[$,€,£,%]/g, '').trim();
    return isNaN(Number(cleanVal));
  };

  const getColLabel = (index: number) => {
    let label = '';
    let i = index;
    while (i >= 0) {
      label = String.fromCharCode((i % 26) + 65) + label;
      i = Math.floor(i / 26) - 1;
    }
    return label;
  };

  const handleFind = () => {
    if (!findText) {
      setSearchResult([]);
      setCurrentSearchIndex(-1);
      return;
    }

    const results: { r: number, c: number }[] = [];
    data.forEach((row, r) => {
      row.forEach((cell, c) => {
        let content = cell || '';
        let search = findText;

        if (!matchCase) {
          content = content.toLowerCase();
          search = search.toLowerCase();
        }

        if (wholeWord) {
          if (content === search) results.push({ r, c });
        } else if (content.includes(search)) {
          results.push({ r, c });
        }
      });
    });

    setSearchResult(results);
    if (results.length > 0) {
      const nextIndex = (currentSearchIndex + 1) % results.length;
      setCurrentSearchIndex(nextIndex);
      setFocusedCell(results[nextIndex]);
      setSelection(null);
    } else {
      setCurrentSearchIndex(-1);
      alert('No matches found.');
    }
  };

  const handleReplace = () => {
    if (currentSearchIndex === -1 || searchResult.length === 0) {
      handleFind();
      return;
    }

    const current = searchResult[currentSearchIndex];
    const newData = data.map((row, r) => {
      if (r === current.r) {
        const newRow = [...row];
        const oldVal = newRow[current.c];
        let flags = matchCase ? '' : 'i';
        let escapedFind = findText.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
        let pattern = wholeWord ? `^${escapedFind}$` : escapedFind;
        let regex = new RegExp(pattern, flags);
        newRow[current.c] = oldVal.replace(regex, replaceText);
        return newRow;
      }
      return row;
    });

    onChange(newData);
    handleFind();
  };

  const handleReplaceAll = () => {
    if (!findText) return;
    let count = 0;
    let flags = matchCase ? 'g' : 'gi';
    let escapedFind = findText.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
    let pattern = wholeWord ? `\\b${escapedFind}\\b` : escapedFind;
    let regex = new RegExp(pattern, flags);
    const newData = data.map(row => 
      row.map(cell => {
        const newVal = cell.replace(regex, replaceText);
        if (newVal !== cell) count++;
        return newVal;
      })
    );
    onChange(newData);
    alert(`Replaced ${count} occurrences.`);
    setSearchResult([]);
    setCurrentSearchIndex(-1);
  };

  const handleMouseDown = (r: number, c: number) => {
    setIsSelecting(true);
    setSelection({ start: { r, c }, end: { r, c } });
    setFocusedCell({ r, c });
  };

  const handleMouseEnter = (r: number, c: number) => {
    if (isSelecting && selection) {
      setSelection({ ...selection, end: { r, c } });
    }
  };

  const handleMouseUp = () => {
    setIsSelecting(false);
    // If start and end are same, treat as single cell focus
    if (selection && selection.start.r === selection.end.r && selection.start.c === selection.end.c) {
      setSelection(null);
    }
  };

  const isSelected = (r: number, c: number) => {
    if (!selection) return false;
    const rStart = Math.min(selection.start.r, selection.end.r);
    const rEnd = Math.max(selection.start.r, selection.end.r);
    const cStart = Math.min(selection.start.c, selection.end.c);
    const cEnd = Math.max(selection.start.c, selection.end.c);
    return r >= rStart && r <= rEnd && c >= cStart && c <= cEnd;
  };

  const currentCellStyle = focusedCell ? styles[`${focusedCell.r}-${focusedCell.c}`] || {} : {};
  const isSelectedRange = selection && (selection.start.r !== selection.end.r || selection.start.c !== selection.end.c);

  const handleColorChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    updateStyle({ backgroundColor: e.target.value });
  };

  const clearColor = () => {
    updateStyle({ backgroundColor: undefined });
  };

  return (
    <div className="w-full space-y-4 relative" onMouseUp={handleMouseUp}>
      <div className="flex flex-wrap items-center justify-between gap-4">
        {/* Floating Toolbar */}
        <div 
          className={`flex items-center space-x-1 p-1 bg-white border border-gray-200 rounded-lg shadow-sm z-30 transition-all duration-200 ${focusedCell || selection ? 'opacity-100' : 'opacity-50 grayscale'}`}
          style={{ width: 'fit-content' }}
        >
          <button 
            onClick={() => updateStyle({ bold: !currentCellStyle.bold })}
            className={`p-1.5 rounded hover:bg-gray-100 transition-colors ${currentCellStyle.bold ? 'bg-green-100 text-green-700' : 'text-gray-600'}`}
            title="Bold"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 4h8a4 4 0 014 4 4 4 0 01-4 4H6z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 12h9a4 4 0 014 4 4 4 0 01-4 4H6z" /></svg>
          </button>
          <button 
            onClick={() => updateStyle({ italic: !currentCellStyle.italic })}
            className={`p-1.5 rounded hover:bg-gray-100 transition-colors ${currentCellStyle.italic ? 'bg-green-100 text-green-700' : 'text-gray-600'}`}
            title="Italic"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M10 20l4-16m-4 0h4m-4 16h4" /></svg>
          </button>
          <div className="w-px h-4 bg-gray-200 mx-1"></div>
          <button 
            onClick={() => updateStyle({ align: 'left' })}
            className={`p-1.5 rounded hover:bg-gray-100 transition-colors ${currentCellStyle.align === 'left' ? 'bg-green-100 text-green-700' : 'text-gray-600'}`}
            title="Align Left"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 12h10M4 18h16" /></svg>
          </button>
          <button 
            onClick={() => updateStyle({ align: 'center' })}
            className={`p-1.5 rounded hover:bg-gray-100 transition-colors ${currentCellStyle.align === 'center' ? 'bg-green-100 text-green-700' : 'text-gray-600'}`}
            title="Align Center"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M7 12h10M4 18h16" /></svg>
          </button>
          <button 
            onClick={() => updateStyle({ align: 'right' })}
            className={`p-1.5 rounded hover:bg-gray-100 transition-colors ${currentCellStyle.align === 'right' ? 'bg-green-100 text-green-700' : 'text-gray-600'}`}
            title="Align Right"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M10 12h10M4 18h16" /></svg>
          </button>
          <div className="w-px h-4 bg-gray-200 mx-1"></div>

          {/* Background Color Picker */}
          <div className="relative group/color flex items-center">
            <input 
              type="color" 
              ref={colorInputRef}
              onChange={handleColorChange}
              value={currentCellStyle.backgroundColor || '#ffffff'}
              className="absolute inset-0 opacity-0 cursor-pointer w-full h-full"
              title="Cell Background Color"
            />
            <button 
              className={`p-1.5 rounded hover:bg-gray-100 transition-colors ${currentCellStyle.backgroundColor ? 'text-green-600' : 'text-gray-600'}`}
            >
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M7 21a4 4 0 01-4-4V5a2 2 0 012-2h4a2 2 0 012 2v12a4 4 0 01-4 4zm0 0h12a2 2 0 002-2v-4a2 2 0 00-2-2h-2.343M11 7.343l1.657-1.657a2 2 0 012.828 0l2.829 2.829a2 2 0 010 2.828l-8.486 8.485M7 17h.01" />
              </svg>
            </button>
            {currentCellStyle.backgroundColor && (
              <button 
                onClick={(e) => { e.stopPropagation(); clearColor(); }}
                className="absolute -top-1 -right-1 bg-red-500 text-white rounded-full w-3 h-3 flex items-center justify-center text-[8px] hover:bg-red-600"
                title="Clear Color"
              >
                ×
              </button>
            )}
          </div>

          <div className="w-px h-4 bg-gray-200 mx-1"></div>
          <button 
            onClick={handleMerge}
            disabled={!isSelectedRange}
            className={`p-1.5 rounded hover:bg-gray-100 transition-colors ${!isSelectedRange ? 'opacity-30 cursor-not-allowed' : 'text-gray-600'}`}
            title="Merge Cells"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 8V6a2 2 0 012-2h4M4 16v2a2 2 0 002 2h4M20 8V6a2 2 0 00-2-2h-4M20 16v2a2 2 0 01-2 2h-4M8 12h8" />
            </svg>
          </button>
          <button 
            onClick={handleUnmerge}
            disabled={!focusedCell || !(styles[`${focusedCell.r}-${focusedCell.c}`]?.rowSpan || styles[`${focusedCell.r}-${focusedCell.c}`]?.colSpan)}
            className={`p-1.5 rounded hover:bg-gray-100 transition-colors ${(!focusedCell || !(styles[`${focusedCell.r}-${focusedCell.c}`]?.rowSpan || styles[`${focusedCell.r}-${focusedCell.c}`]?.colSpan)) ? 'opacity-30 cursor-not-allowed' : 'text-gray-600'}`}
            title="Unmerge Cells"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 6v6m0 0v6m0-6h6m-6 0H6M4 4h16v16H4V4z" />
            </svg>
          </button>
        </div>

        <button 
          onClick={() => setShowFindReplace(!showFindReplace)}
          className={`inline-flex items-center px-3 py-1.5 border rounded-lg text-sm font-medium transition-colors ${showFindReplace ? 'bg-blue-600 text-white border-blue-600' : 'bg-white text-gray-700 border-gray-300 hover:bg-gray-50'}`}
        >
          <svg className="w-4 h-4 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
          Find & Replace
        </button>
      </div>

      {/* Find & Replace Panel */}
      {showFindReplace && (
        <div className="p-4 bg-gray-50 border border-gray-200 rounded-xl animate-in slide-in-from-top-2">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-4">
            <div className="space-y-1">
              <label className="text-xs font-bold text-gray-500 uppercase">Find</label>
              <input 
                type="text" 
                value={findText}
                onChange={(e) => setFindText(e.target.value)}
                placeholder="Search for text..."
                className="w-full px-3 py-2 bg-white border border-gray-300 rounded-lg text-sm outline-none focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500"
              />
            </div>
            <div className="space-y-1">
              <label className="text-xs font-bold text-gray-500 uppercase">Replace with</label>
              <input 
                type="text" 
                value={replaceText}
                onChange={(e) => setReplaceText(e.target.value)}
                placeholder="New text..."
                className="w-full px-3 py-2 bg-white border border-gray-300 rounded-lg text-sm outline-none focus:ring-2 focus:ring-green-500/20 focus:border-green-500"
              />
            </div>
          </div>
          <div className="flex flex-wrap items-center justify-between gap-4">
            <div className="flex items-center space-x-4">
              <label className="flex items-center space-x-2 text-sm text-gray-600 cursor-pointer">
                <input type="checkbox" checked={matchCase} onChange={(e) => setMatchCase(e.target.checked)} className="w-4 h-4 rounded border-gray-300 text-blue-600 focus:ring-blue-500" />
                <span>Match case</span>
              </label>
              <label className="flex items-center space-x-2 text-sm text-gray-600 cursor-pointer">
