          <thead className="sticky top-0 z-20 bg-gray-50 border-b border-gray-200">
            <tr>
              <th className="w-12 border-r border-gray-200 bg-gray-100 px-2 py-2.5 text-center text-[10px] font-bold text-gray-400 uppercase tracking-tighter">#</th>
              {Array.from({ length: colCount }).map((_, i) => (
                <th key={i} className="min-w-[150px] border-r border-gray-200 px-3 py-2.5 text-center text-xs font-bold text-gray-500 uppercase tracking-wider relative group">
                  {getColLabel(i)}
                  {columnTypes[i] && (
                    <span className="absolute bottom-0 left-0 w-full h-0.5 bg-blue-400 opacity-50" title="Numeric column"></span>
                  )}
                </th>
              ))}
            </tr>
          </thead>
          <tbody className="divide-y divide-gray-200">
            {data.map((row, rowIndex) => (
              <tr key={rowIndex} className="group hover:bg-gray-50/50 transition-colors">
                <td className="w-12 border-r border-gray-200 bg-gray-50/50 px-2 py-2 text-center text-xs font-medium text-gray-400">
                  {rowIndex + 1}
                </td>
                {Array.from({ length: colCount }).map((_, colIndex) => {
                  const key = `${rowIndex}-${colIndex}`;
                  if (hiddenCells.has(key)) return null;

                  const val = row[colIndex] || '';
                  const invalid = isInvalid(rowIndex, colIndex, val);
                  const isFocused = focusedCell?.r === rowIndex && focusedCell?.c === colIndex;
                  const selected = isSelected(rowIndex, colIndex);
                  const cellStyle = styles[key] || {};

                  return (
                    <td 
                      key={colIndex} 
                      rowSpan={cellStyle.rowSpan || 1}
                      colSpan={cellStyle.colSpan || 1}
                      onMouseDown={() => handleMouseDown(rowIndex, colIndex)}
                      onMouseEnter={() => handleMouseEnter(rowIndex, colIndex)}
                      style={{ 
                        backgroundColor: cellStyle.backgroundColor || (invalid ? 'rgb(254 242 242)' : isFocused ? 'rgb(240 253 244 / 0.4)' : selected ? 'rgb(239 246 255 / 0.5)' : 'transparent') 
                      }}
                      className={`relative border-r border-gray-100 p-0 transition-all duration-200 ${selected ? 'ring-1 ring-inset ring-blue-300 z-10' : ''}`}
                    >
                      <input
                        type="text"
                        value={val}
                        onFocus={() => {
                          setFocusedCell({ r: rowIndex, c: colIndex });
                          if (!isSelecting) setSelection(null);
                        }}
                        onChange={(e) => handleCellEdit(rowIndex, colIndex, e.target.value)}
                        style={{
                          fontWeight: cellStyle.bold ? 'bold' : 'normal',
                          fontStyle: cellStyle.italic ? 'italic' : 'normal',
                          textAlign: cellStyle.align || 'left',
                          backgroundColor: 'transparent'
                        }}
                        className={`w-full px-3 py-2 outline-none transition-all ${
                          invalid 
                            ? 'text-red-700 font-medium' 
                            : 'text-gray-700'
                        } ${isFocused ? 'ring-2 ring-green-400/50 z-20' : ''}`}
                      />
                      {invalid && (
                        <div className="absolute right-1 top-1 w-1.5 h-1.5 rounded-full bg-red-400 animate-pulse" title="Numeric expected"></div>
                      )}
                    </td>
                  );
                })}
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export type TableData = string[][];

export interface CellStyle {
  bold?: boolean;
  italic?: boolean;
  align?: 'left' | 'center' | 'right';
  rowSpan?: number;
  colSpan?: number;
  backgroundColor?: string;
}

export type TableStyles = Record<string, CellStyle>; // key is "rowIndex-colIndex"

export interface ConversionState {
  isProcessing: boolean;
  error: string | null;
  data: TableData | null;
  fileName: string | null;
  styles?: TableStyles;
}

import * as XLSX from 'xlsx';
import { TableData, TableStyles, CellStyle } from '../types';

export const downloadAsExcel = (data: TableData, fileName: string = 'Snap2Sheet_Export') => {
  const ws = XLSX.utils.aoa_to_sheet(data);
  const wb = XLSX.utils.book_new();
  XLSX.utils.book_append_sheet(wb, ws, "Sheet1");
  XLSX.writeFile(wb, `${fileName}.xlsx`);
};

export const downloadAsCSV = (data: TableData, fileName: string = 'Snap2Sheet_Export') => {
  const csvContent = data.map(row => 
    row.map(cell => {
      const escaped = cell.replace(/"/g, '""');
      return `"${escaped}"`;
    }).join(',')
  ).join('\n');

  const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
  const url = URL.createObjectURL(blob);
  const link = document.createElement('a');
  link.setAttribute('href', url);
  link.setAttribute('download', `${fileName}.csv`);
  link.style.visibility = 'hidden';
  document.body.appendChild(link);
  link.click();
  document.body.removeChild(link);
};

export const copyToClipboard = async (data: TableData) => {
  const csvContent = data.map(row => row.join('\t')).join('\n');
  try {
    await navigator.clipboard.writeText(csvContent);
    return true;
  } catch (err) {
    console.error('Failed to copy: ', err);
    return false;
  }
};

/**
 * Copies the table data and styles to clipboard as HTML.
 * Excel and Google Sheets can parse this to preserve formatting.
 */
export const copyTableToClipboard = async (data: TableData, styles: TableStyles = {}) => {
  const colCount = Math.max(...data.map(row => row.length));

  // Track hidden cells due to spans
  const hidden = new Set<string>();
  Object.entries(styles).forEach(([key, style]) => {
    if (style.rowSpan || style.colSpan) {
      const [r, c] = key.split('-').map(Number);
      const rs = style.rowSpan || 1;
      const cs = style.colSpan || 1;
      for (let dr = 0; dr < rs; dr++) {
        for (let dc = 0; dc < cs; dc++) {
          if (dr === 0 && dc === 0) continue;
          hidden.add(`${r + dr}-${c + dc}`);
        }
      }
    }
  });

  let html = '<table border="1" style="border-collapse: collapse; font-family: sans-serif;">';

  data.forEach((row, r) => {
    html += '<tr>';
    for (let c = 0; c < colCount; c++) {
      const key = `${r}-${c}`;
      if (hidden.has(key)) continue;

      const style = styles[key] || {};
      const value = row[c] || '';

      let css = '';
      if (style.bold) css += 'font-weight: bold; ';
      if (style.italic) css += 'font-style: italic; ';
      if (style.align) css += `text-align: ${style.align}; `;
      if (style.backgroundColor) css += `background-color: ${style.backgroundColor}; `;

      const rs = style.rowSpan ? ` rowspan="${style.rowSpan}"` : '';
      const cs = style.colSpan ? ` colspan="${style.colSpan}"` : '';

      html += `<td${rs}${cs} style="${css}">${value}</td>`;
    }
    html += '</tr>';
  });
  html += '</table>';

  const plainText = data.map(row => row.join('\t')).join('\n');

  try {
    const blobHtml = new Blob([html], { type: 'text/html' });
    const blobText = new Blob([plainText], { type: 'text/plain' });
    const dataObj = [new ClipboardItem({
      'text/html': blobHtml,
      'text/plain': blobText
    })];

    await navigator.clipboard.write(dataObj);
    return true;
  } catch (err) {
    console.error('Rich copy failed', err);
    return false;
  }
};

export const shareData = async (data: TableData) => {
  const csvContent = data.map(row => row.join(',')).join('\n');
  const blob = new Blob([csvContent], { type: 'text/csv' });
  const file = new File([blob], 'Snap2Sheet_Export.csv', { type: 'text/csv' });

  if (navigator.canShare && navigator.canShare({ files: [file] })) {
    try {
      await navigator.share({
        files: [file],
        title: 'Snap2Sheet Data Export',
        text: 'Here is the data converted from my image.',
      });
    } catch (err) {
      console.error('Share failed', err);
    }
  } else {
    alert('Sharing not supported on this browser.');
  }
};

