    isProcessing: false,
    error: null,
    data: null,
    fileName: null,
    styles: {}
  });
  const [isSaved, setIsSaved] = useState(false);

  // Load from localStorage on mount
  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        if (parsed.data && parsed.fileName) {
          setState(prev => ({ 
            ...prev, 
            data: parsed.data, 
            fileName: parsed.fileName,
            styles: parsed.styles || {}
          }));
        }
      } catch (e) {
        console.error("Failed to load autosave data", e);
      }
    }
  }, []);

  // Save to localStorage whenever data, fileName, or styles changes
  useEffect(() => {
    if (state.data && state.fileName) {
      localStorage.setItem(STORAGE_KEY, JSON.stringify({
        data: state.data,
        fileName: state.fileName,
        styles: state.styles
      }));
      setIsSaved(true);
      const timer = setTimeout(() => setIsSaved(false), 2000);
      return () => clearTimeout(timer);
    }
  }, [state.data, state.fileName, state.styles]);

  const handleImageSelected = async (base64: string, fileName: string) => {
    setState({ ...state, isProcessing: true, error: null, data: null, styles: {} });

    try {
      const extractedData = await convertImageToData(base64);
      setState({
        isProcessing: false,
        error: null,
        data: extractedData,
        fileName: fileName.split('.')[0],
        styles: {}
      });
    } catch (err: any) {
      setState({
        ...state,
        isProcessing: false,
