interface WorksheetProps {
  data: TableData;
  styles: TableStyles;
  onChange: (newData: TableData) => void;
  onStylesChange: (newStyles: TableStyles) => void;
}

interface Selection {
  start: { r: number; c: number };
  end: { r: number; c: number };
}

export const Worksheet: React.FC<WorksheetProps> = ({ data, styles, onChange, onStylesChange }) => {
  const [focusedCell, setFocusedCell] = useState<{ r: number; c: number } | null>(null);
  const [selection, setSelection] = useState<Selection | null>(null);
  const [isSelecting, setIsSelecting] = useState(false);

  const [showFindReplace, setShowFindReplace] = useState(false);
  const [findText, setFindText] = useState('');
  const [replaceText, setReplaceText] = useState('');
  const [matchCase, setMatchCase] = useState(false);
  const [wholeWord, setWholeWord] = useState(false);
  const [searchResult, setSearchResult] = useState<{ r: number, c: number }[]>([]);
  const [currentSearchIndex, setCurrentSearchIndex] = useState(-1);

  const colorInputRef = useRef<HTMLInputElement>(null);

  if (!data || data.length === 0) return null;

  const colCount = useMemo(() => Math.max(...data.map(row => row.length)), [data]);

  const columnTypes = useMemo(() => {
    const types: boolean[] = [];
    for (let c = 0; c < colCount; c++) {
      let numericCount = 0;
      let totalCount = 0;
      for (let r = 1; r < data.length; r++) {
        const val = data[r][c]?.trim();
        if (val) {
          totalCount++;
          const cleanVal = val.replace(/[$,€,£,%]/g, '');
          if (!isNaN(Number(cleanVal)) && cleanVal !== '') {
            numericCount++;
          }
        }
      }
      types[c] = totalCount > 0 && (numericCount / totalCount) > 0.6;
    }
    return types;
  }, [data, colCount]);

  // Pre-calculate hidden cells for performance
  const hiddenCells = useMemo(() => {
    const hidden = new Set<string>();
    (Object.entries(styles) as [string, CellStyle][]).forEach(([key, style]) => {
      if ((style.rowSpan && style.rowSpan > 1) || (style.colSpan && style.colSpan > 1)) {
        const [r, c] = key.split('-').map(Number);
        const rowSpan = style.rowSpan || 1;
        const colSpan = style.colSpan || 1;
        for (let dr = 0; dr < rowSpan; dr++) {
          for (let dc = 0; dc < colSpan; dc++) {
            if (dr === 0 && dc === 0) continue;
            hidden.add(`${r + dr}-${c + dc}`);
          }
        }
      }
    });
    return hidden;
  }, [styles]);

  const handleCellEdit = (rowIndex: number, colIndex: number, value: string) => {
    const newData = data.map((row, r) => {
      if (r === rowIndex) {
        const newRow = [...row];
        while (newRow.length < colCount) newRow.push('');
        newRow[colIndex] = value;
        return newRow;
      }
      return row;
    });
    onChange(newData);
  };

  const updateStyle = (stylePatch: Partial<CellStyle>) => {
    if (!focusedCell && !selection) return;

    const next = { ...styles };

    // If we have a range selection, apply to all visible cells in range
    if (selection) {
      const rStart = Math.min(selection.start.r, selection.end.r);
      const rEnd = Math.max(selection.start.r, selection.end.r);
      const cStart = Math.min(selection.start.c, selection.end.c);
      const cEnd = Math.max(selection.start.c, selection.end.c);

      for (let r = rStart; r <= rEnd; r++) {
        for (let c = cStart; c <= cEnd; c++) {
          const key = `${r}-${c}`;
          if (!hiddenCells.has(key)) {
            next[key] = { ...next[key], ...stylePatch };
          }
        }
      }
    } else if (focusedCell) {
      const key = `${focusedCell.r}-${focusedCell.c}`;
      next[key] = { ...next[key], ...stylePatch };
    }

    onStylesChange(next);
  };

  const handleMerge = () => {
    if (!selection) return;
    const rStart = Math.min(selection.start.r, selection.end.r);
    const rEnd = Math.max(selection.start.r, selection.end.r);
    const cStart = Math.min(selection.start.c, selection.end.c);
    const cEnd = Math.max(selection.start.c, selection.end.c);

    if (rStart === rEnd && cStart === cEnd) return;

    const rowSpan = rEnd - rStart + 1;
    const colSpan = cEnd - cStart + 1;

    const next = { ...styles };
    // Remove styles of cells that will be hidden
    for (let r = rStart; r <= rEnd; r++) {
      for (let c = cStart; c <= cEnd; c++) {
        if (r === rStart && c === cStart) continue;
        delete next[`${r}-${c}`];
      }
    }
    // Apply merge to top-left cell
    next[`${rStart}-${cStart}`] = { 
      ...next[`${rStart}-${cStart}`], 
      rowSpan, 
      colSpan 
    };
    onStylesChange(next);
    setSelection(null);
    setFocusedCell({ r: rStart, c: cStart });
  };

  const handleUnmerge = () => {
    if (!focusedCell) return;
    const key = `${focusedCell.r}-${focusedCell.c}`;
    if (styles[key]?.rowSpan || styles[key]?.colSpan) {
      const next = { ...styles };
      const { rowSpan, colSpan, ...rest } = next[key];
      next[key] = rest;
      onStylesChange(next);
    }
  };

  const isInvalid = (rowIndex: number, colIndex: number, value: string) => {
    if (rowIndex === 0) return false;
    if (!columnTypes[colIndex]) return false;
    if (!value.trim()) return false;
    const cleanVal = value.replace(/[$,€,£,%]/g, '').trim();
    return isNaN(Number(cleanVal));
  };

  const getColLabel = (index: number) => {
    let label = '';
    let i = index;
    while (i >= 0) {
      label = String.fromCharCode((i % 26) + 65) + label;
      i = Math.floor(i / 26) - 1;
    }
    return label;
  };

  const handleFind = () => {
    if (!findText) {
      setSearchResult([]);
      setCurrentSearchIndex(-1);
      return;
    }

    const results: { r: number, c: number }[] = [];
    data.forEach((row, r) => {
      row.forEach((cell, c) => {
        let content = cell || '';
        let search = findText;

        if (!matchCase) {
          content = content.toLowerCase();
          search = search.toLowerCase();
        }

        if (wholeWord) {
          if (content === search) results.push({ r, c });
        } else if (content.includes(search)) {
          results.push({ r, c });
        }
      });
    });

    setSearchResult(results);
    if (results.length > 0) {
      const nextIndex = (currentSearchIndex + 1) % results.length;
      setCurrentSearchIndex(nextIndex);
      setFocusedCell(results[nextIndex]);
      setSelection(null);
    } else {
      setCurrentSearchIndex(-1);
      alert('No matches found.');
    }
  };

  const handleReplace = () => {
    if (currentSearchIndex === -1 || searchResult.length === 0) {
      handleFind();
      return;
    }

    const current = searchResult[currentSearchIndex];
    const newData = data.map((row, r) => {
      if (r === current.r) {
        const newRow = [...row];
        const oldVal = newRow[current.c];
        let flags = matchCase ? '' : 'i';
        let escapedFind = findText.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
        let pattern = wholeWord ? `^${escapedFind}$` : escapedFind;
        let regex = new RegExp(pattern, flags);
        newRow[current.c] = oldVal.replace(regex, replaceText);
        return newRow;
      }
      return row;
    });

    onChange(newData);
    handleFind();
  };

  const handleReplaceAll = () => {
    if (!findText) return;
    let count = 0;
    let flags = matchCase ? 'g' : 'gi';
    let escapedFind = findText.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
    let pattern = wholeWord ? `\\b${escapedFind}\\b` : escapedFind;
    let regex = new RegExp(pattern, flags);
    const newData = data.map(row => 
      row.map(cell => {
        const newVal = cell.replace(regex, replaceText);
        if (newVal !== cell) count++;
        return newVal;
      })
    );
    onChange(newData);
    alert(`Replaced ${count} occurrences.`);
    setSearchResult([]);
    setCurrentSearchIndex(-1);
  };

  const handleMouseDown = (r: number, c: number) => {
    setIsSelecting(true);
    setSelection({ start: { r, c }, end: { r, c } });
    setFocusedCell({ r, c });
  };

  const handleMouseEnter = (r: number, c: number) => {
    if (isSelecting && selection) {
      setSelection({ ...selection, end: { r, c } });
    }
  };

  const handleMouseUp = () => {
    setIsSelecting(false);
    // If start and end are same, treat as single cell focus
    if (selection && selection.start.r === selection.end.r && selection.start.c === selection.end.c) {
      setSelection(null);
    }
  };

  const isSelected = (r: number, c: number) => {
    if (!selection) return false;
    const rStart = Math.min(selection.start.r, selection.end.r);
    const rEnd = Math.max(selection.start.r, selection.end.r);
    const cStart = Math.min(selection.start.c, selection.end.c);
    const cEnd = Math.max(selection.start.c, selection.end.c);
    return r >= rStart && r <= rEnd && c >= cStart && c <= cEnd;
  };

  const currentCellStyle = focusedCell ? styles[`${focusedCell.r}-${focusedCell.c}`] || {} : {};
  const isSelectedRange = selection && (selection.start.r !== selection.end.r || selection.start.c !== selection.end.c);

  const handleColorChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    updateStyle({ backgroundColor: e.target.value });
  };

  const clearColor = () => {
    updateStyle({ backgroundColor: undefined });
  };

  return (
    <div className="w-full space-y-4 relative" onMouseUp={handleMouseUp}>
      <div className="flex flex-wrap items-center justify-between gap-4">
        {/* Floating Toolbar */}
        <div 
          className={`flex items-center space-x-1 p-1 bg-white border border-gray-200 rounded-lg shadow-sm z-30 transition-all duration-200 ${focusedCell || selection ? 'opacity-100' : 'opacity-50 grayscale'}`}
          style={{ width: 'fit-content' }}
        >
          <button 
            onClick={() => updateStyle({ bold: !currentCellStyle.bold })}
            className={`p-1.5 rounded hover:bg-gray-100 transition-colors ${currentCellStyle.bold ? 'bg-green-100 text-green-700' : 'text-gray-600'}`}
            title="Bold"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 4h8a4 4 0 014 4 4 4 0 01-4 4H6z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 12h9a4 4 0 014 4 4 4 0 01-4 4H6z" /></svg>
          </button>
          <button 
            onClick={() => updateStyle({ italic: !currentCellStyle.italic })}
            className={`p-1.5 rounded hover:bg-gray-100 transition-colors ${currentCellStyle.italic ? 'bg-green-100 text-green-700' : 'text-gray-600'}`}
            title="Italic"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M10 20l4-16m-4 0h4m-4 16h4" /></svg>
          </button>
          <div className="w-px h-4 bg-gray-200 mx-1"></div>
          <button 
            onClick={() => updateStyle({ align: 'left' })}
            className={`p-1.5 rounded hover:bg-gray-100 transition-colors ${currentCellStyle.align === 'left' ? 'bg-green-100 text-green-700' : 'text-gray-600'}`}
            title="Align Left"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 12h10M4 18h16" /></svg>
          </button>
          <button 
            onClick={() => updateStyle({ align: 'center' })}
            className={`p-1.5 rounded hover:bg-gray-100 transition-colors ${currentCellStyle.align === 'center' ? 'bg-green-100 text-green-700' : 'text-gray-600'}`}
            title="Align Center"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M7 12h10M4 18h16" /></svg>
          </button>
          <button 
            onClick={() => updateStyle({ align: 'right' })}
            className={`p-1.5 rounded hover:bg-gray-100 transition-colors ${currentCellStyle.align === 'right' ? 'bg-green-100 text-green-700' : 'text-gray-600'}`}
            title="Align Right"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M10 12h10M4 18h16" /></svg>
          </button>
          <div className="w-px h-4 bg-gray-200 mx-1"></div>

          {/* Background Color Picker */}
          <div className="relative group/color flex items-center">
            <input 
              type="color" 
              ref={colorInputRef}
              onChange={handleColorChange}
              value={currentCellStyle.backgroundColor || '#ffffff'}
              className="absolute inset-0 opacity-0 cursor-pointer w-full h-full"
              title="Cell Background Color"
            />
            <button 
              className={`p-1.5 rounded hover:bg-gray-100 transition-colors ${currentCellStyle.backgroundColor ? 'text-green-600' : 'text-gray-600'}`}
            >
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M7 21a4 4 0 01-4-4V5a2 2 0 012-2h4a2 2 0 012 2v12a4 4 0 01-4 4zm0 0h12a2 2 0 002-2v-4a2 2 0 00-2-2h-2.343M11 7.343l1.657-1.657a2 2 0 012.828 0l2.829 2.829a2 2 0 010 2.828l-8.486 8.485M7 17h.01" />
              </svg>
            </button>
            {currentCellStyle.backgroundColor && (
              <button 
                onClick={(e) => { e.stopPropagation(); clearColor(); }}
                className="absolute -top-1 -right-1 bg-red-500 text-white rounded-full w-3 h-3 flex items-center justify-center text-[8px] hover:bg-red-600"
                title="Clear Color"
              >
                ×
              </button>
            )}
          </div>

          <div className="w-px h-4 bg-gray-200 mx-1"></div>
          <button 
            onClick={handleMerge}
            disabled={!isSelectedRange}
            className={`p-1.5 rounded hover:bg-gray-100 transition-colors ${!isSelectedRange ? 'opacity-30 cursor-not-allowed' : 'text-gray-600'}`}
            title="Merge Cells"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 8V6a2 2 0 012-2h4M4 16v2a2 2 0 002 2h4M20 8V6a2 2 0 00-2-2h-4M20 16v2a2 2 0 01-2 2h-4M8 12h8" />
            </svg>
          </button>
          <button 
            onClick={handleUnmerge}
            disabled={!focusedCell || !(styles[`${focusedCell.r}-${focusedCell.c}`]?.rowSpan || styles[`${focusedCell.r}-${focusedCell.c}`]?.colSpan)}
            className={`p-1.5 rounded hover:bg-gray-100 transition-colors ${(!focusedCell || !(styles[`${focusedCell.r}-${focusedCell.c}`]?.rowSpan || styles[`${focusedCell.r}-${focusedCell.c}`]?.colSpan)) ? 'opacity-30 cursor-not-allowed' : 'text-gray-600'}`}
            title="Unmerge Cells"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 6v6m0 0v6m0-6h6m-6 0H6M4 4h16v16H4V4z" />
            </svg>
          </button>
        </div>

        <button 
          onClick={() => setShowFindReplace(!showFindReplace)}
          className={`inline-flex items-center px-3 py-1.5 border rounded-lg text-sm font-medium transition-colors ${showFindReplace ? 'bg-blue-600 text-white border-blue-600' : 'bg-white text-gray-700 border-gray-300 hover:bg-gray-50'}`}
        >
          <svg className="w-4 h-4 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
          Find & Replace
        </button>
      </div>

      {/* Find & Replace Panel */}
      {showFindReplace && (
        <div className="p-4 bg-gray-50 border border-gray-200 rounded-xl animate-in slide-in-from-top-2">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-4">
            <div className="space-y-1">
              <label className="text-xs font-bold text-gray-500 uppercase">Find</label>
              <input 
                type="text" 
                value={findText}
                onChange={(e) => setFindText(e.target.value)}
                placeholder="Search for text..."
                className="w-full px-3 py-2 bg-white border border-gray-300 rounded-lg text-sm outline-none focus:ring-2 focus:ring-blue-500/20 focus:border-blue-500"
              />
            </div>
            <div className="space-y-1">
              <label className="text-xs font-bold text-gray-500 uppercase">Replace with</label>
              <input 
                type="text" 
                value={replaceText}
                onChange={(e) => setReplaceText(e.target.value)}
                placeholder="New text..."
                className="w-full px-3 py-2 bg-white border border-gray-300 rounded-lg text-sm outline-none focus:ring-2 focus:ring-green-500/20 focus:border-green-500"
              />
            </div>
          </div>
          <div className="flex flex-wrap items-center justify-between gap-4">
            <div className="flex items-center space-x-4">
              <label className="flex items-center space-x-2 text-sm text-gray-600 cursor-pointer">
                <input type="checkbox" checked={matchCase} onChange={(e) => setMatchCase(e.target.checked)} className="w-4 h-4 rounded border-gray-300 text-blue-600 focus:ring-blue-500" />
                <span>Match case</span>
              </label>
              <label className="flex items-center space-x-2 text-sm text-gray-600 cursor-pointer">
                <input type="checkbox" checked={wholeWord} onChange={(e) => setWholeWord(e.target.checked)} className="w-4 h-4 rounded border-gray-300 text-blue-600 focus:ring-blue-500" />
                <span>Whole word</span>
              </label>
            </div>
            <div className="flex items-center space-x-2">
              {searchResult.length > 0 && (
                <span className="text-xs text-gray-500 mr-2">
                  {currentSearchIndex + 1} of {searchResult.length}
                </span>
              )}
              <button 
                onClick={handleFind}
                className="px-4 py-2 bg-blue-600 text-white text-sm font-semibold rounded-lg hover:bg-blue-700 transition-colors shadow-sm"
              >
                Next Match
              </button>
              <button 
                onClick={handleReplace}
                className="px-4 py-2 bg-white border border-gray-300 text-gray-700 text-sm font-semibold rounded-lg hover:bg-gray-50 transition-colors shadow-sm"
              >
                Replace
              </button>
              <button 
                onClick={handleReplaceAll}
                className="px-4 py-2 bg-white border border-gray-300 text-gray-700 text-sm font-semibold rounded-lg hover:bg-gray-50 transition-colors shadow-sm"
              >
                Replace All
              </button>
            </div>
          </div>
        </div>
      )}

      <div className="flex items-center justify-between text-xs font-medium text-gray-500 px-1">
        <div className="flex items-center space-x-4">
          <div className="flex items-center">
            <div className="w-3 h-3 bg-red-100 border border-red-300 rounded mr-1.5"></div>
            <span>Invalid Format</span>
          </div>
          <div className="flex items-center">
            <div className="w-3 h-3 bg-blue-50 border border-blue-200 rounded mr-1.5"></div>
            <span>Selection</span>
          </div>
          <div className="flex items-center">
            <div className="w-3 h-3 bg-green-50 border border-green-200 rounded mr-1.5"></div>
            <span>Active Cell</span>
          </div>
        </div>
      </div>

      <div className="w-full overflow-auto border border-gray-200 rounded-xl shadow-sm bg-white max-h-[600px] scrollbar-thin scrollbar-thumb-gray-200">
        <table className="w-full text-sm text-left border-collapse table-fixed select-none">
          <thead className="sticky top-0 z-20 bg-gray-50 border-b border-gray-200">
            <tr>
              <th className="w-12 border-r border-gray-200 bg-gray-100 px-2 py-2.5 text-center text-[10px] font-bold text-gray-400 uppercase tracking-tighter">#</th>
              {Array.from({ length: colCount }).map((_, i) => (
                <th key={i} className="min-w-[150px] border-r border-gray-200 px-3 py-2.5 text-center text-xs font-bold text-gray-500 uppercase tracking-wider relative group">
                  {getColLabel(i)}
                  {columnTypes[i] && (
                    <span className="absolute bottom-0 left-0 w-full h-0.5 bg-blue-400 opacity-50" title="Numeric column"></span>
                  )}
                </th>
              ))}
            </tr>
          </thead>
          <tbody className="divide-y divide-gray-200">
            {data.map((row, rowIndex) => (
              <tr key={rowIndex} className="group hover:bg-gray-50/50 transition-colors">
                <td className="w-12 border-r border-gray-200 bg-gray-50/50 px-2 py-2 text-center text-xs font-medium text-gray-400">
                  {rowIndex + 1}
                </td>
                {Array.from({ length: colCount }).map((_, colIndex) => {
                  const key = `${rowIndex}-${colIndex}`;
                  if (hiddenCells.has(key)) return null;

                  const val = row[colIndex] || '';
                  const invalid = isInvalid(rowIndex, colIndex, val);
                  const isFocused = focusedCell?.r === rowIndex && focusedCell?.c === colIndex;
                  const selected = isSelected(rowIndex, colIndex);
                  const cellStyle = styles[key] || {};

                  return (
                    <td 
                      key={colIndex} 
                      rowSpan={cellStyle.rowSpan || 1}
                      colSpan={cellStyle.colSpan || 1}
                      onMouseDown={() => handleMouseDown(rowIndex, colIndex)}
                      onMouseEnter={() => handleMouseEnter(rowIndex, colIndex)}
                      style={{ 
                        backgroundColor: cellStyle.backgroundColor || (invalid ? 'rgb(254 242 242)' : isFocused ? 'rgb(240 253 244 / 0.4)' : selected ? 'rgb(239 246 255 / 0.5)' : 'transparent') 
                      }}
                      className={`relative border-r border-gray-100 p-0 transition-all duration-200 ${selected ? 'ring-1 ring-inset ring-blue-300 z-10' : ''}`}
                    >
                      <input
                        type="text"
                        value={val}
                        onFocus={() => {
                          setFocusedCell({ r: rowIndex, c: colIndex });
                          if (!isSelecting) setSelection(null);
                        }}
                        onChange={(e) => handleCellEdit(rowIndex, colIndex, e.target.value)}
                        style={{
                          fontWeight: cellStyle.bold ? 'bold' : 'normal',
                          fontStyle: cellStyle.italic ? 'italic' : 'normal',
                          textAlign: cellStyle.align || 'left',
                          backgroundColor: 'transparent'
                        }}
                        className={`w-full px-3 py-2 outline-none transition-all ${
                          invalid 
                            ? 'text-red-700 font-medium' 
                            : 'text-gray-700'
                        } ${isFocused ? 'ring-2 ring-green-400/50 z-20' : ''}`}
                      />
                      {invalid && (
                        <div className="absolute right-1 top-1 w-1.5 h-1.5 rounded-full bg-red-400 animate-pulse" title="Numeric expected"></div>
                      )}
                    </td>
                  );
                })}
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

import React, { useMemo, useState, useRef, useEffect } from 'react';
import { TableData, CellStyle, TableStyles } from '../types';

interface WorksheetProps {
  data: TableData;
  styles: TableStyles;
  onChange: (newData: TableData) => void;
  onStylesChange: (newStyles: TableStyles) => void;
}

interface Selection {
  start: { r: number; c: number };
  end: { r: number; c: number };
}

export const Worksheet: React.FC<WorksheetProps> = ({ data, styles, onChange, onStylesChange }) => {
  const [focusedCell, setFocusedCell] = useState<{ r: number; c: number } | null>(null);
  const [selection, setSelection] = useState<Selection | null>(null);
  const [isSelecting, setIsSelecting] = useState(false);
  const tableRef = useRef<HTMLTableElement>(null);

  const [showFindReplace, setShowFindReplace] = useState(false);
  const [findText, setFindText] = useState('');
  const [replaceText, setReplaceText] = useState('');
  const [matchCase, setMatchCase] = useState(false);
  const [wholeWord, setWholeWord] = useState(false);
  const [searchResult, setSearchResult] = useState<{ r: number, c: number }[]>([]);
  const [currentSearchIndex, setCurrentSearchIndex] = useState(-1);

  const colorInputRef = useRef<HTMLInputElement>(null);

  if (!data || data.length === 0) return null;

  const colCount = useMemo(() => Math.max(...data.map(row => row.length)), [data]);

  const columnTypes = useMemo(() => {
    const types: boolean[] = [];
    for (let c = 0; c < colCount; c++) {
      let numericCount = 0;
      let totalCount = 0;
      for (let r = 1; r < data.length; r++) {
        const val = data[r][c]?.trim();
        if (val) {
          totalCount++;
          const cleanVal = val.replace(/[$,€,£,%]/g, '');
          if (!isNaN(Number(cleanVal)) && cleanVal !== '') {
            numericCount++;
          }
        }
      }
      types[c] = totalCount > 0 && (numericCount / totalCount) > 0.6;
    }
    return types;
  }, [data, colCount]);

  const hiddenCells = useMemo(() => {
    const hidden = new Set<string>();
    (Object.entries(styles) as [string, CellStyle][]).forEach(([key, style]) => {
      if ((style.rowSpan && style.rowSpan > 1) || (style.colSpan && style.colSpan > 1)) {
        const [r, c] = key.split('-').map(Number);
        const rowSpan = style.rowSpan || 1;
        const colSpan = style.colSpan || 1;
        for (let dr = 0; dr < rowSpan; dr++) {
          for (let dc = 0; dc < colSpan; dc++) {
            if (dr === 0 && dc === 0) continue;
            hidden.add(`${r + dr}-${c + dc}`);
          }
        }
      }
    });
    return hidden;
  }, [styles]);

  const handleCellEdit = (rowIndex: number, colIndex: number, value: string) => {
    const newData = data.map((row, r) => {
      if (r === rowIndex) {
        const newRow = [...row];
        while (newRow.length < colCount) newRow.push('');
        newRow[colIndex] = value;
        return newRow;
      }
      return row;
    });
    onChange(newData);
  };

  const updateStyle = (stylePatch: Partial<CellStyle>) => {
    if (!focusedCell && !selection) return;
    const next = { ...styles };
    if (selection) {
      const rStart = Math.min(selection.start.r, selection.end.r);
      const rEnd = Math.max(selection.start.r, selection.end.r);
      const cStart = Math.min(selection.start.c, selection.end.c);
      const cEnd = Math.max(selection.start.c, selection.end.c);
      for (let r = rStart; r <= rEnd; r++) {
        for (let c = cStart; c <= cEnd; c++) {
          const key = `${r}-${c}`;
          if (!hiddenCells.has(key)) {
            next[key] = { ...next[key], ...stylePatch };
          }
        }
      }
    } else if (focusedCell) {
      const key = `${focusedCell.r}-${focusedCell.c}`;
      next[key] = { ...next[key], ...stylePatch };
    }
    onStylesChange(next);
  };

  const handleMerge = () => {
    if (!selection) return;
    const rStart = Math.min(selection.start.r, selection.end.r);
    const rEnd = Math.max(selection.start.r, selection.end.r);
    const cStart = Math.min(selection.start.c, selection.end.c);
    const cEnd = Math.max(selection.start.c, selection.end.c);
    if (rStart === rEnd && cStart === cEnd) return;
    const rowSpan = rEnd - rStart + 1;
    const colSpan = cEnd - cStart + 1;
    const next = { ...styles };
    for (let r = rStart; r <= rEnd; r++) {
      for (let c = cStart; c <= cEnd; c++) {
        if (r === rStart && c === cStart) continue;
        delete next[`${r}-${c}`];
      }
    }
    next[`${rStart}-${cStart}`] = { ...next[`${rStart}-${cStart}`], rowSpan, colSpan };
    onStylesChange(next);
    setSelection(null);
    setFocusedCell({ r: rStart, c: cStart });
  };

  const handleUnmerge = () => {
    if (!focusedCell) return;
    const key = `${focusedCell.r}-${focusedCell.c}`;
    if (styles[key]?.rowSpan || styles[key]?.colSpan) {
      const next = { ...styles };
      const { rowSpan, colSpan, ...rest } = next[key];
      next[key] = rest;
      onStylesChange(next);
    }
  };

  const isInvalid = (rowIndex: number, colIndex: number, value: string) => {
    if (rowIndex === 0) return false;
    if (!columnTypes[colIndex]) return false;
    if (!value.trim()) return false;
    const cleanVal = value.replace(/[$,€,£,%]/g, '').trim();
    return isNaN(Number(cleanVal));
  };

  const getColLabel = (index: number) => {
    let label = '';
    let i = index;
    while (i >= 0) {
      label = String.fromCharCode((i % 26) + 65) + label;
      i = Math.floor(i / 26) - 1;
    }
    return label;
  };

  const handleFind = () => {
    if (!findText) {
      setSearchResult([]);
      setCurrentSearchIndex(-1);
      return;
    }
    const results: { r: number, c: number }[] = [];
    data.forEach((row, r) => {
      row.forEach((cell, c) => {
        let content = cell || '';
        let search = findText;
        if (!matchCase) { content = content.toLowerCase(); search = search.toLowerCase(); }
        if (wholeWord) { if (content === search) results.push({ r, c }); }
        else if (content.includes(search)) { results.push({ r, c }); }
      });
    });
    setSearchResult(results);
    if (results.length > 0) {
      const nextIndex = (currentSearchIndex + 1) % results.length;
      setCurrentSearchIndex(nextIndex);
      setFocusedCell(results[nextIndex]);
      setSelection(null);
    } else {
      setCurrentSearchIndex(-1);
      alert('No matches found.');
    }
  };

  const handleReplace = () => {
    if (currentSearchIndex === -1 || searchResult.length === 0) {
      handleFind();
      return;
    }
    const current = searchResult[currentSearchIndex];
    const newData = data.map((row, r) => {
      if (r === current.r) {
        const newRow = [...row];
        const oldVal = newRow[current.c];
        let flags = matchCase ? '' : 'i';
        let regex = new RegExp(wholeWord ? `^${findText.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')}$` : findText.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'), flags);
        newRow[current.c] = oldVal.replace(regex, replaceText);
        return newRow;
      }
      return row;
    });
    onChange(newData);
    handleFind();
  };

  const handleReplaceAll = () => {
    if (!findText) return;
    let count = 0;
    let regex = new RegExp(wholeWord ? `\\b${findText.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')}\\b` : findText.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'), matchCase ? 'g' : 'gi');
    const newData = data.map(row => row.map(cell => {
      const newVal = cell.replace(regex, replaceText);
      if (newVal !== cell) count++;
      return newVal;
    }));
    onChange(newData);
    alert(`Replaced ${count} occurrences.`);
    setSearchResult([]);
    setCurrentSearchIndex(-1);
  };

  const handleMouseDown = (r: number, c: number, e: React.MouseEvent) => {
    // If we click on the textarea, only start selection if it's not already focused
    if (e.button !== 0) return;

    setIsSelecting(true);
    setSelection({ start: { r, c }, end: { r, c } });
    setFocusedCell({ r, c });

    // Prevent browser native text selection while dragging
    window.addEventListener('mouseup', handleGlobalMouseUp);
  };

  const handleMouseEnter = (r: number, c: number) => {
    if (isSelecting && selection) {
      setSelection({ ...selection, end: { r, c } });
    }
  };

  const handleGlobalMouseUp = () => {
    setIsSelecting(false);
    window.removeEventListener('mouseup', handleGlobalMouseUp);
  };

  const isSelected = (r: number, c: number) => {
    if (!selection) return false;
    const rStart = Math.min(selection.start.r, selection.end.r);
    const rEnd = Math.max(selection.start.r, selection.end.r);
    const cStart = Math.min(selection.start.c, selection.end.c);
    const cEnd = Math.max(selection.start.c, selection.end.c);
    return r >= rStart && r <= rEnd && c >= cStart && c <= cEnd;
  };

  const isSelectedRange = selection && (selection.start.r !== selection.end.r || selection.start.c !== selection.end.c);
  const currentCellStyle = focusedCell ? styles[`${focusedCell.r}-${focusedCell.c}`] || {} : {};

  // Visual Overlay for the Selection Rectangle
  const selectionStyle = useMemo(() => {
    if (!selection || !tableRef.current) return null;
    const rStart = Math.min(selection.start.r, selection.end.r);
    const rEnd = Math.max(selection.start.r, selection.end.r);
    const cStart = Math.min(selection.start.c, selection.end.c);
    const cEnd = Math.max(selection.start.c, selection.end.c);

    // This logic relies on the table structure being rendered
    // In a real spreadsheet, we'd use cell refs or a more stable coordinate system
    return null; // For CSS-only implementation inside cell rendering
  }, [selection]);

  return (
    <div className="w-full space-y-4 relative">
      <div className="flex flex-wrap items-center justify-between gap-4">
        <div 
          className={`flex items-center space-x-1 p-1 bg-white border border-gray-200 rounded-lg shadow-sm z-30 transition-all duration-200 ${focusedCell || selection ? 'opacity-100' : 'opacity-50 grayscale'}`}
          style={{ width: 'fit-content' }}
        >
          <button 
            onClick={() => updateStyle({ bold: !currentCellStyle.bold })}
            className={`p-1.5 rounded hover:bg-gray-100 transition-colors ${currentCellStyle.bold ? 'bg-green-100 text-green-700' : 'text-gray-600'}`}
            title="Bold"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 4h8a4 4 0 014 4 4 4 0 01-4 4H6z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 12h9a4 4 0 014 4 4 4 0 01-4 4H6z" /></svg>
          </button>
          <button 
            onClick={() => updateStyle({ italic: !currentCellStyle.italic })}
            className={`p-1.5 rounded hover:bg-gray-100 transition-colors ${currentCellStyle.italic ? 'bg-green-100 text-green-700' : 'text-gray-600'}`}
            title="Italic"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M10 20l4-16m-4 0h4m-4 16h4" /></svg>
          </button>
          <div className="w-px h-4 bg-gray-200 mx-1"></div>
          <button 
            onClick={() => updateStyle({ wrapText: !currentCellStyle.wrapText })}
            className={`p-1.5 rounded hover:bg-gray-100 transition-colors ${currentCellStyle.wrapText ? 'bg-green-100 text-green-700' : 'text-gray-600'}`}
            title="Wrap Text"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 12h10l-4 4m0 0l-4-4m4 4V8a4 4 0 014-4h4" />
            </svg>
          </button>
          <div className="w-px h-4 bg-gray-200 mx-1"></div>
          <button 
            onClick={() => updateStyle({ align: 'left' })}
            className={`p-1.5 rounded hover:bg-gray-100 transition-colors ${currentCellStyle.align === 'left' ? 'bg-green-100 text-green-700' : 'text-gray-600'}`}
            title="Align Left"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 12h10M4 18h16" /></svg>
          </button>
          <button 
            onClick={() => updateStyle({ align: 'center' })}
            className={`p-1.5 rounded hover:bg-gray-100 transition-colors ${currentCellStyle.align === 'center' ? 'bg-green-100 text-green-700' : 'text-gray-600'}`}
            title="Align Center"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M7 12h10M4 18h16" /></svg>
          </button>
          <button 
            onClick={() => updateStyle({ align: 'right' })}
            className={`p-1.5 rounded hover:bg-gray-100 transition-colors ${currentCellStyle.align === 'right' ? 'bg-green-100 text-green-700' : 'text-gray-600'}`}
            title="Align Right"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M10 12h10M4 18h16" /></svg>
          </button>
          <div className="w-px h-4 bg-gray-200 mx-1"></div>
          <div className="relative group/color flex items-center">
            <input 
              type="color" 
              ref={colorInputRef}
              onChange={(e) => updateStyle({ backgroundColor: e.target.value })}
              value={currentCellStyle.backgroundColor || '#ffffff'}
              className="absolute inset-0 opacity-0 cursor-pointer w-full h-full"
              title="Cell Background Color"
            />
            <button className={`p-1.5 rounded hover:bg-gray-100 transition-colors ${currentCellStyle.backgroundColor ? 'text-green-600' : 'text-gray-600'}`}>
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M7 21a4 4 0 01-4-4V5a2 2 0 012-2h4a2 2 0 012 2v12a4 4 0 01-4 4zm0 0h12a2 2 0 002-2v-4a2 2 0 00-2-2h-2.343M11 7.343l1.657-1.657a2 2 0 012.828 0l2.829 2.829a2 2 0 010 2.828l-8.486 8.485M7 17h.01" />
              </svg>
            </button>
            {currentCellStyle.backgroundColor && (
              <button 
                onClick={(e) => { e.stopPropagation(); updateStyle({ backgroundColor: undefined }); }}
                className="absolute -top-1 -right-1 bg-red-500 text-white rounded-full w-3 h-3 flex items-center justify-center text-[8px] hover:bg-red-600"
              >×</button>
            )}
          </div>
          <div className="w-px h-4 bg-gray-200 mx-1"></div>
          <button 
            onClick={handleMerge}
            disabled={!isSelectedRange}
            className={`p-1.5 rounded hover:bg-gray-100 transition-colors ${!isSelectedRange ? 'opacity-30 cursor-not-allowed' : 'text-gray-600'}`}
            title="Merge Cells"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 8V6a2 2 0 012-2h4M4 16v2a2 2 0 002 2h4M20 8V6a2 2 0 00-2-2h-4M20 16v2a2 2 0 01-2 2h-4M8 12h8" /></svg>
          </button>
          <button 
            onClick={handleUnmerge}
            disabled={!focusedCell || !(styles[`${focusedCell.r}-${focusedCell.c}`]?.rowSpan || styles[`${focusedCell.r}-${focusedCell.c}`]?.colSpan)}
            className={`p-1.5 rounded hover:bg-gray-100 transition-colors ${(!focusedCell || !(styles[`${focusedCell.r}-${focusedCell.c}`]?.rowSpan || styles[`${focusedCell.r}-${focusedCell.c}`]?.colSpan)) ? 'opacity-30 cursor-not-allowed' : 'text-gray-600'}`}
            title="Unmerge Cells"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 6v6m0 0v6m0-6h6m-6 0H6M4 4h16v16H4V4z" /></svg>
          </button>
        </div>
        <button 
          onClick={() => setShowFindReplace(!showFindReplace)}
          className={`inline-flex items-center px-3 py-1.5 border rounded-lg text-sm font-medium transition-colors ${showFindReplace ? 'bg-blue-600 text-white border-blue-600' : 'bg-white text-gray-700 border-gray-300 hover:bg-gray-50'}`}
        >
          <svg className="w-4 h-4 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
          Find & Replace
        </button>
      </div>

      {showFindReplace && (
        <div className="p-4 bg-gray-50 border border-gray-200 rounded-xl animate-in slide-in-from-top-2">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-4">
            <input type="text" value={findText} onChange={(e) => setFindText(e.target.value)} placeholder="Find..." className="w-full px-3 py-2 bg-white border border-gray-300 rounded-lg text-sm outline-none focus:ring-2 focus:ring-blue-500/20" />
            <input type="text" value={replaceText} onChange={(e) => setReplaceText(e.target.value)} placeholder="Replace with..." className="w-full px-3 py-2 bg-white border border-gray-300 rounded-lg text-sm outline-none focus:ring-2 focus:ring-green-500/20" />
          </div>
          <div className="flex flex-wrap items-center justify-between gap-4">
            <div className="flex items-center space-x-4">
              <label className="flex items-center space-x-2 text-sm text-gray-600 cursor-pointer"><input type="checkbox" checked={matchCase} onChange={(e) => setMatchCase(e.target.checked)} className="w-4 h-4 rounded text-blue-600" /><span>Case</span></label>
              <label className="flex items-center space-x-2 text-sm text-gray-600 cursor-pointer"><input type="checkbox" checked={wholeWord} onChange={(e) => setWholeWord(e.target.checked)} className="w-4 h-4 rounded text-blue-600" /><span>Word</span></label>
            </div>
            <div className="flex items-center space-x-2">
              <button onClick={handleFind} className="px-4 py-2 bg-blue-600 text-white text-sm font-semibold rounded-lg hover:bg-blue-700">Next</button>
              <button onClick={handleReplace} className="px-4 py-2 bg-white border border-gray-300 text-gray-700 text-sm font-semibold rounded-lg hover:bg-gray-50">Replace</button>
              <button onClick={handleReplaceAll} className="px-4 py-2 bg-white border border-gray-300 text-gray-700 text-sm font-semibold rounded-lg hover:bg-gray-50">All</button>
            </div>
          </div>
        </div>
      )}

      <div className="w-full overflow-auto border border-gray-200 rounded-xl shadow-sm bg-white max-h-[600px] scrollbar-thin select-none">
        <table ref={tableRef} className="w-full text-sm text-left border-collapse table-fixed select-none">
          <thead className="sticky top-0 z-20 bg-gray-50 border-b border-gray-200">
            <tr>
              <th className="w-12 border-r border-gray-200 bg-gray-100 px-2 py-2.5 text-center text-[10px] font-bold text-gray-400 uppercase tracking-tighter">#</th>
              {Array.from({ length: colCount }).map((_, i) => (
                <th key={i} className="min-w-[150px] border-r border-gray-200 px-3 py-2.5 text-center text-xs font-bold text-gray-500 uppercase tracking-wider">{getColLabel(i)}</th>
              ))}
            </tr>
          </thead>
          <tbody className="divide-y divide-gray-200">
            {data.map((row, rowIndex) => (
              <tr key={rowIndex} className="group transition-colors">
                <td className="w-12 border-r border-gray-200 bg-gray-50/50 px-2 py-2 text-center text-xs font-medium text-gray-400">{rowIndex + 1}</td>
                {Array.from({ length: colCount }).map((_, colIndex) => {
                  const key = `${rowIndex}-${colIndex}`;
                  if (hiddenCells.has(key)) return null;
                  const val = row[colIndex] || '';
                  const invalid = isInvalid(rowIndex, colIndex, val);
                  const isFocused = focusedCell?.r === rowIndex && focusedCell?.c === colIndex;
                  const selected = isSelected(rowIndex, colIndex);
                  const cellStyle = styles[key] || {};

                  // Selection border logic: apply border classes to cells at the boundary of selection
                  let borderClasses = '';
                  if (selection) {
                    const rS = Math.min(selection.start.r, selection.end.r);
                    const rE = Math.max(selection.start.r, selection.end.r);
                    const cS = Math.min(selection.start.c, selection.end.c);
                    const cE = Math.max(selection.start.c, selection.end.c);

                    if (selected) {
                      if (rowIndex === rS) borderClasses += ' border-t-2 border-t-blue-500';
                      if (rowIndex === rE) borderClasses += ' border-b-2 border-b-blue-500';
                      if (colIndex === cS) borderClasses += ' border-l-2 border-l-blue-500';
                      if (colIndex === cE) borderClasses += ' border-r-2 border-r-blue-500';
                    }
                  }

                  return (
                    <td 
                      key={colIndex} 
                      rowSpan={cellStyle.rowSpan || 1}
                      colSpan={cellStyle.colSpan || 1}
                      onMouseDown={(e) => handleMouseDown(rowIndex, colIndex, e)}
                      onMouseEnter={() => handleMouseEnter(rowIndex, colIndex)}
                      style={{ 
                        backgroundColor: cellStyle.backgroundColor || (invalid ? 'rgb(254 242 242)' : isFocused ? 'rgb(240 253 244 / 0.4)' : selected ? 'rgb(239 246 255 / 0.5)' : 'transparent'),
                        verticalAlign: 'top'
                      }}
                      className={`relative border-r border-gray-100 p-0 transition-all duration-75 ${borderClasses} ${selected ? 'z-10' : ''}`}
                    >
                      <textarea
                        value={val}
                        rows={1}
                        onFocus={() => {
                          setFocusedCell({ r: rowIndex, c: colIndex });
                          if (!isSelecting) setSelection(null);
                        }}
                        onChange={(e) => {
                          handleCellEdit(rowIndex, colIndex, e.target.value);
                          if (cellStyle.wrapText) {
                            e.target.style.height = 'auto';
                            e.target.style.height = e.target.scrollHeight + 'px';
                          }
                        }}
                        onMouseDown={(e) => {
                          // Allow editing if already focused, otherwise let the td handle selection
                          if (!isFocused) {
                            e.preventDefault();
                          }
                        }}
                        style={{
                          fontWeight: cellStyle.bold ? 'bold' : 'normal',
                          fontStyle: cellStyle.italic ? 'italic' : 'normal',
                          textAlign: cellStyle.align || 'left',
                          backgroundColor: 'transparent',
                          whiteSpace: cellStyle.wrapText ? 'pre-wrap' : 'nowrap',
                          overflow: 'hidden',
                          resize: 'none',
                          minHeight: '2.5rem',
                          height: 'auto',
                          cursor: isFocused ? 'text' : 'cell'
                        }}
                        className={`w-full px-3 py-2 outline-none transition-all block scrollbar-none select-none pointer-events-auto ${invalid ? 'text-red-700 font-medium' : 'text-gray-700'}`}
                      />
                    </td>
                  );
                })}
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export type TableData = string[][];

export interface CellStyle {
  bold?: boolean;
  italic?: boolean;
  align?: 'left' | 'center' | 'right';
  rowSpan?: number;
  colSpan?: number;
  backgroundColor?: string;
  wrapText?: boolean;
  fontSize?: string; // e.g., "12px", "14px"
  fontFamily?: string; // e.g., "Inter", "Monospace"
}

export type TableStyles = Record<string, CellStyle>; // key is "rowIndex-colIndex"

export interface ConversionState {
  isProcessing: boolean;
  error: string | null;
  data: TableData | null;
  fileName: string | null;
  styles?: TableStyles;
}

import * as XLSX from 'xlsx';
import { TableData, TableStyles, CellStyle } from '../types';

export const downloadAsExcel = (data: TableData, fileName: string = 'Snap2Sheet_Export') => {
  const ws = XLSX.utils.aoa_to_sheet(data);
  const wb = XLSX.utils.book_new();
  XLSX.utils.book_append_sheet(wb, ws, "Sheet1");
  XLSX.writeFile(wb, `${fileName}.xlsx`);
};

export const downloadAsCSV = (data: TableData, fileName: string = 'Snap2Sheet_Export') => {
  const csvContent = data.map(row => 
    row.map(cell => {
      const escaped = cell.replace(/"/g, '""');
      return `"${escaped}"`;
    }).join(',')
  ).join('\n');

  const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
  const url = URL.createObjectURL(blob);
  const link = document.createElement('a');
  link.setAttribute('href', url);
  link.setAttribute('download', `${fileName}.csv`);
  link.style.visibility = 'hidden';
  document.body.appendChild(link);
  link.click();
  document.body.removeChild(link);
};

export const copyToClipboard = async (data: TableData) => {
  const csvContent = data.map(row => row.join('\t')).join('\n');
  try {
    await navigator.clipboard.writeText(csvContent);
    return true;
  } catch (err) {
    console.error('Failed to copy: ', err);
    return false;
  }
};

/**
 * Copies the table data and styles to clipboard as HTML.
 * Excel and Google Sheets can parse this to preserve formatting.
 */
export const copyTableToClipboard = async (data: TableData, styles: TableStyles = {}) => {
  const colCount = Math.max(...data.map(row => row.length));

  // Track hidden cells due to spans
  const hidden = new Set<string>();
  Object.entries(styles).forEach(([key, style]) => {
    if (style.rowSpan || style.colSpan) {
      const [r, c] = key.split('-').map(Number);
      const rs = style.rowSpan || 1;
      const cs = style.colSpan || 1;
      for (let dr = 0; dr < rs; dr++) {
        for (let dc = 0; dc < cs; dc++) {
          if (dr === 0 && dc === 0) continue;
          hidden.add(`${r + dr}-${c + dc}`);
        }
      }
    }
  });

  let html = '<table border="1" style="border-collapse: collapse; font-family: sans-serif;">';

  data.forEach((row, r) => {
    html += '<tr>';
    for (let c = 0; c < colCount; c++) {
      const key = `${r}-${c}`;
      if (hidden.has(key)) continue;

      const style = styles[key] || {};
      const value = row[c] || '';

      let css = '';
      if (style.bold) css += 'font-weight: bold; ';
      if (style.italic) css += 'font-style: italic; ';
      if (style.align) css += `text-align: ${style.align}; `;
      if (style.backgroundColor) css += `background-color: ${style.backgroundColor}; `;
      if (style.fontSize) css += `font-size: ${style.fontSize}; `;
      if (style.fontFamily) css += `font-family: ${style.fontFamily}; `;
      if (style.wrapText) css += 'white-space: normal; ';

      const rs = style.rowSpan ? ` rowspan="${style.rowSpan}"` : '';
      const cs = style.colSpan ? ` colspan="${style.colSpan}"` : '';

      html += `<td${rs}${cs} style="${css}">${value}</td>`;
    }
    html += '</tr>';
  });
  html += '</table>';

  const plainText = data.map(row => row.join('\t')).join('\n');

  try {
    const blobHtml = new Blob([html], { type: 'text/html' });
    const blobText = new Blob([plainText], { type: 'text/plain' });
    const dataObj = [new ClipboardItem({
      'text/html': blobHtml,
      'text/plain': blobText
    })];

    await navigator.clipboard.write(dataObj);
    return true;
  } catch (err) {
    console.error('Rich copy failed', err);
    return false;
  }
};

export const shareData = async (data: TableData) => {
  const csvContent = data.map(row => row.join(',')).join('\n');
  const blob = new Blob([csvContent], { type: 'text/csv' });
  const file = new File([blob], 'Snap2Sheet_Export.csv', { type: 'text/csv' });

  if (navigator.canShare && navigator.canShare({ files: [file] })) {
    try {
      await navigator.share({
        files: [file],
        title: 'Snap2Sheet Data Export',
        text: 'Here is the data converted from my image.',
      });
    } catch (err) {
      console.error('Share failed', err);
    }
  } else {
    alert('Sharing not supported on this browser.');
  }
};

import React, { useMemo, useState, useRef, useEffect } from 'react';
import { TableData, CellStyle, TableStyles } from '../types';

interface WorksheetProps {
  data: TableData;
  styles: TableStyles;
  onChange: (newData: TableData) => void;
  onStylesChange: (newStyles: TableStyles) => void;
}

interface Selection {
  start: { r: number; c: number };
  end: { r: number; c: number };
}

const FONT_SIZES = ['8px', '9px', '10px', '11px', '12px', '14px', '16px', '18px', '20px', '24px', '28px', '32px'];
const FONT_FAMILIES = ['Inter', 'Arial', 'Verdana', 'Times New Roman', 'Courier New', 'Monospace', 'Georgia'];

export const Worksheet: React.FC<WorksheetProps> = ({ data, styles, onChange, onStylesChange }) => {
  const [focusedCell, setFocusedCell] = useState<{ r: number; c: number } | null>(null);
  const [selection, setSelection] = useState<Selection | null>(null);
  const [isSelecting, setIsSelecting] = useState(false);
  const tableRef = useRef<HTMLTableElement>(null);

  const [showFindReplace, setShowFindReplace] = useState(false);
  const [findText, setFindText] = useState('');
  const [replaceText, setReplaceText] = useState('');
  const [matchCase, setMatchCase] = useState(false);
  const [wholeWord, setWholeWord] = useState(false);
  const [searchResult, setSearchResult] = useState<{ r: number, c: number }[]>([]);
  const [currentSearchIndex, setCurrentSearchIndex] = useState(-1);

  const colorInputRef = useRef<HTMLInputElement>(null);

  if (!data || data.length === 0) return null;

  const colCount = useMemo(() => Math.max(...data.map(row => row.length)), [data]);

  const columnTypes = useMemo(() => {
    const types: boolean[] = [];
    for (let c = 0; c < colCount; c++) {
      let numericCount = 0;
      let totalCount = 0;
      for (let r = 1; r < data.length; r++) {
        const val = data[r][c]?.trim();
        if (val) {
          totalCount++;
          const cleanVal = val.replace(/[$,€,£,%]/g, '');
          if (!isNaN(Number(cleanVal)) && cleanVal !== '') {
            numericCount++;
          }
        }
      }
      types[c] = totalCount > 0 && (numericCount / totalCount) > 0.6;
    }
    return types;
  }, [data, colCount]);

  const hiddenCells = useMemo(() => {
    const hidden = new Set<string>();
    (Object.entries(styles) as [string, CellStyle][]).forEach(([key, style]) => {
      if ((style.rowSpan && style.rowSpan > 1) || (style.colSpan && style.colSpan > 1)) {
        const [r, c] = key.split('-').map(Number);
        const rowSpan = style.rowSpan || 1;
        const colSpan = style.colSpan || 1;
        for (let dr = 0; dr < rowSpan; dr++) {
          for (let dc = 0; dc < colSpan; dc++) {
            if (dr === 0 && dc === 0) continue;
            hidden.add(`${r + dr}-${c + dc}`);
          }
        }
      }
    });
    return hidden;
  }, [styles]);

  const handleCellEdit = (rowIndex: number, colIndex: number, value: string) => {
    const newData = data.map((row, r) => {
      if (r === rowIndex) {
        const newRow = [...row];
        while (newRow.length < colCount) newRow.push('');
        newRow[colIndex] = value;
        return newRow;
      }
      return row;
    });
    onChange(newData);
  };

  const updateStyle = (stylePatch: Partial<CellStyle>) => {
    if (!focusedCell && !selection) return;
    const next = { ...styles };
    if (selection) {
      const rStart = Math.min(selection.start.r, selection.end.r);
      const rEnd = Math.max(selection.start.r, selection.end.r);
      const cStart = Math.min(selection.start.c, selection.end.c);
      const cEnd = Math.max(selection.start.c, selection.end.c);
      for (let r = rStart; r <= rEnd; r++) {
        for (let c = cStart; c <= cEnd; c++) {
          const key = `${r}-${c}`;
          if (!hiddenCells.has(key)) {
            next[key] = { ...next[key], ...stylePatch };
          }
        }
      }
    } else if (focusedCell) {
      const key = `${focusedCell.r}-${focusedCell.c}`;
      next[key] = { ...next[key], ...stylePatch };
    }
    onStylesChange(next);
  };

  // Structural Updates
  const insertRow = (index: number) => {
    const newRow = Array(colCount).fill('');
    const newData = [...data];
    newData.splice(index, 0, newRow);

    // Shift styles
    const nextStyles: TableStyles = {};
    Object.entries(styles).forEach(([key, style]) => {
      const [r, c] = key.split('-').map(Number);
      if (r >= index) {
        nextStyles[`${r + 1}-${c}`] = style;
      } else {
        nextStyles[key] = style;
      }
    });

    onChange(newData);
    onStylesChange(nextStyles);
    setFocusedCell(null);
    setSelection(null);
  };

  const deleteRow = (index: number) => {
    if (data.length <= 1) return;
    const newData = data.filter((_, i) => i !== index);

    // Shift styles
    const nextStyles: TableStyles = {};
    Object.entries(styles).forEach(([key, style]) => {
      const [r, c] = key.split('-').map(Number);
      if (r === index) return;
      if (r > index) {
        nextStyles[`${r - 1}-${c}`] = style;
      } else {
        nextStyles[key] = style;
      }
    });

    onChange(newData);
    onStylesChange(nextStyles);
    setFocusedCell(null);
    setSelection(null);
  };

  const insertColumn = (index: number) => {
    const newData = data.map(row => {
      const newRow = [...row];
      newRow.splice(index, 0, '');
      return newRow;
    });

    // Shift styles
    const nextStyles: TableStyles = {};
    Object.entries(styles).forEach(([key, style]) => {
      const [r, c] = key.split('-').map(Number);
      if (c >= index) {
        nextStyles[`${r}-${c + 1}`] = style;
      } else {
        nextStyles[key] = style;
      }
    });

    onChange(newData);
    onStylesChange(nextStyles);
    setFocusedCell(null);
    setSelection(null);
  };

  const deleteColumn = (index: number) => {
    if (colCount <= 1) return;
    const newData = data.map(row => row.filter((_, i) => i !== index));

    // Shift styles
    const nextStyles: TableStyles = {};
    Object.entries(styles).forEach(([key, style]) => {
      const [r, c] = key.split('-').map(Number);
      if (c === index) return;
      if (c > index) {
        nextStyles[`${r}-${c - 1}`] = style;
      } else {
        nextStyles[key] = style;
      }
    });

    onChange(newData);
    onStylesChange(nextStyles);
    setFocusedCell(null);
    setSelection(null);
  };

  const handleMerge = () => {
    if (!selection) return;
    const rStart = Math.min(selection.start.r, selection.end.r);
    const rEnd = Math.max(selection.start.r, selection.end.r);
    const cStart = Math.min(selection.start.c, selection.end.c);
    const cEnd = Math.max(selection.start.c, selection.end.c);
    if (rStart === rEnd && cStart === cEnd) return;
    const rowSpan = rEnd - rStart + 1;
    const colSpan = cEnd - cStart + 1;
    const next = { ...styles };
    for (let r = rStart; r <= rEnd; r++) {
      for (let c = cStart; c <= cEnd; c++) {
        if (r === rStart && c === cStart) continue;
        delete next[`${r}-${c}`];
      }
    }
    next[`${rStart}-${cStart}`] = { ...next[`${rStart}-${cStart}`], rowSpan, colSpan };
    onStylesChange(next);
    setSelection(null);
    setFocusedCell({ r: rStart, c: cStart });
  };

  const handleUnmerge = () => {
    if (!focusedCell) return;
    const key = `${focusedCell.r}-${focusedCell.c}`;
    if (styles[key]?.rowSpan || styles[key]?.colSpan) {
      const next = { ...styles };
      const { rowSpan, colSpan, ...rest } = next[key];
      next[key] = rest;
      onStylesChange(next);
    }
  };

  const isInvalid = (rowIndex: number, colIndex: number, value: string) => {
    if (rowIndex === 0) return false;
    if (!columnTypes[colIndex]) return false;
    if (!value.trim()) return false;
    const cleanVal = value.replace(/[$,€,£,%]/g, '').trim();
    return isNaN(Number(cleanVal));
  };

  const getColLabel = (index: number) => {
    let label = '';
    let i = index;
    while (i >= 0) {
      label = String.fromCharCode((i % 26) + 65) + label;
      i = Math.floor(i / 26) - 1;
    }
    return label;
  };

  const handleFind = () => {
    if (!findText) {
      setSearchResult([]);
      setCurrentSearchIndex(-1);
      return;
    }
    const results: { r: number, c: number }[] = [];
    data.forEach((row, r) => {
      row.forEach((cell, c) => {
        let content = cell || '';
        let search = findText;
        if (!matchCase) { content = content.toLowerCase(); search = search.toLowerCase(); }
        if (wholeWord) { if (content === search) results.push({ r, c }); }
        else if (content.includes(search)) { results.push({ r, c }); }
      });
    });
    setSearchResult(results);
    if (results.length > 0) {
      const nextIndex = (currentSearchIndex + 1) % results.length;
      setCurrentSearchIndex(nextIndex);
      setFocusedCell(results[nextIndex]);
      setSelection(null);
    } else {
      setCurrentSearchIndex(-1);
      alert('No matches found.');
    }
  };

  const handleReplace = () => {
    if (currentSearchIndex === -1 || searchResult.length === 0) {
      handleFind();
      return;
    }
    const current = searchResult[currentSearchIndex];
    const newData = data.map((row, r) => {
      if (r === current.r) {
        const newRow = [...row];
        const oldVal = newRow[current.c];
        let flags = matchCase ? '' : 'i';
        let regex = new RegExp(wholeWord ? `^${findText.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')}$` : findText.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'), flags);
        newRow[current.c] = oldVal.replace(regex, replaceText);
        return newRow;
      }
      return row;
    });
    onChange(newData);
    handleFind();
  };

  const handleReplaceAll = () => {
    if (!findText) return;
    let count = 0;
    let regex = new RegExp(wholeWord ? `\\b${findText.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')}\\b` : findText.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'), matchCase ? 'g' : 'gi');
    const newData = data.map(row => row.map(cell => {
      const newVal = cell.replace(regex, replaceText);
      if (newVal !== cell) count++;
      return newVal;
    }));
    onChange(newData);
    alert(`Replaced ${count} occurrences.`);
    setSearchResult([]);
    setCurrentSearchIndex(-1);
  };

  const handleMouseDown = (r: number, c: number, e: React.MouseEvent) => {
    if (e.button !== 0) return;
    setIsSelecting(true);
    setSelection({ start: { r, c }, end: { r, c } });
    setFocusedCell({ r, c });
    window.addEventListener('mouseup', handleGlobalMouseUp);
  };

  const handleMouseEnter = (r: number, c: number) => {
    if (isSelecting && selection) {
      setSelection({ ...selection, end: { r, c } });
    }
  };

  const handleGlobalMouseUp = () => {
    setIsSelecting(false);
    window.removeEventListener('mouseup', handleGlobalMouseUp);
  };

  const isSelected = (r: number, c: number) => {
    if (!selection) return false;
    const rStart = Math.min(selection.start.r, selection.end.r);
    const rEnd = Math.max(selection.start.r, selection.end.r);
    const cStart = Math.min(selection.start.c, selection.end.c);
    const cEnd = Math.max(selection.start.c, selection.end.c);
    return r >= rStart && r <= rEnd && c >= cStart && c <= cEnd;
  };

  const isSelectedRange = selection && (selection.start.r !== selection.end.r || selection.start.c !== selection.end.c);
  const currentCellStyle = focusedCell ? styles[`${focusedCell.r}-${focusedCell.c}`] || {} : {};

  return (
    <div className="w-full space-y-4 relative">
      <div className="flex flex-wrap items-center gap-2 p-1.5 bg-white border border-gray-200 rounded-xl shadow-sm z-30 overflow-x-auto no-scrollbar">
        {/* Font Family */}
        <select 
          value={currentCellStyle.fontFamily || 'Inter'}
          onChange={(e) => updateStyle({ fontFamily: e.target.value })}
          className="text-sm border-gray-200 rounded-lg px-2 py-1 outline-none bg-gray-50 hover:bg-white transition-colors min-w-[120px]"
        >
          {FONT_FAMILIES.map(f => <option key={f} value={f}>{f}</option>)}
        </select>

        {/* Font Size */}
        <select 
          value={currentCellStyle.fontSize || '14px'}
          onChange={(e) => updateStyle({ fontSize: e.target.value })}
          className="text-sm border-gray-200 rounded-lg px-2 py-1 outline-none bg-gray-50 hover:bg-white transition-colors min-w-[70px]"
        >
          {FONT_SIZES.map(s => <option key={s} value={s}>{s}</option>)}
        </select>

        <div className="w-px h-6 bg-gray-200 mx-1"></div>

        <div className="flex items-center space-x-1">
          <button 
            onClick={() => updateStyle({ bold: !currentCellStyle.bold })}
            className={`p-1.5 rounded-lg hover:bg-gray-100 transition-colors ${currentCellStyle.bold ? 'bg-green-100 text-green-700' : 'text-gray-600'}`}
            title="Bold"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 4h8a4 4 0 014 4 4 4 0 01-4 4H6z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 12h9a4 4 0 014 4 4 4 0 01-4 4H6z" /></svg>
          </button>
          <button 
            onClick={() => updateStyle({ italic: !currentCellStyle.italic })}
            className={`p-1.5 rounded-lg hover:bg-gray-100 transition-colors ${currentCellStyle.italic ? 'bg-green-100 text-green-700' : 'text-gray-600'}`}
            title="Italic"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M10 20l4-16m-4 0h4m-4 16h4" /></svg>
          </button>
          <button 
            onClick={() => updateStyle({ wrapText: !currentCellStyle.wrapText })}
            className={`p-1.5 rounded-lg hover:bg-gray-100 transition-colors ${currentCellStyle.wrapText ? 'bg-green-100 text-green-700' : 'text-gray-600'}`}
            title="Wrap Text"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 12h10l-4 4m0 0l-4-4m4 4V8a4 4 0 014-4h4" /></svg>
          </button>
        </div>

        <div className="w-px h-6 bg-gray-200 mx-1"></div>

        <div className="flex items-center space-x-1">
          <button onClick={() => updateStyle({ align: 'left' })} className={`p-1.5 rounded-lg ${currentCellStyle.align === 'left' ? 'bg-blue-100 text-blue-700' : 'text-gray-600'}`}><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 12h10M4 18h16" /></svg></button>
          <button onClick={() => updateStyle({ align: 'center' })} className={`p-1.5 rounded-lg ${currentCellStyle.align === 'center' ? 'bg-blue-100 text-blue-700' : 'text-gray-600'}`}><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M7 12h10M4 18h16" /></svg></button>
          <button onClick={() => updateStyle({ align: 'right' })} className={`p-1.5 rounded-lg ${currentCellStyle.align === 'right' ? 'bg-blue-100 text-blue-700' : 'text-gray-600'}`}><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M10 12h10M4 18h16" /></svg></button>
        </div>

        <div className="w-px h-6 bg-gray-200 mx-1"></div>

        <div className="relative flex items-center">
          <input type="color" ref={colorInputRef} onChange={(e) => updateStyle({ backgroundColor: e.target.value })} value={currentCellStyle.backgroundColor || '#ffffff'} className="absolute inset-0 opacity-0 cursor-pointer w-full h-full" />
          <button className={`p-1.5 rounded-lg ${currentCellStyle.backgroundColor ? 'text-green-600' : 'text-gray-600'}`}><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M7 21a4 4 0 01-4-4V5a2 2 0 012-2h4a2 2 0 012 2v12a4 4 0 01-4 4zm0 0h12a2 2 0 002-2v-4a2 2 0 00-2-2h-2.343M11 7.343l1.657-1.657a2 2 0 012.828 0l2.829 2.829a2 2 0 010 2.828l-8.486 8.485M7 17h.01" /></svg></button>
          {currentCellStyle.backgroundColor && <button onClick={(e) => { e.stopPropagation(); updateStyle({ backgroundColor: undefined }); }} className="absolute -top-1 -right-1 bg-red-500 text-white rounded-full w-3 h-3 text-[8px]">×</button>}
        </div>

        <div className="w-px h-6 bg-gray-200 mx-1"></div>

        <div className="flex items-center space-x-1">
          <button onClick={handleMerge} disabled={!isSelectedRange} className={`p-1.5 rounded-lg ${!isSelectedRange ? 'opacity-30' : 'text-gray-600'}`} title="Merge"><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 8V6a2 2 0 012-2h4M4 16v2a2 2 0 002 2h4M20 8V6a2 2 0 00-2-2h-4M20 16v2a2 2 0 01-2 2h-4M8 12h8" /></svg></button>
          <button onClick={handleUnmerge} disabled={!focusedCell || !(styles[`${focusedCell.r}-${focusedCell.c}`]?.rowSpan || styles[`${focusedCell.r}-${focusedCell.c}`]?.colSpan)} className={`p-1.5 rounded-lg ${(!focusedCell || !(styles[`${focusedCell.r}-${focusedCell.c}`]?.rowSpan || styles[`${focusedCell.r}-${focusedCell.c}`]?.colSpan)) ? 'opacity-30' : 'text-gray-600'}`} title="Unmerge"><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 6v6m0 0v6m0-6h6m-6 0H6M4 4h16v16H4V4z" /></svg></button>
        </div>

        <div className="w-px h-6 bg-gray-200 mx-1"></div>

        {/* Structural Controls */}
        <div className="flex items-center space-x-1">
          <button 
            onClick={() => focusedCell && insertRow(focusedCell.r)}
            disabled={!focusedCell}
            className="p-1.5 rounded-lg text-gray-600 hover:bg-gray-100 disabled:opacity-30" 
            title="Insert Row Above"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4M4 4h16v4H4V4z" /></svg>
          </button>
          <button 
            onClick={() => focusedCell && deleteRow(focusedCell.r)}
            disabled={!focusedCell}
            className="p-1.5 rounded-lg text-red-500 hover:bg-red-50 disabled:opacity-30" 
            title="Delete Row"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M20 12H4M4 4h16v4H4V4z" /></svg>
          </button>
          <button 
            onClick={() => focusedCell && insertColumn(focusedCell.c)}
            disabled={!focusedCell}
            className="p-1.5 rounded-lg text-gray-600 hover:bg-gray-100 disabled:opacity-30" 
            title="Insert Column Left"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 12v8m8-8V4m8 8H4M12 4v16M4 4h4v16H4V4z" /></svg>
          </button>
          <button 
            onClick={() => focusedCell && deleteColumn(focusedCell.c)}
            disabled={!focusedCell}
            className="p-1.5 rounded-lg text-red-500 hover:bg-red-50 disabled:opacity-30" 
            title="Delete Column"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M20 12H4M4 4h4v16H4V4z" /></svg>
          </button>
        </div>

        <button 
          onClick={() => setShowFindReplace(!showFindReplace)}
          className={`ml-auto inline-flex items-center px-3 py-1.5 border rounded-lg text-sm font-medium transition-colors ${showFindReplace ? 'bg-blue-600 text-white border-blue-600' : 'bg-white text-gray-700 border-gray-300 hover:bg-gray-50'}`}
        >
          <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
        </button>
      </div>

      {showFindReplace && (
        <div className="p-4 bg-gray-50 border border-gray-200 rounded-xl animate-in slide-in-from-top-2">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-4">
            <input type="text" value={findText} onChange={(e) => setFindText(e.target.value)} placeholder="Find..." className="w-full px-3 py-2 bg-white border border-gray-300 rounded-lg text-sm outline-none focus:ring-2 focus:ring-blue-500/20" />
            <input type="text" value={replaceText} onChange={(e) => setReplaceText(e.target.value)} placeholder="Replace with..." className="w-full px-3 py-2 bg-white border border-gray-300 rounded-lg text-sm outline-none focus:ring-2 focus:ring-green-500/20" />
          </div>
          <div className="flex flex-wrap items-center justify-between gap-4">
            <div className="flex items-center space-x-4">
              <label className="flex items-center space-x-2 text-sm text-gray-600 cursor-pointer"><input type="checkbox" checked={matchCase} onChange={(e) => setMatchCase(e.target.checked)} className="w-4 h-4 rounded text-blue-600" /><span>Case</span></label>
              <label className="flex items-center space-x-2 text-sm text-gray-600 cursor-pointer"><input type="checkbox" checked={wholeWord} onChange={(e) => setWholeWord(e.target.checked)} className="w-4 h-4 rounded text-blue-600" /><span>Word</span></label>
            </div>
            <div className="flex items-center space-x-2">
              <button onClick={handleFind} className="px-4 py-2 bg-blue-600 text-white text-sm font-semibold rounded-lg hover:bg-blue-700">Next</button>
              <button onClick={handleReplace} className="px-4 py-2 bg-white border border-gray-300 text-gray-700 text-sm font-semibold rounded-lg hover:bg-gray-50">Replace</button>
              <button onClick={handleReplaceAll} className="px-4 py-2 bg-white border border-gray-300 text-gray-700 text-sm font-semibold rounded-lg hover:bg-gray-50">All</button>
            </div>
          </div>
        </div>
      )}

      <div className="w-full overflow-auto border border-gray-200 rounded-xl shadow-sm bg-white max-h-[600px] scrollbar-thin select-none">
        <table ref={tableRef} className="w-full text-sm text-left border-collapse table-fixed select-none">
          <thead className="sticky top-0 z-20 bg-gray-50 border-b border-gray-200">
            <tr>
              <th className="w-12 border-r border-gray-200 bg-gray-100 px-2 py-2.5 text-center text-[10px] font-bold text-gray-400 uppercase tracking-tighter">#</th>
              {Array.from({ length: colCount }).map((_, i) => (
                <th key={i} className="min-w-[150px] border-r border-gray-200 px-3 py-2.5 text-center text-xs font-bold text-gray-500 uppercase tracking-wider">{getColLabel(i)}</th>
              ))}
            </tr>
          </thead>
          <tbody className="divide-y divide-gray-200">
            {data.map((row, rowIndex) => (
              <tr key={rowIndex} className="group transition-colors">
                <td className="w-12 border-r border-gray-200 bg-gray-50/50 px-2 py-2 text-center text-xs font-medium text-gray-400">{rowIndex + 1}</td>
                {Array.from({ length: colCount }).map((_, colIndex) => {
                  const key = `${rowIndex}-${colIndex}`;
                  if (hiddenCells.has(key)) return null;
                  const val = row[colIndex] || '';
                  const invalid = isInvalid(rowIndex, colIndex, val);
                  const isFocused = focusedCell?.r === rowIndex && focusedCell?.c === colIndex;
                  const selected = isSelected(rowIndex, colIndex);
                  const cellStyle = styles[key] || {};

                  let borderClasses = '';
                  if (selection) {
                    const rS = Math.min(selection.start.r, selection.end.r);
                    const rE = Math.max(selection.start.r, selection.end.r);
                    const cS = Math.min(selection.start.c, selection.end.c);
                    const cE = Math.max(selection.start.c, selection.end.c);
                    if (selected) {
                      if (rowIndex === rS) borderClasses += ' border-t-2 border-t-blue-500';
                      if (rowIndex === rE) borderClasses += ' border-b-2 border-b-blue-500';
                      if (colIndex === cS) borderClasses += ' border-l-2 border-l-blue-500';
                      if (colIndex === cE) borderClasses += ' border-r-2 border-r-blue-500';
                    }
                  }

                  return (
                    <td 
                      key={colIndex} 
                      rowSpan={cellStyle.rowSpan || 1}
                      colSpan={cellStyle.colSpan || 1}
                      onMouseDown={(e) => handleMouseDown(rowIndex, colIndex, e)}
                      onMouseEnter={() => handleMouseEnter(rowIndex, colIndex)}
                      style={{ 
                        backgroundColor: cellStyle.backgroundColor || (invalid ? 'rgb(254 242 242)' : isFocused ? 'rgb(240 253 244 / 0.4)' : selected ? 'rgb(239 246 255 / 0.5)' : 'transparent'),
                        verticalAlign: 'top'
                      }}
                      className={`relative border-r border-gray-100 p-0 transition-all duration-75 ${borderClasses} ${selected ? 'z-10' : ''}`}
                    >
                      <textarea
                        value={val}
                        rows={1}
                        onFocus={() => {
                          setFocusedCell({ r: rowIndex, c: colIndex });
                          if (!isSelecting) setSelection(null);
                        }}
                        onChange={(e) => handleCellEdit(rowIndex, colIndex, e.target.value)}
                        onMouseDown={(e) => { if (!isFocused) e.preventDefault(); }}
                        style={{
                          fontWeight: cellStyle.bold ? 'bold' : 'normal',
                          fontStyle: cellStyle.italic ? 'italic' : 'normal',
                          textAlign: cellStyle.align || 'left',
                          fontSize: cellStyle.fontSize || '14px',
                          fontFamily: cellStyle.fontFamily || 'Inter',
                          backgroundColor: 'transparent',
                          whiteSpace: cellStyle.wrapText ? 'pre-wrap' : 'nowrap',
                          overflow: 'hidden',
                          resize: 'none',
                          minHeight: '2.5rem',
                          height: 'auto',
                          cursor: isFocused ? 'text' : 'cell'
                        }}
                        className={`w-full px-3 py-2 outline-none transition-all block scrollbar-none select-none pointer-events-auto ${invalid ? 'text-red-700 font-medium' : 'text-gray-700'}`}
                      />
                    </td>
                  );
                })}
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export type TableData = string[][];

export interface CellStyle {
  bold?: boolean;
  italic?: boolean;
  align?: 'left' | 'center' | 'right';
  rowSpan?: number;
  colSpan?: number;
  backgroundColor?: string;
  color?: string; // Text color
  wrapText?: boolean;
  fontSize?: string; // e.g., "12px", "14px"
  fontFamily?: string; // e.g., "Inter", "Monospace"
}

export type TableStyles = Record<string, CellStyle>; // key is "rowIndex-colIndex"

export interface ConversionState {
  isProcessing: boolean;
  error: string | null;
  data: TableData | null;
  fileName: string | null;
  styles?: TableStyles;
}

import * as XLSX from 'xlsx';
import { TableData, TableStyles, CellStyle } from '../types';

export const downloadAsExcel = (data: TableData, fileName: string = 'Snap2Sheet_Export') => {
  const ws = XLSX.utils.aoa_to_sheet(data);
  const wb = XLSX.utils.book_new();
  XLSX.utils.book_append_sheet(wb, ws, "Sheet1");
  XLSX.writeFile(wb, `${fileName}.xlsx`);
};

export const downloadAsCSV = (data: TableData, fileName: string = 'Snap2Sheet_Export') => {
  const csvContent = data.map(row => 
    row.map(cell => {
      const escaped = cell.replace(/"/g, '""');
      return `"${escaped}"`;
    }).join(',')
  ).join('\n');

  const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
  const url = URL.createObjectURL(blob);
  const link = document.createElement('a');
  link.setAttribute('href', url);
  link.setAttribute('download', `${fileName}.csv`);
  link.style.visibility = 'hidden';
  document.body.appendChild(link);
  link.click();
  document.body.removeChild(link);
};

export const copyToClipboard = async (data: TableData) => {
  const csvContent = data.map(row => row.join('\t')).join('\n');
  try {
    await navigator.clipboard.writeText(csvContent);
    return true;
  } catch (err) {
    console.error('Failed to copy: ', err);
    return false;
  }
};

/**
 * Copies the table data and styles to clipboard as HTML.
 * Excel and Google Sheets can parse this to preserve formatting.
 */
export const copyTableToClipboard = async (data: TableData, styles: TableStyles = {}) => {
  const colCount = Math.max(...data.map(row => row.length));

  // Track hidden cells due to spans
  const hidden = new Set<string>();
  Object.entries(styles).forEach(([key, style]) => {
    if (style.rowSpan || style.colSpan) {
      const [r, c] = key.split('-').map(Number);
      const rs = style.rowSpan || 1;
      const cs = style.colSpan || 1;
      for (let dr = 0; dr < rs; dr++) {
        for (let dc = 0; dc < cs; dc++) {
          if (dr === 0 && dc === 0) continue;
          hidden.add(`${r + dr}-${c + dc}`);
        }
      }
    }
  });

  let html = '<table border="1" style="border-collapse: collapse; font-family: sans-serif;">';

  data.forEach((row, r) => {
    html += '<tr>';
    for (let c = 0; c < colCount; c++) {
      const key = `${r}-${c}`;
      if (hidden.has(key)) continue;

      const style = styles[key] || {};
      const value = row[c] || '';

      let css = '';
      if (style.bold) css += 'font-weight: bold; ';
      if (style.italic) css += 'font-style: italic; ';
      if (style.align) css += `text-align: ${style.align}; `;
      if (style.backgroundColor) css += `background-color: ${style.backgroundColor}; `;
      if (style.color) css += `color: ${style.color}; `;
      if (style.fontSize) css += `font-size: ${style.fontSize}; `;
      if (style.fontFamily) css += `font-family: ${style.fontFamily}; `;
      if (style.wrapText) css += 'white-space: normal; ';

      const rs = style.rowSpan ? ` rowspan="${style.rowSpan}"` : '';
      const cs = style.colSpan ? ` colspan="${style.colSpan}"` : '';

      html += `<td${rs}${cs} style="${css}">${value}</td>`;
    }
    html += '</tr>';
  });
  html += '</table>';

  const plainText = data.map(row => row.join('\t')).join('\n');

  try {
    const blobHtml = new Blob([html], { type: 'text/html' });
    const blobText = new Blob([plainText], { type: 'text/plain' });
    const dataObj = [new ClipboardItem({
      'text/html': blobHtml,
      'text/plain': blobText
    })];

    await navigator.clipboard.write(dataObj);
    return true;
  } catch (err) {
    console.error('Rich copy failed', err);
    return false;
  }
};

export const shareData = async (data: TableData) => {
  const csvContent = data.map(row => row.join(',')).join('\n');
  const blob = new Blob([csvContent], { type: 'text/csv' });
  const file = new File([blob], 'Snap2Sheet_Export.csv', { type: 'text/csv' });

  if (navigator.canShare && navigator.canShare({ files: [file] })) {
    try {
      await navigator.share({
        files: [file],
        title: 'Snap2Sheet Data Export',
        text: 'Here is the data converted from my image.',
      });
    } catch (err) {
      console.error('Share failed', err);
    }
  } else {
    alert('Sharing not supported on this browser.');
  }
};

import React, { useMemo, useState, useRef, useEffect } from 'react';
import { TableData, CellStyle, TableStyles } from '../types';

interface WorksheetProps {
  data: TableData;
  styles: TableStyles;
  onChange: (newData: TableData) => void;
  onStylesChange: (newStyles: TableStyles) => void;
}

interface Selection {
  start: { r: number; c: number };
  end: { r: number; c: number };
}

const FONT_SIZES = ['8px', '9px', '10px', '11px', '12px', '14px', '16px', '18px', '20px', '24px', '28px', '32px'];
const FONT_FAMILIES = ['Inter', 'Arial', 'Verdana', 'Times New Roman', 'Courier New', 'Monospace', 'Georgia'];

export const Worksheet: React.FC<WorksheetProps> = ({ data, styles, onChange, onStylesChange }) => {
  const [focusedCell, setFocusedCell] = useState<{ r: number; c: number } | null>(null);
  const [selection, setSelection] = useState<Selection | null>(null);
  const [isSelecting, setIsSelecting] = useState(false);
  const tableRef = useRef<HTMLTableElement>(null);

  const [showFindReplace, setShowFindReplace] = useState(false);
  const [findText, setFindText] = useState('');
  const [replaceText, setReplaceText] = useState('');
  const [matchCase, setMatchCase] = useState(false);
  const [wholeWord, setWholeWord] = useState(false);
  const [searchResult, setSearchResult] = useState<{ r: number, c: number }[]>([]);
  const [currentSearchIndex, setCurrentSearchIndex] = useState(-1);

  const bgColorInputRef = useRef<HTMLInputElement>(null);
  const textColorInputRef = useRef<HTMLInputElement>(null);

  if (!data || data.length === 0) return null;

  const colCount = useMemo(() => Math.max(...data.map(row => row.length)), [data]);

  const columnTypes = useMemo(() => {
    const types: boolean[] = [];
    for (let c = 0; c < colCount; c++) {
      let numericCount = 0;
      let totalCount = 0;
      for (let r = 1; r < data.length; r++) {
        const val = data[r][c]?.trim();
        if (val) {
          totalCount++;
          const cleanVal = val.replace(/[$,€,£,%]/g, '');
          if (!isNaN(Number(cleanVal)) && cleanVal !== '') {
            numericCount++;
          }
        }
      }
      types[c] = totalCount > 0 && (numericCount / totalCount) > 0.6;
    }
    return types;
  }, [data, colCount]);

  const hiddenCells = useMemo(() => {
    const hidden = new Set<string>();
    (Object.entries(styles) as [string, CellStyle][]).forEach(([key, style]) => {
      if ((style.rowSpan && style.rowSpan > 1) || (style.colSpan && style.colSpan > 1)) {
        const [r, c] = key.split('-').map(Number);
        const rowSpan = style.rowSpan || 1;
        const colSpan = style.colSpan || 1;
        for (let dr = 0; dr < rowSpan; dr++) {
          for (let dc = 0; dc < colSpan; dc++) {
            if (dr === 0 && dc === 0) continue;
            hidden.add(`${r + dr}-${c + dc}`);
          }
        }
      }
    });
    return hidden;
  }, [styles]);

  const handleCellEdit = (rowIndex: number, colIndex: number, value: string) => {
    const newData = data.map((row, r) => {
      if (r === rowIndex) {
        const newRow = [...row];
        while (newRow.length < colCount) newRow.push('');
        newRow[colIndex] = value;
        return newRow;
      }
      return row;
    });
    onChange(newData);
  };

  const updateStyle = (stylePatch: Partial<CellStyle>) => {
    if (!focusedCell && !selection) return;
    const next = { ...styles };
    if (selection) {
      const rStart = Math.min(selection.start.r, selection.end.r);
      const rEnd = Math.max(selection.start.r, selection.end.r);
      const cStart = Math.min(selection.start.c, selection.end.c);
      const cEnd = Math.max(selection.start.c, selection.end.c);
      for (let r = rStart; r <= rEnd; r++) {
        for (let c = cStart; c <= cEnd; c++) {
          const key = `${r}-${c}`;
          if (!hiddenCells.has(key)) {
            next[key] = { ...next[key], ...stylePatch };
          }
        }
      }
    } else if (focusedCell) {
      const key = `${focusedCell.r}-${focusedCell.c}`;
      next[key] = { ...next[key], ...stylePatch };
    }
    onStylesChange(next);
  };

  const insertRow = (index: number) => {
    const newRow = Array(colCount).fill('');
    const newData = [...data];
    newData.splice(index, 0, newRow);
    const nextStyles: TableStyles = {};
    Object.entries(styles).forEach(([key, style]) => {
      const [r, c] = key.split('-').map(Number);
      if (r >= index) nextStyles[`${r + 1}-${c}`] = style;
      else nextStyles[key] = style;
    });
    onChange(newData);
    onStylesChange(nextStyles);
    setFocusedCell(null);
    setSelection(null);
  };

  const deleteRow = (index: number) => {
    if (data.length <= 1) return;
    const newData = data.filter((_, i) => i !== index);
    const nextStyles: TableStyles = {};
    Object.entries(styles).forEach(([key, style]) => {
      const [r, c] = key.split('-').map(Number);
      if (r === index) return;
      if (r > index) nextStyles[`${r - 1}-${c}`] = style;
      else nextStyles[key] = style;
    });
    onChange(newData);
    onStylesChange(nextStyles);
    setFocusedCell(null);
    setSelection(null);
  };

  const insertColumn = (index: number) => {
    const newData = data.map(row => {
      const newRow = [...row];
      newRow.splice(index, 0, '');
      return newRow;
    });
    const nextStyles: TableStyles = {};
    Object.entries(styles).forEach(([key, style]) => {
      const [r, c] = key.split('-').map(Number);
      if (c >= index) nextStyles[`${r}-${c + 1}`] = style;
      else nextStyles[key] = style;
    });
    onChange(newData);
    onStylesChange(nextStyles);
    setFocusedCell(null);
    setSelection(null);
  };

  const deleteColumn = (index: number) => {
    if (colCount <= 1) return;
    const newData = data.map(row => row.filter((_, i) => i !== index));
    const nextStyles: TableStyles = {};
    Object.entries(styles).forEach(([key, style]) => {
      const [r, c] = key.split('-').map(Number);
      if (c === index) return;
      if (c > index) nextStyles[`${r}-${c - 1}`] = style;
      else nextStyles[key] = style;
    });
    onChange(newData);
    onStylesChange(nextStyles);
    setFocusedCell(null);
    setSelection(null);
  };

  const handleMerge = () => {
    if (!selection) return;
    const rStart = Math.min(selection.start.r, selection.end.r);
    const rEnd = Math.max(selection.start.r, selection.end.r);
    const cStart = Math.min(selection.start.c, selection.end.c);
    const cEnd = Math.max(selection.start.c, selection.end.c);
    if (rStart === rEnd && cStart === cEnd) return;
    const rowSpan = rEnd - rStart + 1;
    const colSpan = cEnd - cStart + 1;
    const next = { ...styles };
    for (let r = rStart; r <= rEnd; r++) {
      for (let c = cStart; c <= cEnd; c++) {
        if (r === rStart && c === cStart) continue;
        delete next[`${r}-${c}`];
      }
    }
    next[`${rStart}-${cStart}`] = { ...next[`${rStart}-${cStart}`], rowSpan, colSpan };
    onStylesChange(next);
    setSelection(null);
    setFocusedCell({ r: rStart, c: cStart });
  };

  const handleUnmerge = () => {
    if (!focusedCell) return;
    const key = `${focusedCell.r}-${focusedCell.c}`;
    if (styles[key]?.rowSpan || styles[key]?.colSpan) {
      const next = { ...styles };
      const { rowSpan, colSpan, ...rest } = next[key];
      next[key] = rest;
      onStylesChange(next);
    }
  };

  const isInvalid = (rowIndex: number, colIndex: number, value: string) => {
    if (rowIndex === 0) return false;
    if (!columnTypes[colIndex]) return false;
    if (!value.trim()) return false;
    const cleanVal = value.replace(/[$,€,£,%]/g, '').trim();
    return isNaN(Number(cleanVal));
  };

  const getColLabel = (index: number) => {
    let label = '';
    let i = index;
    while (i >= 0) {
      label = String.fromCharCode((i % 26) + 65) + label;
      i = Math.floor(i / 26) - 1;
    }
    return label;
  };

  const handleFind = () => {
    if (!findText) { setSearchResult([]); setCurrentSearchIndex(-1); return; }
    const results: { r: number, c: number }[] = [];
    data.forEach((row, r) => {
      row.forEach((cell, c) => {
        let content = cell || '';
        let search = findText;
        if (!matchCase) { content = content.toLowerCase(); search = search.toLowerCase(); }
        if (wholeWord) { if (content === search) results.push({ r, c }); }
        else if (content.includes(search)) { results.push({ r, c }); }
      });
    });
    setSearchResult(results);
    if (results.length > 0) {
      const nextIndex = (currentSearchIndex + 1) % results.length;
      setCurrentSearchIndex(nextIndex);
      setFocusedCell(results[nextIndex]);
      setSelection(null);
    } else {
      setCurrentSearchIndex(-1);
      alert('No matches found.');
    }
  };

  const handleReplace = () => {
    if (currentSearchIndex === -1 || searchResult.length === 0) { handleFind(); return; }
    const current = searchResult[currentSearchIndex];
    const newData = data.map((row, r) => {
      if (r === current.r) {
        const newRow = [...row];
        const oldVal = newRow[current.c];
        let flags = matchCase ? '' : 'i';
        let regex = new RegExp(wholeWord ? `^${findText.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')}$` : findText.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'), flags);
        newRow[current.c] = oldVal.replace(regex, replaceText);
        return newRow;
      }
      return row;
    });
    onChange(newData);
    handleFind();
  };

  const handleReplaceAll = () => {
    if (!findText) return;
    let count = 0;
    let regex = new RegExp(wholeWord ? `\\b${findText.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')}\\b` : findText.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'), matchCase ? 'g' : 'gi');
    const newData = data.map(row => row.map(cell => {
      const newVal = cell.replace(regex, replaceText);
      if (newVal !== cell) count++;
      return newVal;
    }));
    onChange(newData);
    alert(`Replaced ${count} occurrences.`);
    setSearchResult([]);
    setCurrentSearchIndex(-1);
  };

  const handleMouseDown = (r: number, c: number, e: React.MouseEvent) => {
    if (e.button !== 0) return;
    setIsSelecting(true);
    setSelection({ start: { r, c }, end: { r, c } });
    setFocusedCell({ r, c });
    window.addEventListener('mouseup', handleGlobalMouseUp);
  };

  const handleMouseEnter = (r: number, c: number) => {
    if (isSelecting && selection) {
      setSelection({ ...selection, end: { r, c } });
    }
  };

  const handleGlobalMouseUp = () => {
    setIsSelecting(false);
    window.removeEventListener('mouseup', handleGlobalMouseUp);
  };

  const isSelected = (r: number, c: number) => {
    if (!selection) return false;
    const rStart = Math.min(selection.start.r, selection.end.r);
    const rEnd = Math.max(selection.start.r, selection.end.r);
    const cStart = Math.min(selection.start.c, selection.end.c);
    const cEnd = Math.max(selection.start.c, selection.end.c);
    return r >= rStart && r <= rEnd && c >= cStart && c <= cEnd;
  };

  const isSelectedRange = selection && (selection.start.r !== selection.end.r || selection.start.c !== selection.end.c);
  const currentCellStyle = focusedCell ? styles[`${focusedCell.r}-${focusedCell.c}`] || {} : {};

  return (
    <div className="w-full space-y-4 relative">
      <div className="flex flex-wrap items-center gap-2 p-1.5 bg-white border border-gray-200 rounded-xl shadow-sm z-30 overflow-x-auto no-scrollbar">
        {/* Font Family */}
        <select 
          value={currentCellStyle.fontFamily || 'Inter'}
          onChange={(e) => updateStyle({ fontFamily: e.target.value })}
          className="text-sm border-gray-200 rounded-lg px-2 py-1 outline-none bg-gray-50 hover:bg-white transition-colors min-w-[120px]"
        >
          {FONT_FAMILIES.map(f => <option key={f} value={f}>{f}</option>)}
        </select>

        {/* Font Size */}
        <select 
          value={currentCellStyle.fontSize || '14px'}
          onChange={(e) => updateStyle({ fontSize: e.target.value })}
          className="text-sm border-gray-200 rounded-lg px-2 py-1 outline-none bg-gray-50 hover:bg-white transition-colors min-w-[70px]"
        >
          {FONT_SIZES.map(s => <option key={s} value={s}>{s}</option>)}
        </select>

        <div className="w-px h-6 bg-gray-200 mx-1"></div>

        <div className="flex items-center space-x-1">
          <button onClick={() => updateStyle({ bold: !currentCellStyle.bold })} className={`p-1.5 rounded-lg hover:bg-gray-100 transition-colors ${currentCellStyle.bold ? 'bg-green-100 text-green-700' : 'text-gray-600'}`} title="Bold"><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 4h8a4 4 0 014 4 4 4 0 01-4 4H6z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 12h9a4 4 0 014 4 4 4 0 01-4 4H6z" /></svg></button>
          <button onClick={() => updateStyle({ italic: !currentCellStyle.italic })} className={`p-1.5 rounded-lg hover:bg-gray-100 transition-colors ${currentCellStyle.italic ? 'bg-green-100 text-green-700' : 'text-gray-600'}`} title="Italic"><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M10 20l4-16m-4 0h4m-4 16h4" /></svg></button>
          <button onClick={() => updateStyle({ wrapText: !currentCellStyle.wrapText })} className={`p-1.5 rounded-lg hover:bg-gray-100 transition-colors ${currentCellStyle.wrapText ? 'bg-green-100 text-green-700' : 'text-gray-600'}`} title="Wrap Text"><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 12h10l-4 4m0 0l-4-4m4 4V8a4 4 0 014-4h4" /></svg></button>
        </div>

        <div className="w-px h-6 bg-gray-200 mx-1"></div>

        <div className="flex items-center space-x-1">
          <button onClick={() => updateStyle({ align: 'left' })} className={`p-1.5 rounded-lg ${currentCellStyle.align === 'left' ? 'bg-blue-100 text-blue-700' : 'text-gray-600'}`}><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 12h10M4 18h16" /></svg></button>
          <button onClick={() => updateStyle({ align: 'center' })} className={`p-1.5 rounded-lg ${currentCellStyle.align === 'center' ? 'bg-blue-100 text-blue-700' : 'text-gray-600'}`}><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M7 12h10M4 18h16" /></svg></button>
          <button onClick={() => updateStyle({ align: 'right' })} className={`p-1.5 rounded-lg ${currentCellStyle.align === 'right' ? 'bg-blue-100 text-blue-700' : 'text-gray-600'}`}><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M10 12h10M4 18h16" /></svg></button>
        </div>

        <div className="w-px h-6 bg-gray-200 mx-1"></div>

        {/* Text Color Picker */}
        <div className="relative flex items-center group">
          <input type="color" ref={textColorInputRef} onChange={(e) => updateStyle({ color: e.target.value })} value={currentCellStyle.color || '#000000'} className="absolute inset-0 opacity-0 cursor-pointer w-full h-full" />
          <button className={`p-1.5 rounded-lg flex flex-col items-center justify-center ${currentCellStyle.color ? 'text-blue-600' : 'text-gray-600'}`} title="Text Color">
            <span className="text-[10px] font-bold leading-none">A</span>
            <div className="w-3 h-0.5 mt-0.5" style={{ backgroundColor: currentCellStyle.color || '#000000' }}></div>
          </button>
          {currentCellStyle.color && <button onClick={(e) => { e.stopPropagation(); updateStyle({ color: undefined }); }} className="absolute -top-1 -right-1 bg-red-500 text-white rounded-full w-3 h-3 text-[8px] flex items-center justify-center">×</button>}
        </div>

        {/* Background Color Picker */}
        <div className="relative flex items-center">
          <input type="color" ref={bgColorInputRef} onChange={(e) => updateStyle({ backgroundColor: e.target.value })} value={currentCellStyle.backgroundColor || '#ffffff'} className="absolute inset-0 opacity-0 cursor-pointer w-full h-full" />
          <button className={`p-1.5 rounded-lg ${currentCellStyle.backgroundColor ? 'text-green-600' : 'text-gray-600'}`} title="Fill Color"><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M7 21a4 4 0 01-4-4V5a2 2 0 012-2h4a2 2 0 012 2v12a4 4 0 01-4 4zm0 0h12a2 2 0 002-2v-4a2 2 0 00-2-2h-2.343M11 7.343l1.657-1.657a2 2 0 012.828 0l2.829 2.829a2 2 0 010 2.828l-8.486 8.485M7 17h.01" /></svg></button>
          {currentCellStyle.backgroundColor && <button onClick={(e) => { e.stopPropagation(); updateStyle({ backgroundColor: undefined }); }} className="absolute -top-1 -right-1 bg-red-500 text-white rounded-full w-3 h-3 text-[8px] flex items-center justify-center">×</button>}
        </div>

        <div className="w-px h-6 bg-gray-200 mx-1"></div>

        <div className="flex items-center space-x-1">
          <button onClick={handleMerge} disabled={!isSelectedRange} className={`p-1.5 rounded-lg ${!isSelectedRange ? 'opacity-30' : 'text-gray-600'}`} title="Merge"><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 8V6a2 2 0 012-2h4M4 16v2a2 2 0 002 2h4M20 8V6a2 2 0 00-2-2h-4M20 16v2a2 2 0 01-2 2h-4M8 12h8" /></svg></button>
          <button onClick={handleUnmerge} disabled={!focusedCell || !(styles[`${focusedCell.r}-${focusedCell.c}`]?.rowSpan || styles[`${focusedCell.r}-${focusedCell.c}`]?.colSpan)} className={`p-1.5 rounded-lg ${(!focusedCell || !(styles[`${focusedCell.r}-${focusedCell.c}`]?.rowSpan || styles[`${focusedCell.r}-${focusedCell.c}`]?.colSpan)) ? 'opacity-30' : 'text-gray-600'}`} title="Unmerge"><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 6v6m0 0v6m0-6h6m-6 0H6M4 4h16v16H4V4z" /></svg></button>
        </div>

        <div className="w-px h-6 bg-gray-200 mx-1"></div>

        <div className="flex items-center space-x-1">
          <button onClick={() => focusedCell && insertRow(focusedCell.r)} disabled={!focusedCell} className="p-1.5 rounded-lg text-gray-600 hover:bg-gray-100 disabled:opacity-30" title="Insert Row Above"><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4M4 4h16v4H4V4z" /></svg></button>
          <button onClick={() => focusedCell && deleteRow(focusedCell.r)} disabled={!focusedCell} className="p-1.5 rounded-lg text-red-500 hover:bg-red-50 disabled:opacity-30" title="Delete Row"><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M20 12H4M4 4h16v4H4V4z" /></svg></button>
          <button onClick={() => focusedCell && insertColumn(focusedCell.c)} disabled={!focusedCell} className="p-1.5 rounded-lg text-gray-600 hover:bg-gray-100 disabled:opacity-30" title="Insert Column Left"><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 12v8m8-8V4m8 8H4M12 4v16M4 4h4v16H4V4z" /></svg></button>
          <button onClick={() => focusedCell && deleteColumn(focusedCell.c)} disabled={!focusedCell} className="p-1.5 rounded-lg text-red-500 hover:bg-red-50 disabled:opacity-30" title="Delete Column"><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M20 12H4M4 4h4v16H4V4z" /></svg></button>
        </div>

        <button onClick={() => setShowFindReplace(!showFindReplace)} className={`ml-auto inline-flex items-center px-3 py-1.5 border rounded-lg text-sm font-medium transition-colors ${showFindReplace ? 'bg-blue-600 text-white border-blue-600' : 'bg-white text-gray-700 border-gray-300 hover:bg-gray-50'}`}><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg></button>
      </div>

      {showFindReplace && (
        <div className="p-4 bg-gray-50 border border-gray-200 rounded-xl animate-in slide-in-from-top-2">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-4">
            <input type="text" value={findText} onChange={(e) => setFindText(e.target.value)} placeholder="Find..." className="w-full px-3 py-2 bg-white border border-gray-300 rounded-lg text-sm outline-none focus:ring-2 focus:ring-blue-500/20" />
            <input type="text" value={replaceText} onChange={(e) => setReplaceText(e.target.value)} placeholder="Replace with..." className="w-full px-3 py-2 bg-white border border-gray-300 rounded-lg text-sm outline-none focus:ring-2 focus:ring-green-500/20" />
          </div>
          <div className="flex flex-wrap items-center justify-between gap-4">
            <div className="flex items-center space-x-4">
              <label className="flex items-center space-x-2 text-sm text-gray-600 cursor-pointer"><input type="checkbox" checked={matchCase} onChange={(e) => setMatchCase(e.target.checked)} className="w-4 h-4 rounded text-blue-600" /><span>Case</span></label>
              <label className="flex items-center space-x-2 text-sm text-gray-600 cursor-pointer"><input type="checkbox" checked={wholeWord} onChange={(e) => setWholeWord(e.target.checked)} className="w-4 h-4 rounded text-blue-600" /><span>Word</span></label>
            </div>
            <div className="flex items-center space-x-2">
              <button onClick={handleFind} className="px-4 py-2 bg-blue-600 text-white text-sm font-semibold rounded-lg hover:bg-blue-700">Next</button>
              <button onClick={handleReplace} className="px-4 py-2 bg-white border border-gray-300 text-gray-700 text-sm font-semibold rounded-lg hover:bg-gray-50">Replace</button>
              <button onClick={handleReplaceAll} className="px-4 py-2 bg-white border border-gray-300 text-gray-700 text-sm font-semibold rounded-lg hover:bg-gray-50">All</button>
            </div>
          </div>
        </div>
      )}

      <div className="w-full overflow-auto border border-gray-200 rounded-xl shadow-sm bg-white max-h-[600px] scrollbar-thin select-none">
        <table ref={tableRef} className="w-full text-sm text-left border-collapse table-fixed select-none">
          <thead className="sticky top-0 z-20 bg-gray-50 border-b border-gray-200">
            <tr>
              <th className="w-12 border-r border-gray-200 bg-gray-100 px-2 py-2.5 text-center text-[10px] font-bold text-gray-400 uppercase tracking-tighter">#</th>
              {Array.from({ length: colCount }).map((_, i) => (
                <th key={i} className="min-w-[150px] border-r border-gray-200 px-3 py-2.5 text-center text-xs font-bold text-gray-500 uppercase tracking-wider">{getColLabel(i)}</th>
              ))}
            </tr>
          </thead>
          <tbody className="divide-y divide-gray-200">
            {data.map((row, rowIndex) => (
              <tr key={rowIndex} className="group transition-colors">
                <td className="w-12 border-r border-gray-200 bg-gray-50/50 px-2 py-2 text-center text-xs font-medium text-gray-400">{rowIndex + 1}</td>
                {Array.from({ length: colCount }).map((_, colIndex) => {
                  const key = `${rowIndex}-${colIndex}`;
                  if (hiddenCells.has(key)) return null;
                  const val = row[colIndex] || '';
                  const invalid = isInvalid(rowIndex, colIndex, val);
                  const isFocused = focusedCell?.r === rowIndex && focusedCell?.c === colIndex;
                  const selected = isSelected(rowIndex, colIndex);
                  const cellStyle = styles[key] || {};

                  let borderClasses = '';
                  if (selection) {
                    const rS = Math.min(selection.start.r, selection.end.r);
                    const rE = Math.max(selection.start.r, selection.end.r);
                    const cS = Math.min(selection.start.c, selection.end.c);
                    const cE = Math.max(selection.start.c, selection.end.c);
                    if (selected) {
                      if (rowIndex === rS) borderClasses += ' border-t-2 border-t-blue-500';
                      if (rowIndex === rE) borderClasses += ' border-b-2 border-b-blue-500';
                      if (colIndex === cS) borderClasses += ' border-l-2 border-l-blue-500';
                      if (colIndex === cE) borderClasses += ' border-r-2 border-r-blue-500';
                    }
                  }

                  return (
                    <td 
                      key={colIndex} 
                      rowSpan={cellStyle.rowSpan || 1}
                      colSpan={cellStyle.colSpan || 1}
                      onMouseDown={(e) => handleMouseDown(rowIndex, colIndex, e)}
                      onMouseEnter={() => handleMouseEnter(rowIndex, colIndex)}
                      style={{ 
                        backgroundColor: cellStyle.backgroundColor || (invalid ? 'rgb(254 242 242)' : isFocused ? 'rgb(240 253 244 / 0.4)' : selected ? 'rgb(239 246 255 / 0.5)' : 'transparent'),
                        verticalAlign: 'top'
                      }}
                      className={`relative border-r border-gray-100 p-0 transition-all duration-75 ${borderClasses} ${selected ? 'z-10' : ''}`}
                    >
                      <textarea
                        value={val}
                        rows={1}
                        onFocus={() => {
                          setFocusedCell({ r: rowIndex, c: colIndex });
                          if (!isSelecting) setSelection(null);
                        }}
                        onChange={(e) => handleCellEdit(rowIndex, colIndex, e.target.value)}
                        onMouseDown={(e) => { if (!isFocused) e.preventDefault(); }}
                        style={{
                          fontWeight: cellStyle.bold ? 'bold' : 'normal',
                          fontStyle: cellStyle.italic ? 'italic' : 'normal',
                          textAlign: cellStyle.align || 'left',
                          fontSize: cellStyle.fontSize || '14px',
                          fontFamily: cellStyle.fontFamily || 'Inter',
                          color: cellStyle.color || (invalid ? 'rgb(185 28 28)' : 'inherit'),
                          backgroundColor: 'transparent',
                          whiteSpace: cellStyle.wrapText ? 'pre-wrap' : 'nowrap',
                          overflow: 'hidden',
                          resize: 'none',
                          minHeight: '2.5rem',
                          height: 'auto',
                          cursor: isFocused ? 'text' : 'cell'
                        }}
                        className={`w-full px-3 py-2 outline-none transition-all block scrollbar-none select-none pointer-events-auto ${invalid ? 'font-medium' : ''}`}
                      />
                    </td>
                  );
                })}
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

import React, { useMemo, useState, useRef, useEffect } from 'react';
import { TableData, CellStyle, TableStyles } from '../types';

interface WorksheetProps {
  data: TableData;
  styles: TableStyles;
  onChange: (newData: TableData) => void;
  onStylesChange: (newStyles: TableStyles) => void;
}

interface Selection {
  start: { r: number; c: number };
  end: { r: number; c: number };
}

const FONT_SIZES = ['8px', '9px', '10px', '11px', '12px', '14px', '16px', '18px', '20px', '24px', '28px', '32px'];
const FONT_FAMILIES = ['Inter', 'Arial', 'Verdana', 'Times New Roman', 'Courier New', 'Monospace', 'Georgia'];

export const Worksheet: React.FC<WorksheetProps> = ({ data, styles, onChange, onStylesChange }) => {
  const [focusedCell, setFocusedCell] = useState<{ r: number; c: number } | null>(null);
  const [selection, setSelection] = useState<Selection | null>(null);
  const [isSelecting, setIsSelecting] = useState(false);
  const tableRef = useRef<HTMLTableElement>(null);

  const [showFindReplace, setShowFindReplace] = useState(false);
  const [findText, setFindText] = useState('');
  const [replaceText, setReplaceText] = useState('');
  const [matchCase, setMatchCase] = useState(false);
  const [wholeWord, setWholeWord] = useState(false);
  const [searchResult, setSearchResult] = useState<{ r: number, c: number }[]>([]);
  const [currentSearchIndex, setCurrentSearchIndex] = useState(-1);

  const bgColorInputRef = useRef<HTMLInputElement>(null);
  const textColorInputRef = useRef<HTMLInputElement>(null);

  if (!data || data.length === 0) return null;

  const colCount = useMemo(() => Math.max(...data.map(row => row.length)), [data]);
  const rowCount = data.length;

  const columnTypes = useMemo(() => {
    const types: boolean[] = [];
    for (let c = 0; c < colCount; c++) {
      let numericCount = 0;
      let totalCount = 0;
      for (let r = 1; r < rowCount; r++) {
        const val = data[r][c]?.trim();
        if (val) {
          totalCount++;
          const cleanVal = val.replace(/[$,€,£,%]/g, '');
          if (!isNaN(Number(cleanVal)) && cleanVal !== '') {
            numericCount++;
          }
        }
      }
      types[c] = totalCount > 0 && (numericCount / totalCount) > 0.6;
    }
    return types;
  }, [data, colCount, rowCount]);

  const hiddenCells = useMemo(() => {
    const hidden = new Set<string>();
    (Object.entries(styles) as [string, CellStyle][]).forEach(([key, style]) => {
      if ((style.rowSpan && style.rowSpan > 1) || (style.colSpan && style.colSpan > 1)) {
        const [r, c] = key.split('-').map(Number);
        const rowSpan = style.rowSpan || 1;
        const colSpan = style.colSpan || 1;
        for (let dr = 0; dr < rowSpan; dr++) {
          for (let dc = 0; dc < colSpan; dc++) {
            if (dr === 0 && dc === 0) continue;
            hidden.add(`${r + dr}-${c + dc}`);
          }
        }
      }
    });
    return hidden;
  }, [styles]);

  const handleCellEdit = (rowIndex: number, colIndex: number, value: string) => {
    const newData = data.map((row, r) => {
      if (r === rowIndex) {
        const newRow = [...row];
        while (newRow.length < colCount) newRow.push('');
        newRow[colIndex] = value;
        return newRow;
      }
      return row;
    });
    onChange(newData);
  };

  const updateStyle = (stylePatch: Partial<CellStyle>) => {
    if (!focusedCell && !selection) return;
    const next = { ...styles };
    if (selection) {
      const rStart = Math.min(selection.start.r, selection.end.r);
      const rEnd = Math.max(selection.start.r, selection.end.r);
      const cStart = Math.min(selection.start.c, selection.end.c);
      const cEnd = Math.max(selection.start.c, selection.end.c);
      for (let r = rStart; r <= rEnd; r++) {
        for (let c = cStart; c <= cEnd; c++) {
          const key = `${r}-${c}`;
          if (!hiddenCells.has(key)) {
            next[key] = { ...next[key], ...stylePatch };
          }
        }
      }
    } else if (focusedCell) {
      const key = `${focusedCell.r}-${focusedCell.c}`;
      next[key] = { ...next[key], ...stylePatch };
    }
    onStylesChange(next);
  };

  const handleSelectAll = () => {
    setSelection({
      start: { r: 0, c: 0 },
      end: { r: rowCount - 1, c: colCount - 1 }
    });
    setFocusedCell({ r: 0, c: 0 });
  };

  const handleSelectRow = (rowIndex: number) => {
    setSelection({
      start: { r: rowIndex, c: 0 },
      end: { r: rowIndex, c: colCount - 1 }
    });
    setFocusedCell({ r: rowIndex, c: 0 });
  };

  const handleSelectColumn = (colIndex: number) => {
    setSelection({
      start: { r: 0, c: colIndex },
      end: { r: rowCount - 1, c: colIndex }
    });
    setFocusedCell({ r: 0, c: colIndex });
  };

  const insertRow = (index: number) => {
    const newRow = Array(colCount).fill('');
    const newData = [...data];
    newData.splice(index, 0, newRow);
    const nextStyles: TableStyles = {};
    Object.entries(styles).forEach(([key, style]) => {
      const [r, c] = key.split('-').map(Number);
      if (r >= index) nextStyles[`${r + 1}-${c}`] = style;
      else nextStyles[key] = style;
    });
    onChange(newData);
    onStylesChange(nextStyles);
    setFocusedCell(null);
    setSelection(null);
  };

  const deleteRow = (index: number) => {
    if (rowCount <= 1) return;
    const newData = data.filter((_, i) => i !== index);
    const nextStyles: TableStyles = {};
    Object.entries(styles).forEach(([key, style]) => {
      const [r, c] = key.split('-').map(Number);
      if (r === index) return;
      if (r > index) nextStyles[`${r - 1}-${c}`] = style;
      else nextStyles[key] = style;
    });
    onChange(newData);
    onStylesChange(nextStyles);
    setFocusedCell(null);
    setSelection(null);
  };

  const insertColumn = (index: number) => {
    const newData = data.map(row => {
      const newRow = [...row];
      newRow.splice(index, 0, '');
      return newRow;
    });
    const nextStyles: TableStyles = {};
    Object.entries(styles).forEach(([key, style]) => {
      const [r, c] = key.split('-').map(Number);
      if (c >= index) nextStyles[`${r}-${c + 1}`] = style;
      else nextStyles[key] = style;
    });
    onChange(newData);
    onStylesChange(nextStyles);
    setFocusedCell(null);
    setSelection(null);
  };

  const deleteColumn = (index: number) => {
    if (colCount <= 1) return;
    const newData = data.map(row => row.filter((_, i) => i !== index));
    const nextStyles: TableStyles = {};
    Object.entries(styles).forEach(([key, style]) => {
      const [r, c] = key.split('-').map(Number);
      if (c === index) return;
      if (c > index) nextStyles[`${r}-${c - 1}`] = style;
      else nextStyles[key] = style;
    });
    onChange(newData);
    onStylesChange(nextStyles);
    setFocusedCell(null);
    setSelection(null);
  };

  const handleMerge = () => {
    if (!selection) return;
    const rStart = Math.min(selection.start.r, selection.end.r);
    const rEnd = Math.max(selection.start.r, selection.end.r);
    const cStart = Math.min(selection.start.c, selection.end.c);
    const cEnd = Math.max(selection.start.c, selection.end.c);
    if (rStart === rEnd && cStart === cEnd) return;
    const rowSpan = rEnd - rStart + 1;
    const colSpan = cEnd - cStart + 1;
    const next = { ...styles };
    for (let r = rStart; r <= rEnd; r++) {
      for (let c = cStart; c <= cEnd; c++) {
        if (r === rStart && c === cStart) continue;
        delete next[`${r}-${c}`];
      }
    }
    next[`${rStart}-${cStart}`] = { ...next[`${rStart}-${cStart}`], rowSpan, colSpan };
    onStylesChange(next);
    setSelection(null);
    setFocusedCell({ r: rStart, c: cStart });
  };

  const handleUnmerge = () => {
    if (!focusedCell) return;
    const key = `${focusedCell.r}-${focusedCell.c}`;
    if (styles[key]?.rowSpan || styles[key]?.colSpan) {
      const next = { ...styles };
      const { rowSpan, colSpan, ...rest } = next[key];
      next[key] = rest;
      onStylesChange(next);
    }
  };

  const isInvalid = (rowIndex: number, colIndex: number, value: string) => {
    if (rowIndex === 0) return false;
    if (!columnTypes[colIndex]) return false;
    if (!value.trim()) return false;
    const cleanVal = value.replace(/[$,€,£,%]/g, '').trim();
    return isNaN(Number(cleanVal));
  };

  const getColLabel = (index: number) => {
    let label = '';
    let i = index;
    while (i >= 0) {
      label = String.fromCharCode((i % 26) + 65) + label;
      i = Math.floor(i / 26) - 1;
    }
    return label;
  };

  const handleFind = () => {
    if (!findText) { setSearchResult([]); setCurrentSearchIndex(-1); return; }
    const results: { r: number, c: number }[] = [];
    data.forEach((row, r) => {
      row.forEach((cell, c) => {
        let content = cell || '';
        let search = findText;
        if (!matchCase) { content = content.toLowerCase(); search = search.toLowerCase(); }
        if (wholeWord) { if (content === search) results.push({ r, c }); }
        else if (content.includes(search)) { results.push({ r, c }); }
      });
    });
    setSearchResult(results);
    if (results.length > 0) {
      const nextIndex = (currentSearchIndex + 1) % results.length;
      setCurrentSearchIndex(nextIndex);
      setFocusedCell(results[nextIndex]);
      setSelection(null);
    } else {
      setCurrentSearchIndex(-1);
      alert('No matches found.');
    }
  };

  const handleReplace = () => {
    if (currentSearchIndex === -1 || searchResult.length === 0) { handleFind(); return; }
    const current = searchResult[currentSearchIndex];
    const newData = data.map((row, r) => {
      if (r === current.r) {
        const newRow = [...row];
        const oldVal = newRow[current.c];
        let flags = matchCase ? '' : 'i';
        let regex = new RegExp(wholeWord ? `^${findText.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')}$` : findText.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'), flags);
        newRow[current.c] = oldVal.replace(regex, replaceText);
        return newRow;
      }
      return row;
    });
    onChange(newData);
    handleFind();
  };

  const handleReplaceAll = () => {
    if (!findText) return;
    let count = 0;
    let regex = new RegExp(wholeWord ? `\\b${findText.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')}\\b` : findText.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'), matchCase ? 'g' : 'gi');
    const newData = data.map(row => row.map(cell => {
      const newVal = cell.replace(regex, replaceText);
      if (newVal !== cell) count++;
      return newVal;
    }));
    onChange(newData);
    alert(`Replaced ${count} occurrences.`);
    setSearchResult([]);
    setCurrentSearchIndex(-1);
  };

  const handleMouseDown = (r: number, c: number, e: React.MouseEvent) => {
    if (e.button !== 0) return;
    setIsSelecting(true);
    setSelection({ start: { r, c }, end: { r, c } });
    setFocusedCell({ r, c });
    window.addEventListener('mouseup', handleGlobalMouseUp);
  };

  const handleMouseEnter = (r: number, c: number) => {
    if (isSelecting && selection) {
      setSelection({ ...selection, end: { r, c } });
    }
  };

  const handleGlobalMouseUp = () => {
    setIsSelecting(false);
    window.removeEventListener('mouseup', handleGlobalMouseUp);
  };

  const isSelected = (r: number, c: number) => {
    if (!selection) return false;
    const rStart = Math.min(selection.start.r, selection.end.r);
    const rEnd = Math.max(selection.start.r, selection.end.r);
    const cStart = Math.min(selection.start.c, selection.end.c);
    const cEnd = Math.max(selection.start.c, selection.end.c);
    return r >= rStart && r <= rEnd && c >= cStart && c <= cEnd;
  };

  const isRowSelected = (r: number) => {
    if (!selection) return false;
    const rStart = Math.min(selection.start.r, selection.end.r);
    const rEnd = Math.max(selection.start.r, selection.end.r);
    const cStart = Math.min(selection.start.c, selection.end.c);
    const cEnd = Math.max(selection.start.c, selection.end.c);
    return r >= rStart && r <= rEnd && cStart === 0 && cEnd === colCount - 1;
  };

  const isColSelected = (c: number) => {
    if (!selection) return false;
    const rStart = Math.min(selection.start.r, selection.end.r);
    const rEnd = Math.max(selection.start.r, selection.end.r);
    const cStart = Math.min(selection.start.c, selection.end.c);
    const cEnd = Math.max(selection.start.c, selection.end.c);
    return c >= cStart && c <= cEnd && rStart === 0 && rEnd === rowCount - 1;
  };

  const isSelectedRange = selection && (selection.start.r !== selection.end.r || selection.start.c !== selection.end.c);
  const currentCellStyle = focusedCell ? styles[`${focusedCell.r}-${focusedCell.c}`] || {} : {};

  return (
    <div className="w-full space-y-4 relative">
      <div className="flex flex-wrap items-center gap-2 p-1.5 bg-white border border-gray-200 rounded-xl shadow-sm z-30 overflow-x-auto no-scrollbar">
        {/* Font Family */}
        <select 
          value={currentCellStyle.fontFamily || 'Inter'}
          onChange={(e) => updateStyle({ fontFamily: e.target.value })}
          className="text-sm border-gray-200 rounded-lg px-2 py-1 outline-none bg-gray-50 hover:bg-white transition-colors min-w-[120px]"
        >
          {FONT_FAMILIES.map(f => <option key={f} value={f}>{f}</option>)}
        </select>

        {/* Font Size */}
        <select 
          value={currentCellStyle.fontSize || '14px'}
          onChange={(e) => updateStyle({ fontSize: e.target.value })}
          className="text-sm border-gray-200 rounded-lg px-2 py-1 outline-none bg-gray-50 hover:bg-white transition-colors min-w-[70px]"
        >
          {FONT_SIZES.map(s => <option key={s} value={s}>{s}</option>)}
        </select>

        <div className="w-px h-6 bg-gray-200 mx-1"></div>

        <div className="flex items-center space-x-1">
          <button onClick={() => updateStyle({ bold: !currentCellStyle.bold })} className={`p-1.5 rounded-lg hover:bg-gray-100 transition-colors ${currentCellStyle.bold ? 'bg-green-100 text-green-700' : 'text-gray-600'}`} title="Bold"><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 4h8a4 4 0 014 4 4 4 0 01-4 4H6z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 12h9a4 4 0 014 4 4 4 0 01-4 4H6z" /></svg></button>
          <button onClick={() => updateStyle({ italic: !currentCellStyle.italic })} className={`p-1.5 rounded-lg hover:bg-gray-100 transition-colors ${currentCellStyle.italic ? 'bg-green-100 text-green-700' : 'text-gray-600'}`} title="Italic"><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M10 20l4-16m-4 0h4m-4 16h4" /></svg></button>
          <button onClick={() => updateStyle({ wrapText: !currentCellStyle.wrapText })} className={`p-1.5 rounded-lg hover:bg-gray-100 transition-colors ${currentCellStyle.wrapText ? 'bg-green-100 text-green-700' : 'text-gray-600'}`} title="Wrap Text"><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 12h10l-4 4m0 0l-4-4m4 4V8a4 4 0 014-4h4" /></svg></button>
        </div>

        <div className="w-px h-6 bg-gray-200 mx-1"></div>

        <div className="flex items-center space-x-1">
          <button onClick={() => updateStyle({ align: 'left' })} className={`p-1.5 rounded-lg ${currentCellStyle.align === 'left' ? 'bg-blue-100 text-blue-700' : 'text-gray-600'}`}><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M4 12h10M4 18h16" /></svg></button>
          <button onClick={() => updateStyle({ align: 'center' })} className={`p-1.5 rounded-lg ${currentCellStyle.align === 'center' ? 'bg-blue-100 text-blue-700' : 'text-gray-600'}`}><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M7 12h10M4 18h16" /></svg></button>
          <button onClick={() => updateStyle({ align: 'right' })} className={`p-1.5 rounded-lg ${currentCellStyle.align === 'right' ? 'bg-blue-100 text-blue-700' : 'text-gray-600'}`}><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 6h16M10 12h10M4 18h16" /></svg></button>
        </div>

        <div className="w-px h-6 bg-gray-200 mx-1"></div>

        {/* Text Color Picker */}
        <div className="relative flex items-center group">
          <input type="color" ref={textColorInputRef} onChange={(e) => updateStyle({ color: e.target.value })} value={currentCellStyle.color || '#000000'} className="absolute inset-0 opacity-0 cursor-pointer w-full h-full" />
          <button className={`p-1.5 rounded-lg flex flex-col items-center justify-center ${currentCellStyle.color ? 'text-blue-600' : 'text-gray-600'}`} title="Text Color">
            <span className="text-[10px] font-bold leading-none">A</span>
            <div className="w-3 h-0.5 mt-0.5" style={{ backgroundColor: currentCellStyle.color || '#000000' }}></div>
          </button>
          {currentCellStyle.color && <button onClick={(e) => { e.stopPropagation(); updateStyle({ color: undefined }); }} className="absolute -top-1 -right-1 bg-red-500 text-white rounded-full w-3 h-3 text-[8px] flex items-center justify-center">×</button>}
        </div>

        {/* Background Color Picker */}
        <div className="relative flex items-center">
          <input type="color" ref={bgColorInputRef} onChange={(e) => updateStyle({ backgroundColor: e.target.value })} value={currentCellStyle.backgroundColor || '#ffffff'} className="absolute inset-0 opacity-0 cursor-pointer w-full h-full" />
          <button className={`p-1.5 rounded-lg ${currentCellStyle.backgroundColor ? 'text-green-600' : 'text-gray-600'}`} title="Fill Color"><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M7 21a4 4 0 01-4-4V5a2 2 0 012-2h4a2 2 0 012 2v12a4 4 0 01-4 4zm0 0h12a2 2 0 002-2v-4a2 2 0 00-2-2h-2.343M11 7.343l1.657-1.657a2 2 0 012.828 0l2.829 2.829a2 2 0 010 2.828l-8.486 8.485M7 17h.01" /></svg></button>
          {currentCellStyle.backgroundColor && <button onClick={(e) => { e.stopPropagation(); updateStyle({ backgroundColor: undefined }); }} className="absolute -top-1 -right-1 bg-red-500 text-white rounded-full w-3 h-3 text-[8px] flex items-center justify-center">×</button>}
        </div>

        <div className="w-px h-6 bg-gray-200 mx-1"></div>

        <div className="flex items-center space-x-1">
          <button onClick={handleMerge} disabled={!isSelectedRange} className={`p-1.5 rounded-lg ${!isSelectedRange ? 'opacity-30' : 'text-gray-600'}`} title="Merge"><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 8V6a2 2 0 012-2h4M4 16v2a2 2 0 002 2h4M20 8V6a2 2 0 00-2-2h-4M20 16v2a2 2 0 01-2 2h-4M8 12h8" /></svg></button>
          <button onClick={handleUnmerge} disabled={!focusedCell || !(styles[`${focusedCell.r}-${focusedCell.c}`]?.rowSpan || styles[`${focusedCell.r}-${focusedCell.c}`]?.colSpan)} className={`p-1.5 rounded-lg ${(!focusedCell || !(styles[`${focusedCell.r}-${focusedCell.c}`]?.rowSpan || styles[`${focusedCell.r}-${focusedCell.c}`]?.colSpan)) ? 'opacity-30' : 'text-gray-600'}`} title="Unmerge"><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 6v6m0 0v6m0-6h6m-6 0H6M4 4h16v16H4V4z" /></svg></button>
        </div>

        <div className="w-px h-6 bg-gray-200 mx-1"></div>

        <div className="flex items-center space-x-1">
          <button onClick={() => focusedCell && insertRow(focusedCell.r)} disabled={!focusedCell} className="p-1.5 rounded-lg text-gray-600 hover:bg-gray-100 disabled:opacity-30" title="Insert Row Above"><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4M4 4h16v4H4V4z" /></svg></button>
          <button onClick={() => focusedCell && deleteRow(focusedCell.r)} disabled={!focusedCell} className="p-1.5 rounded-lg text-red-500 hover:bg-red-50 disabled:opacity-30" title="Delete Row"><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M20 12H4M4 4h16v4H4V4z" /></svg></button>
          <button onClick={() => focusedCell && insertColumn(focusedCell.c)} disabled={!focusedCell} className="p-1.5 rounded-lg text-gray-600 hover:bg-gray-100 disabled:opacity-30" title="Insert Column Left"><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 12v8m8-8V4m8 8H4M12 4v16M4 4h4v16H4V4z" /></svg></button>
          <button onClick={() => focusedCell && deleteColumn(focusedCell.c)} disabled={!focusedCell} className="p-1.5 rounded-lg text-red-500 hover:bg-red-50 disabled:opacity-30" title="Delete Column"><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M20 12H4M4 4h4v16H4V4z" /></svg></button>
        </div>

        <button onClick={() => setShowFindReplace(!showFindReplace)} className={`ml-auto inline-flex items-center px-3 py-1.5 border rounded-lg text-sm font-medium transition-colors ${showFindReplace ? 'bg-blue-600 text-white border-blue-600' : 'bg-white text-gray-700 border-gray-300 hover:bg-gray-50'}`}><svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg></button>
      </div>

      {showFindReplace && (
        <div className="p-4 bg-gray-50 border border-gray-200 rounded-xl animate-in slide-in-from-top-2">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-4">
            <input type="text" value={findText} onChange={(e) => setFindText(e.target.value)} placeholder="Find..." className="w-full px-3 py-2 bg-white border border-gray-300 rounded-lg text-sm outline-none focus:ring-2 focus:ring-blue-500/20" />
            <input type="text" value={replaceText} onChange={(e) => setReplaceText(e.target.value)} placeholder="Replace with..." className="w-full px-3 py-2 bg-white border border-gray-300 rounded-lg text-sm outline-none focus:ring-2 focus:ring-green-500/20" />
          </div>
          <div className="flex flex-wrap items-center justify-between gap-4">
            <div className="flex items-center space-x-4">
              <label className="flex items-center space-x-2 text-sm text-gray-600 cursor-pointer"><input type="checkbox" checked={matchCase} onChange={(e) => setMatchCase(e.target.checked)} className="w-4 h-4 rounded text-blue-600" /><span>Case</span></label>
              <label className="flex items-center space-x-2 text-sm text-gray-600 cursor-pointer"><input type="checkbox" checked={wholeWord} onChange={(e) => setWholeWord(e.target.checked)} className="w-4 h-4 rounded text-blue-600" /><span>Word</span></label>
            </div>
            <div className="flex items-center space-x-2">
              <button onClick={handleFind} className="px-4 py-2 bg-blue-600 text-white text-sm font-semibold rounded-lg hover:bg-blue-700">Next</button>
              <button onClick={handleReplace} className="px-4 py-2 bg-white border border-gray-300 text-gray-700 text-sm font-semibold rounded-lg hover:bg-gray-50">Replace</button>
              <button onClick={handleReplaceAll} className="px-4 py-2 bg-white border border-gray-300 text-gray-700 text-sm font-semibold rounded-lg hover:bg-gray-50">All</button>
            </div>
          </div>
        </div>
      )}

      <div className="w-full overflow-auto border border-gray-200 rounded-xl shadow-sm bg-white max-h-[600px] scrollbar-thin select-none">
        <table ref={tableRef} className="w-full text-sm text-left border-collapse table-fixed select-none">
          <thead className="sticky top-0 z-20 bg-gray-50 border-b border-gray-200">
            <tr>
              <th 
                onClick={handleSelectAll}
                className="w-12 border-r border-gray-200 bg-gray-100 px-2 py-2.5 text-center text-[10px] font-bold text-gray-400 uppercase tracking-tighter cursor-pointer hover:bg-gray-200 hover:text-gray-600 transition-colors"
              >
                ◩
              </th>
              {Array.from({ length: colCount }).map((_, i) => {
                const active = isColSelected(i);
                return (
                  <th 
                    key={i} 
                    onClick={() => handleSelectColumn(i)}
                    className={`min-w-[150px] border-r border-gray-200 px-3 py-2.5 text-center text-xs font-bold uppercase tracking-wider cursor-pointer transition-colors ${active ? 'bg-blue-100 text-blue-700' : 'text-gray-500 hover:bg-gray-200'}`}
                  >
                    {getColLabel(i)}
                  </th>
                );
              })}
            </tr>
          </thead>
          <tbody className="divide-y divide-gray-200">
            {data.map((row, rowIndex) => (
              <tr key={rowIndex} className="group transition-colors">
                <td 
                  onClick={() => handleSelectRow(rowIndex)}
                  className={`w-12 border-r border-gray-200 px-2 py-2 text-center text-xs font-medium cursor-pointer transition-colors ${isRowSelected(rowIndex) ? 'bg-blue-100 text-blue-700' : 'bg-gray-50/50 text-gray-400 hover:bg-gray-200'}`}
                >
                  {rowIndex + 1}
                </td>
                {Array.from({ length: colCount }).map((_, colIndex) => {
                  const key = `${rowIndex}-${colIndex}`;
                  if (hiddenCells.has(key)) return null;
                  const val = row[colIndex] || '';
                  const invalid = isInvalid(rowIndex, colIndex, val);
                  const isFocused = focusedCell?.r === rowIndex && focusedCell?.c === colIndex;
                  const selected = isSelected(rowIndex, colIndex);
                  const cellStyle = styles[key] || {};

                  let borderClasses = '';
                  if (selection) {
                    const rS = Math.min(selection.start.r, selection.end.r);
                    const rE = Math.max(selection.start.r, selection.end.r);
                    const cS = Math.min(selection.start.c, selection.end.c);
                    const cE = Math.max(selection.start.c, selection.end.c);
                    if (selected) {
                      if (rowIndex === rS) borderClasses += ' border-t-2 border-t-blue-500';
                      if (rowIndex === rE) borderClasses += ' border-b-2 border-b-blue-500';
                      if (colIndex === cS) borderClasses += ' border-l-2 border-l-blue-500';
                      if (colIndex === cE) borderClasses += ' border-r-2 border-r-blue-500';
                    }
                  }

                  return (
                    <td 
                      key={colIndex} 
                      rowSpan={cellStyle.rowSpan || 1}
                      colSpan={cellStyle.colSpan || 1}
                      onMouseDown={(e) => handleMouseDown(rowIndex, colIndex, e)}
                      onMouseEnter={() => handleMouseEnter(rowIndex, colIndex)}
                      style={{ 
                        backgroundColor: cellStyle.backgroundColor || (invalid ? 'rgb(254 242 242)' : isFocused ? 'rgb(240 253 244 / 0.4)' : selected ? 'rgb(239 246 255 / 0.5)' : 'transparent'),
                        verticalAlign: 'top'
                      }}
                      className={`relative border-r border-gray-100 p-0 transition-all duration-75 ${borderClasses} ${selected ? 'z-10' : ''}`}
                    >
                      <textarea
                        value={val}
                        rows={1}
                        onFocus={() => {
                          setFocusedCell({ r: rowIndex, c: colIndex });
                          if (!isSelecting) setSelection(null);
                        }}
                        onChange={(e) => handleCellEdit(rowIndex, colIndex, e.target.value)}
                        onMouseDown={(e) => { if (!isFocused) e.preventDefault(); }}
                        style={{
                          fontWeight: cellStyle.bold ? 'bold' : 'normal',
                          fontStyle: cellStyle.italic ? 'italic' : 'normal',
                          textAlign: cellStyle.align || 'left',
                          fontSize: cellStyle.fontSize || '14px',
                          fontFamily: cellStyle.fontFamily || 'Inter',
                          color: cellStyle.color || (invalid ? 'rgb(185 28 28)' : 'inherit'),
                          backgroundColor: 'transparent',
                          whiteSpace: cellStyle.wrapText ? 'pre-wrap' : 'nowrap',
                          overflow: 'hidden',
                          resize: 'none',
                          minHeight: '2.5rem',
                          height: 'auto',
                          cursor: isFocused ? 'text' : 'cell'
                        }}
                        className={`w-full px-3 py-2 outline-none transition-all block scrollbar-none select-none pointer-events-auto ${invalid ? 'font-medium' : ''}`}
                      />
                    </td>
                  );
                })}
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

import { GoogleGenAI, Type } from "@google/genai";
import { TableData } from "../types";

/**
 * Extraction of tabular data from an image.
 * Uses Gemini 3 Flash for optimal speed and reliability in vision-to-structured-data tasks.
 * Flash provides robust performance for OCR and layout preservation without the overhead
 * that can lead to internal proxy timeouts.
 */
export const convertImageToData = async (base64Image: string): Promise<TableData> => {
  // Initialize with the provided API key from environment
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `
    Task: Extract tabular data from the provided image.
    Rules:
    1. Scan the entire image for tables, grids, or structured lists.
    2. Map the spatial layout exactly into a 2D array.
    3. Include all headers and data cells.
    4. If a cell is blank or unreadable, represent it as an empty string ("").
    5. Return ONLY a valid JSON object matching the requested schema.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: {
        parts: [
          { inlineData: { data: base64Image, mimeType: "image/png" } },
          { text: prompt }
        ]
      },
      config: {
        // High-speed extraction mode to avoid XHR/500 timeouts common in thinking-enabled preview models
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            rows: {
              type: Type.ARRAY,
              description: "A 2D array of rows, where each row contains an array of string cell values.",
              items: {
                type: Type.ARRAY,
                items: { type: Type.STRING }
              }
            }
          },
          required: ["rows"]
        }
      }
    });

    const text = response.text;
    if (!text) {
      throw new Error("The AI returned an empty response. Ensure the image is clear and contains a visible table.");
    }

    let result;
    try {
      result = JSON.parse(text);
    } catch (parseError) {
      console.error("JSON Parsing Error:", text);
      throw new Error("Received a malformed response from the AI. Cropping the image to just the table often helps.");
    }

    if (!result.rows || !Array.isArray(result.rows) || result.rows.length === 0) {
      throw new Error("No tabular data could be detected in this image.");
    }

    // Post-processing: Normalize rows to ensure a perfect rectangular grid
    const maxCols = Math.max(...result.rows.map((r: any) => Array.isArray(r) ? r.length : 0), 0);
    const normalizedRows = result.rows.map((row: any) => {
      const rowArr = Array.isArray(row) ? row : [];
      // Clean up values and fill missing columns
      const cleanedRow = [...rowArr].map(cell => (cell === null || cell === undefined) ? "" : String(cell));
      while (cleanedRow.length < maxCols) cleanedRow.push("");
      return cleanedRow;
    });

    return normalizedRows;
  } catch (error: any) {
    console.error("Gemini Table Extraction Error:", error);

    // Map specific technical failures to user-friendly advice
    const errorMsg = error.message?.toLowerCase() || "";
    const isNetworkError = errorMsg.includes("xhr") || errorMsg.includes("500") || errorMsg.includes("rpc failed") || error.status === "UNKNOWN";

    if (isNetworkError) {
      throw new Error("The AI server timed out while analyzing the image. This often happens with very complex tables or high-resolution images. Please try cropping the image to focus only on the table area.");
    }

    throw new Error(error.message || "Failed to extract table data. Please ensure your image is clear and try again.");
  }
};

export type TableData = string[][];

export interface CellStyle {
  bold?: boolean;
  italic?: boolean;
  align?: 'left' | 'center' | 'right';
  rowSpan?: number;
  colSpan?: number;
  backgroundColor?: string;
  color?: string; // Text color
  wrapText?: boolean;
  fontSize?: string; // e.g., "12px", "14px"
  fontFamily?: string; // e.g., "Inter", "Monospace"
}

export type ConditionalOperator = 
  | 'greater_than' 
  | 'less_than' 
  | 'equals' 
  | 'contains' 
  | 'not_contains' 
  | 'starts_with' 
  | 'ends_with' 
  | 'is_empty' 
  | 'is_not_empty';

export interface ConditionalRule {
  id: string;
  operator: ConditionalOperator;
  value: string;
  style: Partial<CellStyle>;
  enabled: boolean;
}

export type TableStyles = Record<string, CellStyle>; // key is "rowIndex-colIndex"

export interface ConversionState {
  isProcessing: boolean;
  error: string | null;
  data: TableData | null;
  fileName: string | null;
  styles?: TableStyles;
  conditionalRules?: ConditionalRule[];
}

